INSERT INTO public.photos VALUES (23913, 'Mâ”œأ­rtires de Zaragoza, siglo XVII', '"Mâ”œأ­rtires de Zaragoza con una vista de la ciudad", â”œâ”‚leo sobre lienzo, 73 x 51 cm. Escuela aragonesa del siglo XVII. Representaciâ”œâ”‚n quizâ”œأ­s figurada de la Zaragoza barroca. En la parte superior, vista de la ciudad con el templo del Pilar y la Virgen. En la parte inferior, legendario martirio de los cristianos en el siglo IV, en el exterior del recinto amurallado, con la Puerta Cinegia detrâ”œأ­s. Entre los martirizados, posiblemente santa Engracia, de rodillas en primer plano.', 1650, 1600, 1699, 'Siglo XIX', 'CENTRO', 41.65212900, -0.88104400, '0101000020E6100000E7C8CA2F8331ECBFF8E28BF678D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53644828840.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53644828840.webp', 'https://www.flickr.com/photos/zaragozaantigua/53644828840/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23977, 'Pl. de la Constituciâ”œâ”‚n 1904', '23 de octubre de 1904. Inauguraciâ”œâ”‚n del Monumento a los Mâ”œأ­rtires de la Religiâ”œâ”‚n y de la Patria en la plaza de la Constituciâ”œâ”‚n. El castillo que se levanta detrâ”œأ­s es una construcciâ”œâ”‚n efâ”œآ،mera proyectada por Ricardo Magdalena, que cubre la Fuente de Neptuno. Inicialmente prevista su igniciâ”œâ”‚n en las fiestas del Pilar, â”œآ®sta no se llevâ”œâ”‚ a cabo y acabâ”œâ”‚ desmantelâ”œأ­ndose el 25 de octubre. Fuente visual: Estudio Coyne, AHPZ', 1904, 1904, 1904, 'Anos 1900', 'CENTRO', 41.65205900, -0.88097800, '0101000020E61000000ADB4FC6F830ECBFFF0758AB76D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15259514858.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15259514858.webp', 'https://www.flickr.com/photos/zaragozaantigua/15259514858/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23985, 'Pl. de la Constituciâ”œâ”‚n 1902', 'Fiestas del Pilar de 1902. La plaza de la Constituciâ”œâ”‚n luce engalanada el dâ”œآ،a 10 de octubre, fecha de la inauguraciâ”œâ”‚n al pâ”œâ•‘blico de la lâ”œآ،nea elâ”œآ®ctrica del tranvâ”œآ،a que conectaba con la playa de Torrero. El dâ”œآ،a antes los vehâ”œآ،culos habâ”œآ،an sido ritualmente bendecidos por el arzobispo Soldevila. En primer tâ”œآ®rmino, la jardinera nâ”¬â•‘ 41, traccionada por caballerâ”œآ،as. En el centro de la imagen, tranvâ”œآ،a elâ”œآ®ctrico prestado para la ocasiâ”œâ”‚n por la ciudad de San Sebastiâ”œأ­n, tirando de un remolque cerrado hasta entonces tirado por caballerâ”œآ،as.', 1902, 1902, 1902, 'Anos 1900', 'CENTRO', 41.65181200, -0.88118800, '0101000020E6100000B115342DB132ECBFF7915B936ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15496845845.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15496845845.webp', 'https://www.flickr.com/photos/zaragozaantigua/15496845845/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23998, 'Cine Farrusini 1907', 'Aunque la barraca ambulante del seâ”œâ–’or Farrusini, con su cinematâ”œâ”‚grafo, recorrâ”œآ،a las ciudades espaâ”œâ–’olas, hacia 1907 se quedâ”œâ”‚ en Zaragoza, aprovechando la inminente celebraciâ”œâ”‚n del centenario de los Sitios. En la imagen, fachada del espectâ”œأ­culo, sin que se pueda determinar si su instalaciâ”œâ”‚n es en la calle de San Miguel 5, futuros locales de Criado y Lorenzo y del cine Goya. Luis Buâ”œâ–’uel relatâ”œâ”‚ que su primera experiencia cinematogrâ”œأ­fica como espectador se dio en este lugar. Fuente visual: AMZ', 1907, 1907, 1907, 'Anos 1900', 'CENTRO', 41.65106800, -0.88053800, '0101000020E6100000F4531C075E2DECBF6FBC3B3256D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21165699386.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21165699386.webp', 'https://www.flickr.com/photos/zaragozaantigua/21165699386/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23999, 'Pl. de la Constituciâ”œâ”‚n 1931', 'Foto: Marâ”œآ،n Chivite. Martes 14 de abril de 1931. Celebraciâ”œâ”‚n de la proclamaciâ”œâ”‚n de la II Repâ”œâ•‘blica, en la plaza de la Constituciâ”œâ”‚n de Zaragoza. Al fondo, el inicio del paseo de la Independencia, del que proviene la manifestaciâ”œâ”‚n popular con banderas republicanas. Fuente: Archivo Heraldo de Aragâ”œâ”‚n.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65187100, -0.88099800, '0101000020E6100000D0ECBAB72231ECBFFC1A498270D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21251056479.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21251056479.webp', 'https://www.flickr.com/photos/zaragozaantigua/21251056479/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24011, 'Plaza Espaâ”œâ–’a 2001', 'El 30 de junio de 2001, el equipo de fâ”œâ•‘tbol local resultâ”œâ”‚ vencedor en la Copa del Rey, un campeonato de carâ”œأ­cter nacional. Esa noche, miles de seguidores del Real Zaragoza se acercaron a la plaza de Espaâ”œâ–’a para celebrarlo en el Monumento a los Mâ”œأ­rtires de la Religiâ”œâ”‚n y de la Patria. En la foto, detalle de la concentraciâ”œâ”‚n cavernâ”œآ،cola. Fuente: Agencia EFE.', 2001, 2001, 2001, 'Siglo XXI', 'CENTRO', 41.65213600, -0.88081000, '0101000020E61000001DACFF73982FECBFAA45443179D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24025835073.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24025835073.webp', 'https://www.flickr.com/photos/zaragozaantigua/24025835073/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24022, 'Plaza de Espaâ”œâ–’a 1958', '"Que por una noche seamos todos hermanos, que por una noche los duros de corazâ”œâ”‚n sean generosos, que por una noche cenen los pobresأ”أ‡آھ", voceaba el personaje de Quintanilla en la irrepetible "Plâ”œأ­cido", la reciente y monumental pelâ”œآ،cula de Berlanga sobre la hipocresâ”œآ،a desatada en esos dâ”œآ،as tan seâ”œâ–’alados de diciembre, en que la ficciâ”œâ”‚n de la justicia social parece conseguirse mediante la distribuciâ”œâ”‚n de unas contadas viandas y bebidas espirituosas, en forma de "aguinaldo", o sentando a un pobre en su mesa, una noche. Escenificaciones como esta de la imagen, donde se acumulan ofrendas votivas, entre ellas un cerdo enjaulado, al trabajador municipal que regula el trâ”œأ­fico en esa zona de la plaza de Espaâ”œâ–’a, se repetâ”œآ،an en otros escenarios de la ciudad. Como telâ”œâ”‚n de fondo, el Banco de Espaâ”œâ–’a. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.65191300, -0.88037400, '0101000020E610000062F54718062CECBF2B6B9BE271D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24730973952.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24730973952.webp', 'https://www.flickr.com/photos/zaragozaantigua/24730973952/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24042, 'Pl. de Espaâ”œâ–’a 1958', 'Imagen centrada en el tenderete montado por el antropolâ”œâ”‚gico "aguinaldo", o tipismo caracterizado por la donaciâ”œâ”‚n convertida en espectâ”œأ­culo de viandas y bebidas durante los seâ”œâ–’alados dâ”œآ،as navideâ”œâ–’os, en este caso en el puesto de trabajo de un municipal guardia de trâ”œأ­fico sito en la plaza de Espaâ”œâ–’a lindando ya casi con el tramo medio del Coso. Entre las ofrendas destaca sobremanera un joven cerdo enjaulado sobre varios toneles posiblemente de bebidas espirituosas, y con globos decorativos. De fondo escâ”œآ®nico, la plaza de Espaâ”œâ–’a con su cuadrangular glorieta resultante de la reforma de 1942, como lugar central del trâ”œأ­nsito de peatones, tranvâ”œآ،as, autobuses y un pequeâ”œâ–’o carro de transporte a pedales. La plaza contaba entonces con dos zonas de aparcamiento en superficie a ambos lados de la glorieta. Mâ”œأ­s al fondo, el arranque del paseo de la Indepedencia con su original andador central arbolado, y con vista siquiera borrosa de algunos de los antiguos edificios de tres alturas que conformaban el original paseo, y que pocos aâ”œâ–’os despuâ”œآ®s serâ”œآ،an derribados para dar paso a la moderna gran superficie comercial vertical de la Sociedad Espaâ”œâ–’ola de Precios â”œأœnicos. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.65213000, -0.88062100, '0101000020E6100000537765170C2EECBFC85EEFFE78D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30898119208.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30898119208.webp', 'https://www.flickr.com/photos/zaragozaantigua/30898119208/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24046, 'Plaza de Espaâ”œâ–’a 1940', 'Portada de "Fotos, Semanario Grâ”œأ­fico de Informaciâ”œâ”‚n y Reportajes", fundado en 1937 como â”œâ”‚rgano propagandâ”œآ،stico de Falange Espaâ”œâ–’ola de las JONS, para mostrar a los lectores "los magnos acontecimientos de la heroica gesta que vivimos". La imagen ilustra un gran reportaje publicado en este nâ”œâ•‘mero de octubre de 1940, para informar de la extraordinaria confluencia del "XIX Centenario de la Venida de la Virgen del Pilar", la "Fiesta de la Raza", la celebraciâ”œâ”‚n de la victoria militar en la guerra de 1936-39, y la presencia del caudillo Franco. El montaje fotogrâ”œأ­fico representa el momento en el que el Jefe del Estado parece transitar en su vehâ”œآ،culo oficial por la plaza de Espaâ”œâ–’a, junto al monumento a los Mâ”œأ­rtires de la Religiâ”œâ”‚n y la Patria, y la fachada del Coso recayente a la plaza, mientras una entregada parroquia de zaragozanos enfundados en trajes folclâ”œâ”‚ricos, sonrâ”œآ،en felices. El evento fue un clamoroso â”œآ®xito de crâ”œآ،tica y pâ”œâ•‘blico. Nadie pudo decir lo contrario. Fuente visual: www.todocoleccion.net/', 1940, 1940, 1940, 'Anos 40', 'CENTRO', 41.65213600, -0.88081000, '0101000020E61000001DACFF73982FECBFAA45443179D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31085463495.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31085463495.webp', 'https://www.flickr.com/photos/zaragozaantigua/31085463495/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24047, 'Pl. de la Constituciâ”œâ”‚n 1931', 'Foto: Miguel Marâ”œآ،n Chivite. El lunes 13 de abril de 1931, un dâ”œآ،a despuâ”œآ®s de las elecciones municipales, se van conociendo datos sobre el triunfo de las candidaturas republicanas, y se forman pequeâ”œâ–’as concentraciones. Es el momento que recoge la imagen, centrada en el monumento a los Mâ”œأ­rtires de la plaza de la Constituciâ”œâ”‚n, con la Diputaciâ”œâ”‚n Provincial a la izquierda. Al dâ”œآ،a siguiente serâ”œآ،a proclamada la Segunda Repâ”œâ•‘blica. Fuente: Heraldo de Aragâ”œâ”‚n.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65207700, -0.88097900, '0101000020E610000020CF2EDFFA30ECBFA5BC564277D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31095726584.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31095726584.webp', 'https://www.flickr.com/photos/zaragozaantigua/31095726584/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24055, 'Pl. de la Constituciâ”œâ”‚n 1904', 'Aspecto del castillo de madera erigido en la plaza de la Constituciâ”œâ”‚n para las fiestas del Pilar de 1904. A la izquierda, pedestal del monumento a los Mâ”œأ­rtires, que serâ”œأ­ colocado e inaugurado a los pocos dâ”œآ،as. A la derecha, embocadura de la calle de los Mâ”œأ­rtires. Fuente: cesbor.blogspot.com.es/', 1904, 1904, 1904, 'Anos 1900', 'CENTRO', 41.65210100, -0.88098900, '0101000020E61000000458E4D70F31ECBF2E58AA0B78D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31586333526.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31586333526.webp', 'https://www.flickr.com/photos/zaragozaantigua/31586333526/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24891, 'Campus San Francisco 1969', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. 29/01/1969. Tras el 18 de julio de 1936, la Universidad fue militarizada y nacionalcatolitizada. La regimental nueva Junta de Gobierno (la anterior fue piqueteada) en octubre de 1936 aprobâ”œâ”‚ la erecciâ”œâ”‚n de un "Monumento a los estudiantes caâ”œآ،dos por Dios y por Espaâ”œâ–’a", proyectado por Fâ”œآ®lix Burriel y realizado por Regino Borobio y Josâ”œآ® Beltrâ”œأ­n. Se instalâ”œâ”‚ en una zona del nuevo campus de la Plaza de Espaâ”œâ–’a (al poco se cambiarâ”œآ،a el nombre por el de San Francisco), en la entrada desde la calle Menâ”œآ®ndez Pelayo. En la imagen, estudiantes universitarios depositando coronas en el monumental monumento, en el aâ”œâ–’o XXX de la Victoria sobre el comunismo. Este monumento fue trasladado por partes en 1981 al patio central del CRM del Ejâ”œآ®rcito de Tierra, siendo recompuesto sâ”œâ”‚lo en lo referido a las figuras de los soldados centinelas de los laterales.', 1969, 1969, 1969, 'Anos 60', 'UNIVERSIDAD', 41.64262800, -0.89672600, '0101000020E6100000F7216FB9FAB1ECBF38BF61A241D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15081260547.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15081260547.webp', 'https://www.flickr.com/photos/zaragozaantigua/15081260547/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24073, 'Calle de San Miguel 1906', 'Imagen centrada en la portada del itinerante espectâ”œأ­culo de los "Autâ”œâ”‚matas de Narbâ”œâ”‚n", representado en el espacio esquinero entre la calle de San Miguel y la calle de los Sitios (hacia la derecha), que fue antigua casa de baâ”œâ–’os, y que en 1904 fuera provisional palacio de proyecciones cinematogrâ”œأ­ficas de los Jimeno. En su lado norte estuvo (1869-1886) el Teatro Lope de Vega, y enfrente, El Prado Aragonâ”œآ®s/Teatro Goya (1880-1893). A finales de 1906, teniendo de vecino al reciente Cinematâ”œâ”‚grafo Coyne (hacia la izquierda), en este espacio se estableciâ”œâ”‚ el impresionante espectâ”œأ­culo de los Autâ”œâ”‚matas de Isidro Narbâ”œâ”‚n, que arrancaba con una introducciâ”œâ”‚n en la que se proyectaba una breve pelâ”œآ،cula cinematogrâ”œأ­fica que daba paso a la representaciâ”œâ”‚n de un espectâ”œأ­culo lâ”œآ،rico a cargo de cerca de 300 marionetas mecanizadas. En el interior del establecimiento se apiâ”œâ–’aban 600 entusiasmados espectadores, las mâ”œأ­s de las veces niâ”œâ–’as y niâ”œâ–’os. Una de esas niâ”œâ–’as, de 9 aâ”œâ–’os de edad, fue Pilar Bayona Lâ”œâ”‚pez de Ansâ”œâ”‚. En la imagen, capturada desde la calle de San Miguel, un â”œâ”‚rgano monumental que servâ”œآ،a de ingreso al interior, y cuyas campanillas musicantes atraâ”œآ،an a la chiquillerâ”œآ،a de forma tan irresistible como la flauta del cuento a los roedores de Hamelin. Este monumental espectâ”œأ­culo de Narbâ”œâ”‚n cerrâ”œâ”‚ aâ”œâ–’os despuâ”œآ®s, y todo su patrimonio artâ”œآ،stico desapareciâ”œâ”‚ como lâ”œأ­grimas en la lluvia. En esta misma ubicaciâ”œâ”‚n, entre 1908 y 1913 se estableciâ”œâ”‚ el Cinematâ”œâ”‚grafo Farrusini. Fuente visual: www.mecd.gob.es/.', 1906, 1906, 1906, 'Anos 1900', 'CENTRO', 41.65116000, -0.88062100, '0101000020E6100000537765170C2EECBF4F3BFC3559D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35561879262.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35561879262.webp', 'https://www.flickr.com/photos/zaragozaantigua/35561879262/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24846, 'Huelga TUZSA 1986', 'Desde la plaza de Espaâ”œâ–’a, imagen centrada en un grupo de usuarios que asciende a un autobâ”œâ•‘s proveniente de Madrid que sustituyâ”œâ”‚ a los que estaban en huelga de la empresa Transportes Urbanos de Zaragoza S.A., Tuzsa. Llegaron a incorporarse hasta un total de 150 autobuses foranos para hacer los recorridos regulares. Esta movilizaciâ”œâ”‚n se extendiâ”œâ”‚ entre los meses de junio y noviembre y fue liderado por el Colectivo Unitario de Trabajadores, CUT. Las condiciones laborales por las que se regâ”œآ،a la concesionaria databan de 1961, y el conflicto se prolongâ”œâ”‚ a causa de los sucesivos incumplimientos de lo pactado por parte de la empresa, con infructuosas negociaciones encabezadas por el alcalde Antonio Gonzâ”œأ­lez Triviâ”œâ–’o y por carpetovetâ”œâ”‚nico gerente de Tuzsa, Luis Senar. El vehâ”œآ،culo se encuentra en el arranque del Coso Medio. A la izquierda, sede central del Banco Zaragozano. Fuente visual: www.zaragoza.es/ciudad/actividades/ficha_Agenda?codigo=13...', 1986, 1986, 1986, 'Anos 80', 'CENTRO', 41.65211200, -0.88012000, '0101000020E6100000D2C6116BF129ECBF22AAF06778D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15296837543.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15296837543.webp', 'https://www.flickr.com/photos/zaragozaantigua/15296837543/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24966, 'Pl. de Espaâ”œâ–’a 1966', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. Mayo 1966. "IV Vuelta Ciclista a Aragâ”œâ”‚n." Imagen de la entrada en la Plaza de Espaâ”œâ–’a desde el Coso Medio, al fondo, en direcciâ”œâ”‚n al Paseo de la Independencia.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65208800, -0.88033300, '0101000020E6100000BEDD921CB02BECBF990E9D9E77D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15048168268.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15048168268.webp', 'https://www.flickr.com/photos/zaragozaantigua/15048168268/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25058, 'UVE 1989', 'Un agente de la Unidad de Vigilancia Especial de la policâ”œآ،a local de Zaragoza se dirige a conversar con el fotâ”œâ”‚grafo de Heraldo de Aragâ”œâ”‚n Vicente Jorcano, en la plaza de Espaâ”œâ–’a de Zaragoza. Al fondo, el Banco de Espaâ”œâ–’a. Mâ”œأ­s informaciâ”œâ”‚n: www.zaragozarebelde.org/uve-elterror-de-la-noche', 1989, 1989, 1989, 'Anos 80', 'CENTRO', 41.65208100, -0.88111100, '0101000020E6100000DAAA24B20F32ECBFE7ABE46377D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14833840478.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14833840478.webp', 'https://www.flickr.com/photos/zaragozaantigua/14833840478/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25067, 'Santa Engracia y los Innumerables. Siglo IV', 'Santa Engracia y los Innumerables Mâ”œأ­rtires de Zaragoza. Anâ”œâ”‚nimo, finales del XIX. Basâ”œآ،lica de Santa Engracia, Zaragoza. Engracia de Zaragoza es un personaje legendario que muere torturado por Diocleciano en el aâ”œâ–’o 303. Las citadas torturas consisten en araâ”œâ–’arle las carnes con garfios, cortarle un pecho y clavarle un clavo en la cabeza, entre otras. Los Innumerables Mâ”œأ­rtires que vemos detrâ”œأ­s son 18 personajes legendarios llamados: "Optato, Luperco, Suceso, Marcial, Urbano, Julio, Quintiliano, Publio, Frontonio, Fâ”œآ®lix, Ceciliano, Evodio, Primitivo, Apodemio, y cuatro mâ”œأ­s llamados Saturnino. Sobre el nombre de estos â”œâ•‘ltimos hay una doble tradiciâ”œâ”‚n, pues otras fuentes los llaman Casiano, Jenaro, Matutino y Fausto. Con ellos padeciâ”œâ”‚ tambiâ”œآ®n, aunque sin morir en el tormento, la virgen Engracia de Zaragoza. La Passio los hace morir bajo el prefecto imperial Daciano, el gran perseguidor de los cristianos espaâ”œâ–’oles en tiempo de Diocleciano; despuâ”œآ®s de ser degollados, sus cuerpos fueron quemados. El cuerpo de Santa Engracia fue sepultado por el obispo Prudencio en una urna de mâ”œأ­rmol, uniendo a â”œآ®l las cenizas de sus 18 compaâ”œâ–’eros." Wikipedia A la izquierda de la pintura, la Puerta Cinegia de Zaragoza. Las figuras se encuentran pues en los actuales plaza de Espaâ”œâ–’a y paseo de la Independencia.', 350, 300, 399, 'Siglo XIX', 'CENTRO', 41.65214200, -0.88072000, '0101000020E61000001EDC9DB5DB2EECBF8C2C996379D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15099020172.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15099020172.webp', 'https://www.flickr.com/photos/zaragozaantigua/15099020172/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25087, 'Plaza Constituciâ”œâ”‚n 1903', 'Dibujo de Dionisio Lasuâ”œآ®n. Entrada del rey Alfonso XIII en Zaragoza, en octubre de 1903. Al fondo, la Diputaciâ”œâ”‚n Provincial. Fuente: Heraldo de Aragâ”œâ”‚n.', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.65211300, -0.88109900, '0101000020E6100000C939B187F631ECBFF225547078D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31707969276.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31707969276.webp', 'https://www.flickr.com/photos/zaragozaantigua/31707969276/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25096, 'Pl. de la Constituciâ”œâ”‚n 1931', 'Imagen capturada en la terraza del muy reciente cafâ”œآ®-restaurant Salduba en los bajos del nâ”¬â•‘ 6 de la plaza de la Constituciâ”œâ”‚n, como escenario de un reportaje publicitario protagonizado por la bonaerense actriz y vedete Celia Gâ”œأ­mez (sentada en primer plano) con ocasiâ”œâ”‚n de su paso por el Teatro Principal. Con diseâ”œâ–’o de los hermanos Borobio, el Salduba se ubicaba donde antes estuvieran el cafâ”œآ® La Perla, primero, y luego el Casino Artâ”œآ،stico. Apenas un par de aâ”œâ–’os despuâ”œآ®s, una ampliaciâ”œâ”‚n de local dio paso a una nueva reforma tambiâ”œآ®n diseâ”œâ–’ada por los Borobio. Fuente visual: www.mecd.gob.es/.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65162500, -0.88062100, '0101000020E6100000537765170C2EECBFC520B07268D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36317808970.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36317808970.webp', 'https://www.flickr.com/photos/zaragozaantigua/36317808970/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25107, 'Paseo de Santa Engracia nevado 1888', 'Estampa invernal de la plaza de la Constituciâ”œâ”‚n y el arranque del paseo de Santa Engracia. Preside el conjunto la fuente de la Princesa. Fuente visual: La Ilustraciâ”œâ”‚n Espaâ”œâ–’ola y Americana.', 1888, 1888, 1888, 'Siglo XIX', 'CENTRO', 41.65204000, -0.88096500, '0101000020E6100000E275FD82DD30ECBF88D7F50B76D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14672302348.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14672302348.webp', 'https://www.flickr.com/photos/zaragozaantigua/14672302348/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
