INSERT INTO public.photos VALUES (25116, 'Plaza de Espaâ”œâ–’a 1978', 'â”¬أ­Oh! la circulaciâ”œâ”‚n, Josâ”œآ® Borobio, 1978. Rotuladores de color sobre papel. Vista de la plaza de Espaâ”œâ–’a desde el paseo de la Independencia, en un momento histâ”œâ”‚rico de atasco.', 1978, 1978, 1978, 'Anos 70', 'CENTRO', 41.65195000, -0.88101700, '0101000020E6100000810A47904A31ECBF4850FC1873D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15084818351.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15084818351.webp', 'https://www.flickr.com/photos/zaragozaantigua/15084818351/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25136, 'Los innumerables mâ”œأ­rtires siglo IV', 'Los innumerables mâ”œأ­rtires de Zaragoza, aguafuerte de Antonio Banzo, Roma, ca. 1840. El dibujo representa el legendario suceso de martirio de 18 cristianos en el aâ”œâ–’o 303 en Zaragoza. El apelativo de "innumerables" lleva al artista a representarlos en grupo numeroso, saliendo de la Puerta Cinegia para ser eliminados en fila por los malvados romanos en formaciâ”œâ”‚n. Al fondo, mientras, san Lamberto llega con su cabeza en la mano al lugar donde quiere ser enterrado, en la futura ubicaciâ”œâ”‚n del Monasterio de Santa Engracia.', 350, 300, 399, 'Siglo XIX', 'CENTRO', 41.65207800, -0.88104200, '0101000020E6100000B9E00CFE7E31ECBF7638BA4A77D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19639506708.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19639506708.webp', 'https://www.flickr.com/photos/zaragozaantigua/19639506708/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25271, 'Monumento a los Mâ”œأ­rtires 1902', '"1902, preparaciâ”œâ”‚n del Monumento a los Mâ”œأ­rtires mientras todavâ”œآ،a existâ”œآ،a la fuente de Neptuno. Fuente: Archivo Coyne, AHPZ.', 1902, 1902, 1902, 'Anos 1900', 'CENTRO', 41.65196900, -0.88092600, '0101000020E61000006B4606B98B30ECBFBF805EB873D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14894517541.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14894517541.webp', 'https://www.flickr.com/photos/zaragozaantigua/14894517541/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25275, 'Coso e iglesia de San Francisco 1808', 'Fundaciâ”œâ”‚n Lâ”œأ­zaro Galdiano/IFC. Fernando Brambila, 1808. Lâ”œأ­piz sobre papel. Dibujo del espacio del Coso que ocuparâ”œأ­ despuâ”œآ®s la plaza de San Fernando, actual plaza de Espaâ”œâ–’a. En primer plano, la iglesia del Hospital de Nuestra Seâ”œâ–’ora de Gracia o de Locos. A la derecha, con tres torretas, la iglesia de San Francisco. Aunque no se ve, entrambos edificios se halla el estrecho camino de Santa Engracia, hoy paseo de la Independencia. Este apunte servirâ”œأ­ a su autor para realizar la lâ”œأ­mina "Vista de la calle del Coso" de la serie "Ruinas de Zaragoza".', 1808, 1808, 1808, 'Siglo XIX', 'CENTRO', 41.65213600, -0.88081000, '0101000020E61000001DACFF73982FECBFAA45443179D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14985229539.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14985229539.webp', 'https://www.flickr.com/photos/zaragozaantigua/14985229539/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25281, 'Plaza de Espaâ”œâ–’a 1968', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. 08/04/1968. Fenomenal imagen del fondo escâ”œآ®nico configurado por el frontal del Coso "pleno", el que se asoma a la Plaza de Espaâ”œâ–’a, mâ”œأ­s famoso por sus interioridades y tripas en forma de Tubo al que entrar, por ejemplo, por la calle de los Mâ”œأ­rtires. Los anuncios comerciales incitando al consumo, aun los mâ”œأ­s cutres, maridaban bastante mejor con el paisaje y el paisanaje que las posmodernas y vacâ”œآ،as fachadas acristaladas y opacas que dâ”œآ®cadas despuâ”œآ®s se impondrâ”œأ­n como canon postmorten del viejo Tubo. En primer plano, los encapuchados que se llevan siempre la palma.', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65195000, -0.88101700, '0101000020E6100000810A47904A31ECBF4850FC1873D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15228524762.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15228524762.webp', 'https://www.flickr.com/photos/zaragozaantigua/15228524762/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
