INSERT INTO public.photos VALUES (25296, 'Coso 1808', '"Vista de la calle del Coso", grabado de la serie "Ruinas de Zaragoza" de Juan Gâ”œأ­lvez y Fernando Brambila, 1812-1813. Espacio del Coso visto desde la confluencia con la actual calle de Don Jaime. En primer plano, la iglesia del Hospital de Nuestra Seâ”œâ–’ora de Gracia o de Locos. A la derecha, con tres torretas, la iglesia del convento de San Francisco, al que tambiâ”œآ®n corresponde la torre alta de la izquierda. Aunque no se ve, entrambos edificios se halla el estrecho camino de Santa Engracia, hoy paseo de la Independencia. A la derecha, ruinas de la Cruz del Coso. Fuente visual: eszaragoza.blogspot.com.es/2014/05/la-crus-del-coso-en-za...', 1808, 1808, 1808, 'Siglo XIX', 'CENTRO', 41.65207800, -0.88104200, '0101000020E6100000B9E00CFE7E31ECBF7638BA4A77D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19083373031.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19083373031.webp', 'https://www.flickr.com/photos/zaragozaantigua/19083373031/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25302, 'Plaza Constituciâ”œâ”‚n 1902', 'Detalle de la plaza de la Constituciâ”œâ”‚n de Zaragoza en las fiestas de octubre de 1902, con el pie del monumento a los mâ”œأ­rtires engalanado para la ocasiâ”œâ”‚n, a la espera de que se coloque la estatua, dos aâ”œâ–’os despuâ”œآ®s. Fuente: www.facebook.com/photo.php?fbid=1458347304491395&set=...', 1902, 1902, 1902, 'Anos 1900', 'CENTRO', 41.65207800, -0.88104200, '0101000020E6100000B9E00CFE7E31ECBF7638BA4A77D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20438461526.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20438461526.webp', 'https://www.flickr.com/photos/zaragozaantigua/20438461526/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25304, 'Plaza de la Constituciâ”œâ”‚n 1903', 'La plaza de la Constituciâ”œâ”‚n, en el tiempo de espera que se prolongâ”œâ”‚ largarmente desde el desmontaje de la Fuente de la Princesa, y la inauguraciâ”œâ”‚n del Monumento a los Mâ”œأ­rtires de la Religiâ”œâ”‚n y de la Patria, que en la imagen aparece con el pedestal, pero sin nada que soportar. Hasta octubre de 1904, este serâ”œآ،a el panorama de la plaza, adobado mientras con alguna floreada ocasional. Mientras, la transiciâ”œâ”‚n de los sistemas de tracciâ”œâ”‚n tranviaria permitâ”œآ،a la ocasional convivencia entre unidades tiradas por mulas, y las nuevas y elâ”œآ®ctricas, como esta capturada por la Fototipia de Lucas Escolâ”œأ­. Fuente visual: www.delcampe.net/', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.65207800, -0.88104200, '0101000020E6100000B9E00CFE7E31ECBF7638BA4A77D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20656248781.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20656248781.webp', 'https://www.flickr.com/photos/zaragozaantigua/20656248781/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25317, 'Plaza de Espaâ”œâ–’a c.1956', 'Rincâ”œâ”‚n de la plaza de Espaâ”œâ–’a entre el Coso Medio y el paseo de la Independencia, con el velador del Restaurante Nacional. Fuente visual: Foto Casas Torres.', 1956, 1956, 1956, 'Anos 50', 'CENTRO', 41.65167000, -0.88084900, '0101000020E610000094DBF63DEA2FECBF65E42CEC69D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23239585269.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23239585269.webp', 'https://www.flickr.com/photos/zaragozaantigua/23239585269/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25329, 'Plaza de la Constituciâ”œâ”‚n c.1899', 'Imagen de la plaza de la Constituciâ”œâ”‚n centrada en la Fuente de Neptuno, todavâ”œآ،a como proveedora del lâ”œآ،quido elemento. Al fondo, la fachada del Coso, y entrada a la calle de Don Jaime I. Hacia la derecha, continuidad del Coso en su tramo Medio. Aunque la postal sigue llevando la marca de "Laurent", esta imagen no fue realizada por â”œآ®l, pues Jean Laurent habâ”œآ،a fallecido en 1892. Pero el mâ”œأ­s que justificado prestigio de la casa se mantenâ”œآ،a, aunque el fotâ”œâ”‚grafo fuera otro, en esta breve serie postal de finales del siglo XIX. Fuente visual: www.delcampe.es/', 1899, 1899, 1899, 'Siglo XIX', 'CENTRO', 41.65213500, -0.88097700, '0101000020E6100000F3E670ADF630ECBFDAC9E02879D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24626981980.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24626981980.webp', 'https://www.flickr.com/photos/zaragozaantigua/24626981980/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25330, 'Plaza Espaâ”œâ–’a 1983', 'Foto para postal de la plaza de Espaâ”œâ–’a. Fuente: www.delcampe.net', 1983, 1983, 1983, 'Anos 80', 'CENTRO', 41.65208700, -0.88099900, '0101000020E6100000E7E099D02431ECBFC992399677D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25202565469.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25202565469.webp', 'https://www.flickr.com/photos/zaragozaantigua/25202565469/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25331, 'Gigantes y cabezudos c.1915', 'Comparsa de gigantes y cabezudos en la plaza de la Constituciâ”œâ”‚n hacia 1915. Los gigantes, de izquierda a derecha: el Duque, la Negra, el Chino, la Duquesa y el Rey. Cabezudos que figuran, de izquierda a derecha: Forana, Torero, Berrugâ”œâ”‚n. Al fondo, Gran Hotel Restaurante Europa. Fuente visual: www.ebay.com/', 1915, 1915, 1915, 'Anos 10', 'CENTRO', 41.65208700, -0.88099900, '0101000020E6100000E7E099D02431ECBFC992399677D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25558566986.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25558566986.webp', 'https://www.flickr.com/photos/zaragozaantigua/25558566986/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25335, 'Plaza de la Constituciâ”œâ”‚n 1899', '"Place de la Constitution", Renâ”œآ® Ancely, 1899. Plaza de la Constituciâ”œâ”‚n y Fuente de la Princesa, o de Neptuno. En primer plano, un coche cerrado del que comenzara siendo ramal Cuarto tranviario, y ya era denominado lâ”œآ،nea de "Torrero", de tracciâ”œâ”‚n animal, cuando se estaba pensando en la transiciâ”œâ”‚n pactada hacia la elâ”œآ®ctrica, aunque tardarâ”œآ،a tres aâ”œâ–’os en comenzar. Al fondo, emboque del Coso Alto, donde destaca la antigua casa de Juan Coloma, dentro de un irrepetible paâ”œâ–’o de la soleada fachada de ese tramo del Coso, tambiâ”œآ®n denominado "brasero de los pobres", como literalmente ilustra esta luminosa imagen. Fuente: www.georgesancely.com/', 1899, 1899, 1899, 'Siglo XIX', 'CENTRO', 41.65213600, -0.88081000, '0101000020E61000001DACFF73982FECBFAA45443179D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27100961750.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27100961750.webp', 'https://www.flickr.com/photos/zaragozaantigua/27100961750/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25336, 'Plaza de la Constituciâ”œâ”‚n 1899', '"Place de la Constitution. Fontaine de Neptune", Renâ”œآ® Ancely, 1899. Imagen de la plaza de la Constituciâ”œâ”‚n centrada en el antiguo paâ”œâ–’o de la fachada del Coso entre los nâ”œâ•‘meros 31 y 37, casi ya en el emboque, a la derecha, de la calle de los Mâ”œأ­rtires. Focaliza la escena, con luminosidad natural, la funcional Fuente de la Princesa, o de Neptuno, portador de su cetro tridentino. Un carro de aguador, y una seâ”œâ–’ora con câ”œأ­ntaro, reponen existencias. Tras la fuente, transita un tranvâ”œآ،a de tracciâ”œâ”‚n animal, posiblemente de la lâ”œآ،nea de Circunvalaciâ”œâ”‚n. Hace fresco, y el sol de invierno, en un dâ”œآ،a despejado, sienta bien. Fuente: www.georgesancely.com/', 1899, 1899, 1899, 'Siglo XIX', 'CENTRO', 41.65213600, -0.88081000, '0101000020E61000001DACFF73982FECBFAA45443179D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27278686542.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27278686542.webp', 'https://www.flickr.com/photos/zaragozaantigua/27278686542/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25350, 'Plaza Constituciâ”œâ”‚n 1899', 'Foto: Francisco de Soto. "Acto de colocar la primera piedra del monumento a los Mâ”œأ­rtires de la religiâ”œâ”‚n y la libertad", octubre de 1899. Serâ”œأ­ inaugurado cinco aâ”œâ–’os despuâ”œآ®s, cambiando "libertad" por "patria". Al fondo, la Diputaciâ”œâ”‚n Provincial. Fuente: Revista Iris (Barcelona).', 1899, 1899, 1899, 'Siglo XIX', 'CENTRO', 41.65214800, -0.88106000, '0101000020E6100000520ABABDA431ECBF6E13EE9579D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33156317282.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33156317282.webp', 'https://www.flickr.com/photos/zaragozaantigua/33156317282/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25352, 'Vista aâ”œآ®rea plaza Espaâ”œâ–’a c.1968', 'Vista aâ”œآ®rea centrada en la plaza de Espaâ”œâ–’a. Al fondo, el centro histâ”œâ”‚rico. Fuente visual: foto Pedro Marco.', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65214500, -0.88103400, '0101000020E6100000034015376E31ECBFFD9FC37C79D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33541848882.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33541848882.webp', 'https://www.flickr.com/photos/zaragozaantigua/33541848882/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25357, 'Pl. de la Constituciâ”œâ”‚n 1935', 'Imagen de la reciâ”œآ®n remodelada fachada del Cafâ”œآ®-Bar Rojo en su tradicional ubicaciâ”œâ”‚n del nâ”¬â•‘ 5 de la plaza de la Constituciâ”œâ”‚n. Este establecimiento iniciâ”œâ”‚ su andadura en 1915 como Bar Rojo y Blanco, si bien coloquial y abreviadamente ya era conocido como &quot;El Rojo&quot;. En 1935 fue objeto de una intensa reforma, diseâ”œâ–’ada por el arquitecto Fausto Garcâ”œآ،a Marco, que le confiriâ”œâ”‚ un aspecto modernâ”œآ،simo y magnâ”œآ،fico. Signo de los tiempos, en diciembre de 1936 su nombre fue trocado por el de Cafâ”œآ® Nacional, a la par que la denominaciâ”œâ”‚n de la plaza transitaba a la fuerza desde la Constituciâ”œâ”‚n a la nueva Espaâ”œâ–’a vieja. Fuente visual: www.mecd.gob.es/.', 1935, 1935, 1935, 'Anos 30', 'CENTRO', 41.65161700, -0.88087900, '0101000020E61000003E7617282930ECBF4242942F68D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36423504231.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36423504231.webp', 'https://www.flickr.com/photos/zaragozaantigua/36423504231/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24900, 'Salesianos c.1971', 'El colegio de los Salesianos de Zaragoza se instalâ”œâ”‚ en la Ciudad Jardâ”œآ،n en el aâ”œâ–’o 1940. En la imagen, vista de sus instalaciones. En primer plano, la avenida de San Juan Bosco (fundador de los Salesianos). A la derecha, la calle de Pedro Lâ”œâ”‚pez de Luna. Fuente visual: www.todocoleccion.net/salesianos-zaragoza-vista-aerea~x43...', 1971, 1971, 1971, 'Anos 70', 'UNIVERSIDAD', 41.64447200, -0.90343100, '0101000020E61000009529E620E8E8ECBF0798F90E7ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15518495480.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15518495480.webp', 'https://www.flickr.com/photos/zaragozaantigua/15518495480/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25362, 'Plaza de Espaâ”œâ–’a 1983', 'Imagen capturada en la plaza de Espaâ”œâ–’a y centrada en el efecto provocado por la visual de dos convexos espejos situados en este frecuentado paso de trâ”œأ­fico urbano para mejorar la seguridad vial y reducir el riesgo de colisiones. El espejo superior refleja la fachada del Banco de Espaâ”œâ–’a, y el espejo inferior alcanza hasta el inclasificable inmueble del nâ”¬â•‘ 55 del Coso Medio. Al fondo, fachada del Coso recayente a la plaza rematada por los luminosos comerciales de la â”œآ®poca, y donde se abre el tradicional punto de ingreso al Tubo por la calle de los Mâ”œأ­rtires. En primer tâ”œآ®rmino, un autobâ”œâ•‘s urbano.', 1983, 1983, 1983, 'Anos 80', 'CENTRO', 41.65213000, -0.88062100, '0101000020E6100000537765170C2EECBFC85EEFFE78D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48781028063.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48781028063.webp', 'https://www.flickr.com/photos/zaragozaantigua/48781028063/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25364, 'Plaza de Espaâ”œâ–’a 1955', 'Colorista imagen capturada desde la altura del inmueble del nâ”¬â•‘ 2 de la calle de Don Jaime I, esquinero con el tramo medio del Coso, y centrada en la plaza de Espaâ”œâ–’a con la traza que mantenâ”œآ،a desde 1942, hasta la radical reforma de 1961. De fondo y de izquierda a derecha, el edificio del Banco Hispano-Americano, la nueva Diputaciâ”œâ”‚n Provincial ya terminada con el râ”œâ”‚tulo de la fachada que la identifica, y el inmueble del nâ”¬â•‘ 1 de la plaza, esquinero con el tramo alto del Coso, todavâ”œآ،a con su "palomar" sobre el tejado. Entre el movimiento peatonal y el creciente trâ”œأ­fico rodado, destacan algunas de las tranviaria lâ”œآ،neas que transitaban desde y por la plaza, como la lâ”œآ،nea 5. Venecia-Delicias (una composiciâ”œâ”‚n motor+remolque), y la 15. Casablanca (una unidad de la serie 150 o "Topolino").', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.65212800, -0.88094400, '0101000020E61000000470B378B130ECBF276728EE78D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49310316782.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49310316782.webp', 'https://www.flickr.com/photos/zaragozaantigua/49310316782/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23365, 'Almenara de La Sagrada 1833', '"Almenara de La Sagrada. Tomada desde el Barco por parte del Este mirando al Oeste", litografâ”œآ،a de Faramundo Blanchard. Esta almenara de desagâ”œâ•‌e se encuentra en Garrapinillos. Fuente visual: "Memoria histâ”œâ”‚rica del Canal imperial de Aragon: noticia sobre las utilidades que produce, y esplicacion de lo que contienen las lâ”œأ­minas que se publican", Madrid, 1833.', 1833, 1833, 1833, 'Siglo XIX', NULL, 41.67502600, -1.03376700, '0101000020E6100000CCF10A444F8AF0BF90F9804067D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19307287348.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19307287348.webp', 'https://www.flickr.com/photos/zaragozaantigua/19307287348/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25367, 'Plaza de la Constituciâ”œâ”‚n 1900', 'Imagen posiblemente capturada desde la altura del antiguo inmueble del nâ”¬â•‘ 51 del Coso, esquinero con el arranque de la calle de Don Jaime I, orientada hacia la plaza de la Constituciâ”œâ”‚n. El trâ”œأ­fago urbano incluye el movimiento de peatones, carros, y los coches de punto estacionados al principio del paseo de la Independencia, junto a uno de los urinarios fronteros con la plaza. A la derecha, la Fuente de la Princesa muestra la recurrente estampa de lavanderas y aguadores a los pies de Neptuno.', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.65208800, -0.88106200, '0101000020E610000080F277EFA831ECBF990E9D9E77D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50810577587.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50810577587.webp', 'https://www.flickr.com/photos/zaragozaantigua/50810577587/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25373, 'Plaza de Espaâ”œâ–’a c.1955', 'Imagen capturada desde el arranque del bulevar del paseo de la Independencia y centrada de forma parcial en la cuadrangular y arbolada glorieta central de la plaza de Espaâ”œâ–’a. El monumento a los Mâ”œأ­rtires de la Religiâ”œâ”‚n y la Patria queda fuera de plano y a la izquierda. Hacia el fondo, sombrilla que resguarda levemente a un guardia urbano de la implacable solanera frente al emboque a la calle de los Mâ”œأ­rtires, flanqueada a la derecha desde 1949 por el bar-cervecerâ”œآ،a Hergar. En primer tâ”œآ®rmino y sobre el adoquinado firme, trazado viario por el que el tranvâ”œآ،a circunvalaba la glorieta', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.65207200, -0.88106200, '0101000020E610000080F277EFA831ECBF9351651877D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52126528214.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52126528214.webp', 'https://www.flickr.com/photos/zaragozaantigua/52126528214/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25376, 'Plaza de la Constituciâ”œâ”‚n c. 1929', 'Imagen capturada desde cierta altura en el arranque del tramo medio del Coso, donde a la izquierda y en umbrâ”œآ،a figura Marâ”œآ،a Baraibar contemplando la animaciâ”œâ”‚n callejera desde un balcâ”œâ”‚n del hotel de Europa. De fondo escâ”œآ®nico y por contraste bien luminosa, la plaza de la Constituciâ”œâ”‚n con el ingreso a la calle de los Mâ”œأ­rtires a la derecha, en cuya esquina destaca el Cafâ”œآ® Oriental, antecedido por las oficinas del periâ”œâ”‚dico La Voz de Aragâ”œâ”‚n y el Cafâ”œآ® Royalty. Hacia el fondo continâ”œâ•‘a el soleado tramo alto del Coso que con sus toldos desplegados flanquea el arranque de la calle de Alfonso I. Sobre el firme, armâ”œâ”‚nica convivencia de peatones, carros, vehâ”œآ،culos a motor de explosiâ”œâ”‚n y un elâ”œآ®ctrico tranvâ”œآ،a cerrado, posiblemente en servicio en la lâ”œآ،nea 7. "Ayuntamiento".', 1929, 1929, 1929, 'Anos 20', 'CENTRO', 41.65179300, -0.88028300, '0101000020E61000004D310741472BECBF8061F9F36DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54333738140.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54333738140.webp', 'https://www.flickr.com/photos/zaragozaantigua/54333738140/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25509, 'Plaza de la Constituciâ”œâ”‚n 1903', 'Imagen de la convivencia del "Arco de la Real Maestranza" y del Pedestal de los "Mâ”œأ­rtires de la Religiâ”œâ”‚n y la Patria", sin esculturas. El Arco era una temporal composiciâ”œâ”‚n realizada con motivo de una visita a la ciudad del monarca del momento. Detrâ”œأ­s, el monumento, que acababa de destronar al monarca de los mares, estaba aâ”œâ•‘n sin mâ”œأ­rtires ni patria. Al fondo, la embocadura con la calle Mâ”œأ­rtires, antigua Cineja, por el arco del mismo nombre. Fuente visual: Eduardo Laborda, "Zaragoza, la ciudad sumergida", Onagro editores, 2008.', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.65207800, -0.88104200, '0101000020E6100000B9E00CFE7E31ECBF7638BA4A77D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19490467542.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19490467542.webp', 'https://www.flickr.com/photos/zaragozaantigua/19490467542/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25654, 'Don Jaime I 1969', 'La calle Don Jaime I como mero afluente de trâ”œأ­fico rodado al Coso y la plaza de Espaâ”œâ–’a. Tres carriles habilitados para dar entrada a la ciudad a quienes accedâ”œآ،an por el puente de Piedra. Los coches particulares eran mâ”œأ­s pequeâ”œâ–’os de tamaâ”œâ–’o medio, pero su hegemonâ”œآ،a iba camino de ser absoluta, con el desmantelamiento polâ”œآ،ticamente programado de las â”œâ•‘ltimas lâ”œآ،neas de ferrocarril urbano, o tranvâ”œآ،a. En la imagen, esquina de la calle Don Jaime en su encuentro con el Coso. Al fondo, la plaza de Espaâ”œâ–’a. Fuente: "Zaragoza viva" (1969)', 1969, 1969, 1969, 'Anos 60', 'CENTRO', 41.65193400, -0.87998200, '0101000020E61000009032E202D028ECBF4293C49272D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15250558713.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15250558713.webp', 'https://www.flickr.com/photos/zaragozaantigua/15250558713/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25803, 'Cine Goya 2008', 'Imagen del "antiguo" cine Goya, que fuera levantado en 1932 con diseâ”œâ–’o del arquitecto Ignacio Mendizâ”œأ­bal, y que habâ”œآ،a llegado al siglo XXI como uno de los escasos testimonios del estilo "Art Dâ”œآ®co" que supervivâ”œآ،an en esta entraâ”œâ–’able ciudad. En el aâ”œâ–’o 2005 fue cerrado, y en el momento de la imagen, en el aâ”œâ–’o de la esplendorosa Expo 2008, el edificio fue vaciado para, conservando su fachada, levantar en su interior necesarias viviendas y espacios comerciales varios. Fuente visual: "La ciudad de Zaragoza de 1908 a 2008", XIII Coloquio de arte aragonâ”œآ®s, IFC, 2008', 2008, 2008, 2008, 'Siglo XXI', 'CENTRO', 41.65106800, -0.88053800, '0101000020E6100000F4531C075E2DECBF6FBC3B3256D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19944327166.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19944327166.webp', 'https://www.flickr.com/photos/zaragozaantigua/19944327166/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25898, 'Coso Medio c.1973', 'Trolebâ”œâ•‘s y motocarro en la confluencia del Coso con la calle Josefa Amar y Borbâ”œâ”‚n. Fuente visual: foto Daniel Pâ”œآ®rez, en www.facebook.com/photo.php?fbid=10204174831144596&set...', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.65177000, -0.87974900, '0101000020E6100000DD09F65FE726ECBFC84109336DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15496982342.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15496982342.webp', 'https://www.flickr.com/photos/zaragozaantigua/15496982342/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25913, 'Plaza de la Constituciâ”œâ”‚n c.1896', 'Desde la altura del antiguo nâ”¬â•‘ 4 de la plaza de la Constituciâ”œâ”‚n, interesante imagen de la fachada del Coso recayente a esta plaza, en el tramo entre la embocadura a la calle de los Mâ”œأ­rtires, a la izquierda, y el antiguo nâ”¬â•‘ 49 del Coso. En el centro, luminoso y moderno, el nâ”¬â•‘ 43-45, en cuyos bajos se habâ”œآ،a reubicado hacâ”œآ،a bien poco la farmacia Râ”œآ،os. Sobre los tejados, despuntan levemente los remates de las torres de la iglesia parroquial de San Gil, y de la metropolitana de la Seo. Por el espacio de la plaza, dominada por la fuente de la Princesa, o Neptuno (fuera de plano, a la izquierda) circulan tranvâ”œآ،as pre-elâ”œآ®ctricos, en tiempos en que este era el nudo gordiano de todos los ramales abiertos (Arrabal, Circunvalaciâ”œâ”‚n, Bajo Aragâ”œâ”‚n, Torrero, y Madrid).', 1896, 1896, 1896, 'Siglo XIX', 'CENTRO', 41.65200200, -0.88073900, '0101000020E6100000CFF9298E032FECBF9B7631CD74D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28433958415.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28433958415.webp', 'https://www.flickr.com/photos/zaragozaantigua/28433958415/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25915, 'Pl. de Espaâ”œâ–’a 1970', 'Imagen de la unidad motora que tiraba de la composiciâ”œâ”‚n M+R 56 en la lâ”œآ،nea 5 "Venecia-Delicias", en direcciâ”œâ”‚n hacia la plaza de Rocasolano. Es abril y la primavera invita a recostar el codo en la ventanilla abierta, y mirar, y pensar, o sencillamente dejarse llevar por la sencilla contemplaciâ”œâ”‚n de lo contingente, como el fotâ”œâ”‚grafo que realiza esta captura. Al fondo, la referencial esquina de la plaza de Espaâ”œâ–’a donde intiman una entidad bancaria, y la DPZ Fuente visual: Gerardo Sancho Ramo, AMZ.', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.65213600, -0.88081000, '0101000020E61000001DACFF73982FECBFAA45443179D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29549591093.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29549591093.webp', 'https://www.flickr.com/photos/zaragozaantigua/29549591093/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25924, 'Plaza de la Constituciâ”œâ”‚n 1903', 'Despejada imagen de la plaza de la Constituciâ”œâ”‚n capturada en el lapso de tiempo tras el desmontaje de la afrancesada fuente de Neptuno, y la inauguraciâ”œâ”‚n del Monumento a los Mâ”œأ­rtires de la Religiâ”œâ”‚n y de la Patria, que aparece sâ”œâ”‚lo con el pedestal. En este trâ”œأ­nsito, la plaza fue reurbanizada, eliminando el arbolado previo. De telâ”œâ”‚n de fondo, a la izquierda, el edificio de la Diputaciâ”œâ”‚n Provincial. En el entorno de la plaza circulan elâ”œآ®ctricas unidades de la serie "Primitivos", en servicio en la lâ”œآ،nea Circunvalaciâ”œâ”‚n, y posiblemente Bajo Aragâ”œâ”‚n-Madrid. Fuente visual: cromolitografâ”œآ،a nâ”¬â•‘ 16 "Plaza de San Francisco", editada por Agustâ”œآ،n Alluâ”œآ® en la serie "Zaragoza", en www.todocoleccion.net/', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.65206100, -0.88104300, '0101000020E6100000D0D4EB168131ECBFA0FF1EBC76D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33894626923.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33894626923.webp', 'https://www.flickr.com/photos/zaragozaantigua/33894626923/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25934, 'Pl. de la Constituciâ”œâ”‚n c.1895', 'Inâ”œآ®dita y luminosa imagen de la plaza de la Constituciâ”œâ”‚n capturada a nivel de la terrosa calzada en el arranque del tramo medio del Coso, con una interesante panorâ”œأ­mica de la fachada oeste de la plaza, conformada de derecha a izquierda por los inmuebles del nâ”¬â•‘ 1, esquinero con el Coso Alto, el nâ”¬â•‘ 2 de la decimonâ”œâ”‚nica Diputaciâ”œâ”‚n Provincial de Zaragoza, y el esquinero nâ”¬â•‘ 3 con el principio de la calle de la Independencia, en cuyos bajos estaba el Cafâ”œآ® Suizo. La solanera se puede mitigar, en el centro de la plaza, con la isleta de humedad proporcionada por la Fuente de la Princesa y la umbrâ”œآ،a del cerco de â”œأ­rboles que la rodeaba, por donde asoma el bulto redondo de Neptuno, al que la calor que pueda llegar a hacer le importa bien poco. A la derecha, una "Jardinera" posiblemente del "tipo G", avanza arrastrada por caballerâ”œآ،as en servicio tal vez en la tranviaria lâ”œآ،nea del Bajo Aragâ”œâ”‚n, encaminada hacia la carretera de Castellâ”œâ”‚n. En primer tâ”œآ®rmino, un seâ”œâ–’or cruza con resoluciâ”œâ”‚n el Coso, cubierto con tremendo sombrero, hacia la calle de Don Jaime I.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.65208800, -0.88048300, '0101000020E610000011E335AFEA2CECBF990E9D9E77D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48024305998.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48024305998.webp', 'https://www.flickr.com/photos/zaragozaantigua/48024305998/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25997, 'Pl. de la Constituciâ”œâ”‚n 1925', 'Foto: Lucien Roisin. Vista desde el edificio La Joyita de la plaza de la Constituciâ”œâ”‚n 1 de buena parte del este de Zaragoza. En la plaza, a la derecha, el Gran Hotel de Europa. Un tranvâ”œآ،a de la serie 40 arrastra un remolque jardinera. Al fondo a la izquierda, el seminario de San Carlos. En el centro, el tramo del Coso Medio al completo. A la derecha, la torre de la iglesia de San Miguel y la de la central elâ”œآ®ctrica de la Compaâ”œâ–’â”œآ،a Aragonesa, en la calle San Miguel, entre Porcell y Blancas. Fuente visual: www.facebook.com/photo.php?fbid=1630323313854055&set=...', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.65209500, -0.88052700, '0101000020E6100000F9D687F5462DECBF4C7155D977D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21440773062.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21440773062.webp', 'https://www.flickr.com/photos/zaragozaantigua/21440773062/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26046, 'Pl. de la Constituciâ”œâ”‚n 1926', 'Vista de la plaza de la Constituciâ”œâ”‚n, "por fin pavimentada", en 1926. A la derecha, el Coso. A la izquierda, el paseo de la Independencia.', 1926, 1926, 1926, 'Anos 20', 'CENTRO', 41.65214500, -0.88092700, '0101000020E6100000823AE5D18D30ECBFFD9FC37C79D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31625382271.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31625382271.webp', 'https://www.flickr.com/photos/zaragozaantigua/31625382271/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21167, 'Puente de Santa Engracia 1893', 'Vista de la antigua Facultad de Medicina y Ciencias, con el puente de Santa Engracia sobre el Huerva en primer plano, ubicado en la actual confluencia del paseo de la Constituciâ”œâ”‚n con la plaza de Basilio Paraâ”œآ،so. Fuente visual: <a href=&quot;', 1893, 1893, 1893, 'Siglo XIX', 'CENTRO', 41.64714800, -0.88547300, '0101000020E610000056B60F79CB55ECBFFED5E3BED5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23828738014.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23828738014.webp', 'https://www.flickr.com/photos/zaragozaantigua/23828738014/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21179, 'Puente de Santa Engracia c.1890', 'Imagen capturada durante las obras de construcciâ”œâ”‚n del nuevo edificio para las Facultades de Medicina y Ciencias de la Universidad de Zaragoza, levantado sobre el campo de Lezcano con proyecto del arquitecto Ricardo Magdalena. En primer tâ”œآ®rmino, el puente de Santa Engracia sobre el râ”œآ،o Huerva, que hacia la izquierda daba acceso a los paseos de Sagasta y de las Damas, y sobre el que desde 1886 transitaban los tranvâ”œآ،as de la lâ”œآ،nea de Torrero. Tras el edificio de las dos Facultades, se construirâ”œآ،a el Hospital Clâ”œآ،nico, y mâ”œأ­s allâ”œأ­, el Departamento Anatâ”œâ”‚mico. El conjunto fue inaugurado oficialmente el 18 de octubre de 1893. Este puente fue construido en 1885, quedando soterrado en 1923 con el cubrimiento de ese tramo del râ”œآ،o Huerva.', 1890, 1890, 1890, 'Siglo XIX', 'CENTRO', 41.64708500, -0.88555800, '0101000020E6100000E3C116BB7D56ECBFB75D68AED3D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33546560358.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33546560358.webp', 'https://www.flickr.com/photos/zaragozaantigua/33546560358/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21190, 'Plaza de Aragâ”œâ”‚n 1893', 'Inâ”œآ®dita imagen capturada desde la altura del hotelito del nâ”¬â•‘ 10 de la plaza de Aragâ”œâ”‚n y centrada en la luminosa fachada de la nueva sede de la Capitanâ”œآ،a General, cuyo proyecto fue realizado bajo la supervisiâ”œâ”‚n de los ingenieros militares Carlos Vila y Lara, Francisco Rizzo, Honorato de Saleta y Josâ”œآ® Gâ”œâ”‚mez Pallete. Su alabeada fachada se adecua a la planta de los solares 2, 3 y 4 de la Manzana E adquiridos por el Ramo de la Guerra tras la urbanizaciâ”œâ”‚n de los terrenos donde tuvo lugar la Exposiciâ”œâ”‚n aragonesa de 1868. A la derecha, vista parcial del vecino hotelito del nâ”¬â•‘ 10 de la plaza, ya remodelado de su traza original segâ”œâ•‘n proyecto del arquitecto Fernando de Yarza Fernâ”œأ­ndez-Treviâ”œâ–’o. El solar de este inmueble, y sobre el plano del proyecto de la Capitanâ”œآ،a, se intentâ”œâ”‚ que tambiâ”œآ®n fuera adquirido para formar parte del recinto militar, pero no fructificaron las gestiones. A la izquierda, vista del arbolado paseo de la Lealtad y el desemboque en â”œآ®l del camino de los Cubos, con la esquinera zona inmediata a la Capitanâ”œآ،a todavâ”œآ،a en obras de urbanizaciâ”œâ”‚n', 1893, 1893, 1893, 'Siglo XIX', 'CENTRO', 41.64807900, -0.88567600, '0101000020E61000005F44DB317557ECBFB91CAF40F4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50089723907.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50089723907.webp', 'https://www.flickr.com/photos/zaragozaantigua/50089723907/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21199, 'Puente de Santa Engracia c.1894', 'Imagen capturada en el momento en que una calesa cubierta cruza el puente de Santa Engracia sobre el râ”œآ،o Huerva, posiblemente encaminada hacia la puerta de Santa Engracia y la plaza de Aragâ”œâ”‚n. Al fondo, el nuevo edificio construido para la enseâ”œâ–’anza de las Facultades de Medicina y Ciencias, actual Paraninfo de la Universidad de Zaragoza. Sobre el barrizal la calesa circula por el trazado por el que desde septiembre de 1886 transitaba el tranvâ”œآ،a de la lâ”œآ،nea de Torrero.', 1894, 1894, 1894, 'Siglo XIX', 'CENTRO', 41.64686100, -0.88561100, '0101000020E6100000994A3FE1EC56ECBF68075C57CCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53152875909.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53152875909.webp', 'https://www.flickr.com/photos/zaragozaantigua/53152875909/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21274, 'Puerta de Santa Engracia 1903', 'Imagen de la puerta de Santa Engracia. Tras las rejas, y a la izquierda, el edificio de Capitanâ”œآ،a en la arbolada glorieta de Pignatelli. Al fondo, el final de la calle de la Independencia. La postal fue editada por el establecimiento "La Reina de las Tintas" en 1903, dentro de una serie titulada "Zaragoza". El ejemplar de la imagen fue circulado en mayo de 1904, cuatro meses antes del derribo de la â”œâ•‘ltima versiâ”œâ”‚n de esta puerta. Fuente: www.todocoleccion.net/', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.64785400, -0.88552600, '0101000020E61000000C3F389F3A56ECBF994A3FE1ECD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22820925978.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22820925978.webp', 'https://www.flickr.com/photos/zaragozaantigua/22820925978/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21278, 'Glorieta de Pignatelli c.1900', 'Imagen de la Glorieta de Pignatelli, identificada ya como "Plaza de Aragâ”œâ”‚n", antes de su remodelaciâ”œâ”‚n e instalaciâ”œâ”‚n en su centro del Monumento al Justicia, en 1904. En primer tâ”œآ®rmino, a la derecha, estatua de Ramâ”œâ”‚n de Pignatelli. Al fondo, Facultad de Medicina, Capitanâ”œآ،a y Puerta de Santa Engracia. Fuente: www.delcampe.net', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.64782300, -0.88521400, '0101000020E610000054C37E4FAC53ECBF5E4C33DDEBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24456990035.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24456990035.webp', 'https://www.flickr.com/photos/zaragozaantigua/24456990035/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21305, 'Puerta de Santa Engracia c.1903', 'Imagen de la puerta de Santa Engracia centrada en el ingreso principal a la plaza de Aragâ”œâ”‚n, jalonado por las casetas de cobro de Consumos. El tendido tranviario de la lâ”œآ،nea de Torrero circulaba a izquierda y derecha de la imagen, como sucedâ”œآ،a desde la inauguraciâ”œâ”‚n de la lâ”œآ،nea en 1886, por lo que parece que tuvo poca responsabilidad en el derribo de esta â”œâ•‘ltima versiâ”œâ”‚n de la histâ”œâ”‚rica puerta de Santa Engracia, realizado un aâ”œâ–’o despuâ”œآ®s. Fuente visual: Colecciâ”œâ”‚n Montserrat/Sociedad Estereoscâ”œâ”‚pica Espaâ”œâ–’ola (Barcelona), en Zaragoza estereoscâ”œâ”‚pica, fotografâ”œآ،a profesional y comercial 1850-1970, PUZ.', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.64785400, -0.88552600, '0101000020E61000000C3F389F3A56ECBF994A3FE1ECD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34834825882.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34834825882.webp', 'https://www.flickr.com/photos/zaragozaantigua/34834825882/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21469, 'Colegio del Salvador c.1910', 'Fachada principal del colegio del Salvador. Al fondo, edificio de la Capitanâ”œآ،a General en la plaza de Aragâ”œâ”‚n.', 1910, 1910, 1910, 'Anos 10', 'CENTRO', 41.64660900, -0.88474400, '0101000020E610000094A12AA6D24FECBF4E266E15C4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53478001422.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53478001422.webp', 'https://www.flickr.com/photos/zaragozaantigua/53478001422/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23393, 'Puente de La Muela 1796', 'Dibujo representando la planta y perfil del puente construido sobre el Canal Imperial para dar paso al camino de la Muela, tambiâ”œآ®n denominado camino Real de las Postas para Madrid. Labrado en piedra de sillerâ”œآ،a, ademâ”œأ­s de mejorar considerablemente el trâ”œأ­nsito caminero hacia la Villa y Corte, por â”œآ®l tambiâ”œآ®n pasaba la acequia de Santa Bâ”œأ­rbara. Fuente visual: Dibujo de Fâ”œآ®lix Guitarte, grabado por Manuel Navarro, e impreso en Zaragoza por Francisco Magallâ”œâ”‚n (1796) dentro de la "Descripciâ”œâ”‚n de los canales Imperial de Aragâ”œâ”‚n i Real de Tauste dedicada a los augustos soberanos D. Carlos IV i D. Marâ”œآ،a Luisa de Borbâ”œâ”‚n por el actual protector por S. Magestad de ambos canales el conde de Sâ”œأ­stago".', 1796, 1796, 1796, 'Siglo XIX', NULL, 41.64029600, -0.95480000, '0101000020E6100000CB10C7BAB88DEEBF3BE12538F5D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45628886361.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45628886361.webp', 'https://www.flickr.com/photos/zaragozaantigua/45628886361/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21633, 'Plaza de Aragâ”œâ”‚n 1923', 'Luminosa imagen capturada en la plaza de Aragâ”œâ”‚n durante el râ”œأ­pido paso por la ciudad, a comienzos de diciembre de ese aâ”œâ–’o, del rey Alfonso XIII de Borbâ”œâ”‚n y la reina Victoria Eugenia de Battenberg, en su regreso del viaje oficial al reino de Italia, donde se reunieron con el rey Victor Manuel III, el papa Pâ”œآ،o XI, y el presidente del Consejo de ministros, Benito Mussolini. Si bien este viaje institucional habâ”œآ،a sido organizado durante los â”œâ•‘ltimos coletazos de la Monarquâ”œآ،a constitucional, se convirtiâ”œâ”‚ en un acto polâ”œآ،tico para normalizar y legitimar el golpe de Estado del general Primo de Rivera (que les acompaâ”œâ–’â”œâ”‚ en el viaje) realizado unas semanas antes, y la Dictadura reciâ”œآ®n instaurada. Ademâ”œأ­s, escenificâ”œâ”‚ la buena sintonâ”œآ،a de estos dos regâ”œآ،menes dictatoriales en la convulsa Europa de comienzos de los aâ”œâ–’os 20. En la imagen, la Real pareja acompaâ”œâ–’ada por el alcalde Juan Fabiani en el coche que les transportaba por la ciudad durante su estancia, junto a las verjas de la Capitanâ”œآ،a General, donde se hospedaron. Al fondo, algunos de los hotelitos del lado oeste de la plaza de Aragâ”œâ”‚n. En primer tâ”œآ®rmino, el nâ”¬â•‘ 10, durante las obras de recrecimiento y remodelaciâ”œâ”‚n acometidas para darle un extra en altura de dos plantas, mâ”œأ­s â”œأ­tico. A continuaciâ”œâ”‚n y tras la calle de Canfranc, el inmueble del nâ”¬â•‘ 11.', 1923, 1923, 1923, 'Anos 20', 'CENTRO', 41.64805500, -0.88546100, '0101000020E610000046459C4EB255ECBF30815B77F3D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48502848826.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48502848826.webp', 'https://www.flickr.com/photos/zaragozaantigua/48502848826/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23066, 'Puente del ferrocarril 1997', '"Puente del ferrocarril", â”œâ”‚leo sobre lienzo, Ignacio Mayayo, 1997. Vista del puente del ferrocarril que cruzaba el râ”œآ،o Ebro (a la derecha, fuera de plano) entre 1968 y 2007. Estâ”œأ­ tomada desde el actual camino de La Alfranca, que lleva hasta allâ”œآ، pasando por La Cartuja Baja. Al fondo, bloques de viviendas en la calle de Fray Luis Urbano del barrio de Las Fuentes. Este puente se mantuvo en pie provisionalmente entre el de Manuel Gimâ”œآ®nez Abad y el actual puente del AVE.', 1997, 1997, 1997, 'Anos 90', 'LAS FUENTES', 41.65078900, -0.85334500, '0101000020E61000005890662C9A4EEBBF5CCCCF0D4DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52471595717.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52471595717.webp', 'https://www.flickr.com/photos/zaragozaantigua/52471595717/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21900, 'Pâ”¬â•‘. de Marina Moreno 1939', 'Imagen capturada en el arranque del paseo de Marina Moreno (hasta poco antes, avenida de Galâ”œأ­n y Garcâ”œآ،a Hernâ”œأ­ndez) durante el ceremonial de homenaje a la XV bandera de la Legiâ”œâ”‚n (entre 1936-37 Bandera o Tercio General Sanjurjo), mediante la imposiciâ”œâ”‚n de la corbata de San Fernando por el general â”œأ¼lvaro Sueiro y Vilariâ”œâ–’o, con presencia en la tribuna de autoridades del presidente de la DPZ Miguel Alluâ”œآ® Salvador y el alcalde Juan Josâ”œآ® Rivas Bosch. De telâ”œâ”‚n de fondo edilicio, traseras de los "hotelitos" nâ”¬â•‘ 7 y 6 de la plaza de Aragâ”œâ”‚n, bajo los que esperan su turno para recibir diversas medallas militares concedidas por mâ”œآ®ritos adquiridos durante la "Cruzada" de 1936-39 (esta ceremonia se realizâ”œâ”‚ en octubre de este â”œâ•‘ltimo aâ”œâ–’o). Entre ellos destaca el coronel Santiago Amado Lâ”œâ”‚riga, que en 1943 serâ”œآ،a segundo jefe de la Divisiâ”œâ”‚n Azul durante su participaciâ”œâ”‚n en la "Cruzada contra el Bolchevismo".', 1939, 1939, 1939, 'Anos 30', 'CENTRO', 41.64751800, -0.88478500, '0101000020E610000039B9DFA12850ECBF21C9ACDEE1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51410344109.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51410344109.webp', 'https://www.flickr.com/photos/zaragozaantigua/51410344109/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21970, 'Plaza de Aragâ”œâ”‚n 1946', 'Imagen de la temporal composiciâ”œâ”‚n tranviaria de extraordinaria capacidad formada por las novâ”œآ،simas unidades nâ”¬â•‘ 202 (haciendo de "motor") y nâ”¬â•‘ 203 (en funciones de "remolque") de la serie "200", habilitadas para la Lâ”œآ،nea 11. Parque, circulando en direcciâ”œâ”‚n a la plaza del Emperador Carlos V. De fondo, el provinciano panorama edilicio de la antigua plaza de Aragâ”œâ”‚n. Fuente visual: Archivo Construcciones y Auxiliar de Ferrocarriles (DARA-AHPZ)', 1946, 1946, 1946, 'Anos 40', 'CENTRO', 41.64802900, -0.88528100, '0101000020E610000048A5D8D13854ECBF07EE409DF2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23600301759.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23600301759.webp', 'https://www.flickr.com/photos/zaragozaantigua/23600301759/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22074, 'Pl. de Basilio Paraâ”œآ،so 1951', 'Imagen capturada desde cierta altura en el Edificio Elâ”œآ،seos con vista, en primer tâ”œآ®rmino de la reciâ”œآ®n reformada plaza de Basilio Paraâ”œآ،so, con sus imponentes columnas-farolas de hormigâ”œâ”‚n armado. La ovalada isleta central ya habâ”œآ،a sido despojada previamente (octubre de 1950) de la estatua de Câ”œآ®sar Augusto, y tendrâ”œآ،a que esperar unos aâ”œâ–’os hasta la instalaciâ”œâ”‚n de una llamativa fuente. Dos trolebuses de la nueva lâ”œآ،nea del Terminillo (estrenada en mayo) uno por direcciâ”œâ”‚n de terminal (Duquesa Villahermosa y paseo de la Independencia), coinciden en la plaza. Fuente visual: Zaragoza 1908-2008. FCC.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.64723600, -0.88584000, '0101000020E6100000F0A2AF20CD58ECBF9D6516A1D8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15524929189.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15524929189.webp', 'https://www.flickr.com/photos/zaragozaantigua/15524929189/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22078, 'Pl. de Basilio Paraâ”œآ،so 1958', 'Câ”œآ®sar Gracia Jarque "Plaza de Paraâ”œآ،so."', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.64723600, -0.88584000, '0101000020E6100000F0A2AF20CD58ECBF9D6516A1D8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15752856778.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15752856778.webp', 'https://www.flickr.com/photos/zaragozaantigua/15752856778/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
