INSERT INTO public.photos VALUES (22197, 'Pl. de Basilio Paraâ”œآ،so 1958', 'Imagen de la plaza de Paraâ”œآ،so y la Facultad de Medicina, uno de los espacios recurrentes de la ciudad editados luego como postal. Circula una composiciâ”œâ”‚n tranviaria de la lâ”œآ،nea 5 "Torrero-Delicias" (posiblemente, un motor de la serie 60, tirando de un remolque de la 70) en direcciâ”œâ”‚n sur. Fuente visual: Ediciones DARVI, en www.abebooks.com', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.64730700, -0.88579600, '0101000020E610000008AF5DDA7058ECBF66BCADF4DAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33333814704.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33333814704.webp', 'https://www.flickr.com/photos/zaragozaantigua/33333814704/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22212, 'Pl. de Basilio Paraâ”œآ،so 1958', 'Fotografâ”œآ،a tomada desde la altura del Edificio Elâ”œآ،seos y centrada en la plaza de Basilio Paraâ”œآ،so tras la remodelaciâ”œâ”‚n culminada con una fuente caracterizada por sus juegos de agua, a distintas alturas, y en colores. Tres aâ”œâ–’os mâ”œأ­s tarde esta fuente fue ampliada con mâ”œأ­s chorros y luminarias, para embellecer aâ”œâ•‘n mâ”œأ­s lo que ya era un primor. Alrededor circulan un par de trolebuses de la lâ”œآ،nea Terminillo, los dos de regreso a la terminal de la plaza de Santa Engracia, un tranvâ”œآ،a de la lâ”œآ،nea 11. Parque, hacia el original Parque de Buenavista, y un tranvâ”œآ،a de la lâ”œآ،nea 15. Casablanca, hacia la terminal de la plaza de Espaâ”œâ–’a. La panorâ”œأ­mica de la plaza de Aragâ”œâ”‚n ofrece una buena vista de los hotelitos a ambos lados de su ovalada y arbolada traza. Este escenario serâ”œأ­ radicalmente modificado pocos aâ”œâ–’os despuâ”œآ®s, cuando las obras de remodelaciâ”œâ”‚n del eje de comunicaciâ”œâ”‚n entre la plaza de Espaâ”œâ–’a y la plaza de Aragâ”œâ”‚n. Fuente visual: www.delcampe.net', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.64754400, -0.88577600, '0101000020E6100000419DF2E84658ECBF4B5CC7B8E2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45981521284.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45981521284.webp', 'https://www.flickr.com/photos/zaragozaantigua/45981521284/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22216, 'Pl. de Basilio Paraâ”œآ،so 1954', 'Imagen capturada desde la relativa altura del antiguo y desaparecido inmueble del nâ”¬â•‘ 1 del paseo de Pamplona, esquinero con la calle del Doctor Cerrada, y centrada en el entorno de la plaza de Paraâ”œآ،so y su engarce con la plaza de Aragâ”œâ”‚n, de la que destacan los hotelitos construidos desde la calle de Agustina Simâ”œâ”‚n, antigua de Puigcerdâ”œأ­. A la izquierda, el chaflâ”œأ­n del edificio de la Capitanâ”œآ،a General. Al fondo, la moderna manzana recayente entre el paseo de Marina Moreno y la calle del Arquitecto Yarza, y el esquinero edificio del arranque de la calle de Madre Vedruna. A la derecha se destaca la mole del colegio del Salvador. Por la plaza de Paraâ”œآ،so transita un trolebâ”œâ•‘s BUT de un piso en servicio en la lâ”œآ،nea Terminillo, de regreso de la Ciudad Jardâ”œآ،n; y un tranvâ”œآ،a de la serie 200 en servicio en la lâ”œآ،nea 11.Parque encaminada hacia la terminal de la plaza de Espaâ”œâ–’a. Fuente visual: AMZ', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.64754400, -0.88577600, '0101000020E6100000419DF2E84658ECBF4B5CC7B8E2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46878111802.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46878111802.webp', 'https://www.flickr.com/photos/zaragozaantigua/46878111802/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22221, 'Plaza de Paraâ”œآ،so c.1957', 'Interesante imagen capturada en la plaza de Basilio Paraâ”œآ،so y centrada en el referencial Edificio Elâ”œآ،seos, especialmente tras la aparatosa instalaciâ”œâ”‚n en su parte superior de la tremenda peineta publicitaria de una entidad de ahorro local. Hacia la izquierda arranca en ascenso el paseo del General Mola, por donde se encamina una composiciâ”œâ”‚n tranviaria de la serie 100, en servicio en la lâ”œآ،nea 5. Venecia-Delicias. En la plaza destaca el aâ”œآ®reo tendido tranviario y trolebusero, tal que una elâ”œآ®ctrica tela de araâ”œâ–’a; la acuâ”œأ­tica fuente y el puesto a cubierto del guardia urbano encargado de regular el trâ”œأ­nsito viario, que no es mucho. Hacia la derecha, arranque del paseo de Calvo Sotelo y vista parcial de la Facultad de Medicina y Ciencias de la Universidad.', 1957, 1957, 1957, 'Anos 50', 'CENTRO', 41.64718900, -0.88549300, '0101000020E61000001DC87A6AF555ECBF5CAAD216D7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48330009202.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48330009202.webp', 'https://www.flickr.com/photos/zaragozaantigua/48330009202/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22223, 'Plaza de Aragâ”œâ”‚n 1958', 'Imagen capturada en original blanco y negro en la plaza de Aragâ”œâ”‚n, y coloreada posteriormente a mano para ser editada como postal. La antropolâ”œâ”‚gica escena recoge el dominguero paseo arriba, paseo abajo, por el antiguo bulevar de Independencia, al fondo, y su continuidad por la arbolada glorieta o plaza de Aragâ”œâ”‚n, echando la tarde en una actividad sana y muy poco economicista, para horror del sector terciario. Centra la imagen el Monumento al Justiciazgo. Detrâ”œأ­s, el cenotafio "A los funcionarios muertos en agosto de 1920".', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.64806300, -0.88492500, '0101000020E6100000A835CD3B4E51ECBFB35F77BAF3D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48953051398.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48953051398.webp', 'https://www.flickr.com/photos/zaragozaantigua/48953051398/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22258, 'Plaza de Paraâ”œآ،so c.1964', 'Plaza de Basilio Paraâ”œآ،so. Trolebâ”œâ•‘s; fuente. Fuente visual: postal Garcia Garrabella.', 1964, 1964, 1964, 'Anos 60', 'CENTRO', 41.64707900, -0.88568100, '0101000020E6100000D10836AE7F57ECBFD576137CD3D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14728373298.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14728373298.webp', 'https://www.flickr.com/photos/zaragozaantigua/14728373298/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22265, 'Vista aâ”œآ®rea plaza Paraâ”œآ،so 1966', 'Vista aâ”œآ®rea de 1966. Plaza Aragâ”œâ”‚n en primer plano; plaza Paraâ”œآ،so, Sagasta, Gran Vâ”œآ،a...', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.64712400, -0.88566400, '0101000020E61000004ED367075C57ECBF753A90F5D4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14847263268.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14847263268.webp', 'https://www.flickr.com/photos/zaragozaantigua/14847263268/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22403, 'Plaza de Paraâ”œآ،so 1961', 'Colorista vista en altura para postal de la plaza de Paraâ”œآ،so, centrada en la entraâ”œâ–’able rotonda acuâ”œأ­tica y luminosa, y la Facultad de Medicina y Ciencias. A la izquierda, el paseo de Calvo Sotelo. A la derecha, el paseo de Pamplona. En primer plano, tranvâ”œآ،a de la lâ”œآ،nea 11 "Parque", con una novâ”œآ،sima unidad de los "300", que serâ”œآ،a la â”œâ•‘ltima serie construida para la histâ”œâ”‚rica red zaragozana, antes de ser arrasada a mediados de los 70. Fuente visual: Editorial Garrabella, www.delcampe.net/', 1961, 1961, 1961, 'Anos 60', 'CENTRO', 41.64713800, -0.88567300, '0101000020E61000001B683EE76E57ECBFDAFF006BD5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23840123526.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23840123526.webp', 'https://www.flickr.com/photos/zaragozaantigua/23840123526/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22404, 'Plaza de Paraâ”œآ،so 1969', 'Imagen en altura de la antigua plaza de Paraâ”œآ،so, con un amplio catâ”œأ­logo de elementos de un pasado que pasâ”œâ”‚, salvo en muy contadas y excepcionales singularidades. El resto, sean componentes edilicios, estâ”œأ­ticos, semovientes, sombras, vegetaciâ”œâ”‚n, ornamento, fluidos varios, son muy otros. Aunque, en el fondo, la suma de todos sus elementos energâ”œآ®ticos esenciales siga siendo la misma. Fuente: Gerardo Sancho Ramo, en AMZ.', 1969, 1969, 1969, 'Anos 60', 'CENTRO', 41.64713800, -0.88567300, '0101000020E61000001B683EE76E57ECBFDAFF006BD5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23943835502.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23943835502.webp', 'https://www.flickr.com/photos/zaragozaantigua/23943835502/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22424, 'Plaza de Paraâ”œآ،so c.1967', 'Plaza de Basilio Paraâ”œآ،so. Al fondo, paseo de Pamplona. Fuente: Foto para postal de Comercial Josan. Cesiâ”œâ”‚n de la familia de Josâ”œآ® Marâ”œآ،a Sanz Gonzâ”œأ­lez a Rafael Castillejo. Dataciâ”œâ”‚n y procesado:', 1967, 1967, 1967, 'Anos 60', 'CENTRO', 41.64730700, -0.88579600, '0101000020E610000008AF5DDA7058ECBF66BCADF4DAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27321578912.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27321578912.webp', 'https://www.flickr.com/photos/zaragozaantigua/27321578912/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22534, 'Plaza Paraâ”œآ،so 1975', '1975. Aâ”œآ®rea vista del entorno de la Plaza de Paraâ”œآ،so, Plaza de Aragâ”œâ”‚n, Paseo Independencia, Paseo Pamplona, y Marina Moreno. Al fondo, la Avenida de los Pirineos, con la ACTUR como gran actuaciâ”œâ”‚n urbanâ”œآ،stica de urgencia que, lo que se dice urgencia, ya no lo era mucho. En la Plaza de Salamero, a la izquierda, impone la visiâ”œâ”‚n del edificio reciâ”œآ®n nacido, obra de Lorenzo Monclâ”œâ•‘s Ramâ”œآ،rez, con 55,34 metros de altura, y 16 plantas. Todo un impacto. En la Plaza de Aragâ”œâ”‚n, siguen cayendo hotelitos, en beneficios de otros edificios de mâ”œأ­s alturas y beneficios. La justificaciâ”œâ”‚n es que, ya puestos, se trataba de igualar visualmente los edificios de toda la Plaza, para atraer turistas e inversiones. El solar del antiguo Colegio de los PP Jesuitas, abajo, ejerce como transitorio vivero de herbâ”œأ­ceas silvestres, mientras culminan las operaciones urbanâ”œآ،sticas de intercambio de cromos que, ad maiorem dei gloriam, colocarâ”œأ­n aquâ”œآ، en breve la nueva sede central de una importante entidad de ahorro.', 1975, 1975, 1975, 'Anos 70', 'CENTRO', 41.64718800, -0.88572000, '0101000020E610000047382D78D157ECBF8C2E6F0ED7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14793197140.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14793197140.webp', 'https://www.flickr.com/photos/zaragozaantigua/14793197140/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22589, 'Edificio central Ibercaja 1977', 'Imagen de las vallas metâ”œأ­licas que delimitaban el perâ”œآ،metro de obra de construcciâ”œâ”‚n del edificio central de la Caja de Ahorros y Monte de Piedad de Zaragoza, Aragâ”œâ”‚n y Rioja en la plaza de Paraâ”œآ،so, segâ”œâ•‘n proyecto de Teodoro Râ”œآ،os Usâ”œâ”‚n. En este solar se ubicaban anteriormente el veterano colegio y la joven iglesia de los Jesuitas. La captura, desde el Paseo del General Mola, permite una visual irrepetible de los bloques de viviendas de San Ignacio de Loyola, tramo Pedro Marâ”œآ،a Ric-Francisco de Vitoria. Fuente visual: "La evoluciâ”œâ”‚n urbana de Zaragoza al este del Huerva", Carmen Santos Vich, 1978.', 1977, 1977, 1977, 'Anos 70', 'CENTRO', 41.64661700, -0.88490000, '0101000020E6100000705F07CE1951ECBFD1048A58C4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15751683372.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15751683372.webp', 'https://www.flickr.com/photos/zaragozaantigua/15751683372/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22611, 'Plaza Paraâ”œآ،so 1973', 'Imagen del subsuelo de la fuente luminosa instalada en 1961 en la plaza de Paraâ”œآ،so de Zaragoza. En el centro, fumando, Josâ”œآ® Longarâ”œâ”‚n, encargado de su mantenimiento. En 1975 esta fuente se trasladâ”œâ”‚ al Parque Primo de Rivera, junto a la subida al Batallador. Fuente: Diario Amanecer, 24 de mayo de 1973.', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.64714800, -0.88547300, '0101000020E610000056B60F79CB55ECBFFED5E3BED5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19173029259.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19173029259.webp', 'https://www.flickr.com/photos/zaragozaantigua/19173029259/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22734, 'Calvo Sotelo 1973', 'Imagen de una unidad tranviaria de la serie 200 (posiblemente, el nâ”¬â•‘ 212), en servicio en la lâ”œآ،nea 11 "Parque-San Josâ”œآ®", saliendo del paseo de Calvo Sotelo, al fondo, y entrando en el espacio de la plaza de Basilio Paraâ”œآ،so, hacia la terminal en San Josâ”œآ®. A la derecha, el edificio de la Facultad de Medicina y Ciencias. Fuente visual: Foto Heidiland, a travâ”œآ®s de www.forotrenes.com/', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.64681000, -0.88568800, '0101000020E610000070B54E5C8E57ECBFE65C8AABCAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31172688815.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31172688815.webp', 'https://www.flickr.com/photos/zaragozaantigua/31172688815/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22740, 'Plaza Paraâ”œآ،so 1972', 'Un tranvâ”œآ،a de la lâ”œآ،nea 11 "Parque-San Josâ”œآ®" se dirige hacia el parque Primo de Rivera, a su paso por la plaza de Basilio Paraâ”œآ،so, en octubre, durante la 32â”¬آ¬ Ferial Oficial y Nacional de Muestras. Al fondo, un trolebâ”œâ•‘s encaminado hacia la Ciudad Jardâ”œآ،n, el edificio de Capitanâ”œآ،a, y el nuevo bloque de plaza de Aragâ”œâ”‚n nâ”¬â•‘ 11 en construcciâ”œâ”‚n. Fuente visual: www.facebook.com/photo.php?fbid=1577623582253481&set=...', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.64727400, -0.88587100, '0101000020E6100000B131AF230E59ECBF8BC6DADFD9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31624782131.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31624782131.webp', 'https://www.flickr.com/photos/zaragozaantigua/31624782131/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22776, 'Plaza de Paraâ”œآ،so 1976', 'Maqueta del moderno edificio proyectado como sede central de la Caja de Ahorros de Zaragoza, Aragâ”œâ”‚n y Rioja, a construir en la plaza de Paraâ”œآ،so. Ello suponâ”œآ،a el traslado desde la sede construida sobre el solar de la antigua casa de Zaporta hasta los terrenos del colegio del Salvador adquiridos a los PP. Jesuitas. Su realizaciâ”œâ”‚n, con licencia como edificio de caracterâ”œآ،sticas singulares, y proyecto de Teodoro Râ”œآ،os Usâ”œâ”‚n, tuvo un coste econâ”œâ”‚mico de varios miles de millones de pesetas. El resultado, un referente sâ”œآ،mbolo visual a la altura de uno de los poderes polâ”œآ،ticos y econâ”œâ”‚micos mâ”œأ­s influyentes de la regiâ”œâ”‚n aragonesa. Entre el trâ”œأ­fico ya no figuran unidades del tranvâ”œآ،a de la ciudad, pues la â”œâ•‘ltima lâ”œآ،nea Parque- San Josâ”œآ® habâ”œآ،a sido clausurada pocos meses antes. Fuente visual: revista "Aragâ”œâ”‚n turâ”œآ،stico y monumental", SIPA.', 1976, 1976, 1976, 'Anos 70', 'CENTRO', 41.64660900, -0.88474400, '0101000020E610000094A12AA6D24FECBF4E266E15C4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34455945110.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34455945110.webp', 'https://www.flickr.com/photos/zaragozaantigua/34455945110/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22778, 'Iglesia de la Madre del Salvador 1970', 'Comienza la demoliciâ”œâ”‚n de la iglesia del Colegio del Salvador de los jesuitas (detrâ”œأ­s, a la izquierda). Habâ”œآ،a sido levantada en 1960. Abajo, el inicio del paseo de las Damas. La instantâ”œأ­nea, tomada desde el paseo del General Mola. Fuente: www.facebook.com/groups/fotosantiguasdezaragoza/permalink...', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.64646500, -0.88523600, '0101000020E610000049BDA772DA53ECBF1B81785DBFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36172340170.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36172340170.webp', 'https://www.flickr.com/photos/zaragozaantigua/36172340170/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22795, 'Plaza Paraâ”œآ،so 1978', 'La plaza de Basilio Paraâ”œآ،so desde la altura del Edificio Elâ”œآ،seos. En primer plano, figuras del Monumento al Ahorro, conjunto escultâ”œâ”‚rico encargado por la Caja de Ahorros de Zaragoza a Fâ”œآ®lix Burriel en 1945. Un cartel de esa entidad anuncia las obras de su nueva sede, a la derecha. Abajo, obras para colocar en la ajardinada rotonda central la estatua de Câ”œآ®sar Augusto, que regresa de su periplo por las murallas romanas junto al Torreâ”œâ”‚n de la Zuda.', 1978, 1978, 1978, 'Anos 70', 'CENTRO', 41.64717000, -0.88574000, '0101000020E61000000E4A9869FB57ECBFE6797077D6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/44124329622.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/44124329622.webp', 'https://www.flickr.com/photos/zaragozaantigua/44124329622/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23428, 'Santa Fe 1999', 'Iglesia del monasterio de Santa Marâ”œآ،a de Santa Fe, vista desde la entrada a su recinto amurallado, a orillas del râ”œآ،o Huerva y entre Cuarte y Cadrete. Este monasterio cisterciense se enclavâ”œâ”‚ aquâ”œآ، en 1341, y la iglesia barroca, que se encuentra en ruinas, fue construida en 1774. Pese a la distancia de 8 km entre ellos, el lugar de Santa Fe forma parte del distrito de Casablanca, que hasta mayo de 2003 aâ”œâ•‘n era oficialmente un barrio rural.', 1999, 1999, 1999, 'Anos 90', NULL, 41.57696100, -0.95160400, '0101000020E6100000E3C4573B8A73EEBFA208A9DBD9C94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50198851173.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50198851173.webp', 'https://www.flickr.com/photos/zaragozaantigua/50198851173/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23016, 'P.â”¬â•‘ de la Constituciâ”œâ”‚n 1994', 'Vista del paseo de la Constituciâ”œâ”‚n, en su arranque desde la plaza de Paraâ”œآ،so, en octubre de 1994. En el jardâ”œآ،n estâ”œأ­n plantadas unas tiendas de campaâ”œâ–’a correspondientes a la acampada reivindicativa de la Plataforma 0,7, dentro de un movimiento a nivel nacional. Se reclamaba el cumplimiento de un compromiso adquirido 20 aâ”œâ–’os antes en la ONU por el cual los paâ”œآ،ses ricos debâ”œآ،an dedicar el 0''7 del Producto Interior Bruto a programas de ayuda al desarrollo en los paâ”œآ،ses pobres. Esta acampada se prolongâ”œâ”‚ durante un mes, siendo hostigada por ultraderechistas. Fuente: www.zaragozarebelde.org', 1994, 1994, 1994, 'Anos 90', 'CENTRO', 41.64723400, -0.88519300, '0101000020E610000077BD34458053ECBFFC6D4F90D8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37778586271.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37778586271.webp', 'https://www.flickr.com/photos/zaragozaantigua/37778586271/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23126, 'Plaza de Paraâ”œآ،so 2009', 'Imagen capturada en altura, posiblemente desde el chaflanero edificio "Elâ”œآ،seos", de la rotonda automovilâ”œآ،stica en que habâ”œآ،a sido convertida la plaza de Paraâ”œآ،so. Cuando a finales de los aâ”œâ–’os 80 este espacio fue remodelado cosmâ”œآ®ticamente, tras una nueva reubicaciâ”œâ”‚n de la estatua de Câ”œآ®sar Augusto, la rotonda fue desposeâ”œآ،da de su densa vegetaciâ”œâ”‚n, y en su lugar se colocâ”œâ”‚ una preciosa fuente que no estorbaba la visual, y que los dâ”œآ،as de recio viento norte era mejor dejar apagada. En 2011, las obras de la lâ”œآ،nea 1 del moderno tranvâ”œآ،a incluyeron necesariamente una intervenciâ”œâ”‚n en esta zona, dejâ”œأ­ndola con su aspecto actual. Entonces, a las filas del gran eje opositor al tranvâ”œآ،a, se uniâ”œâ”‚ un grupo de presiâ”œâ”‚n especâ”œآ،fico que defendiâ”œâ”‚ esta fuente como valioso patrimonio artâ”œآ،stico, cultural, e histâ”œâ”‚rico de los aâ”œâ–’os 90 del siglo XX. Fuente visual: www.verpueblos.com/', 2009, 2009, 2009, 'Siglo XXI', 'CENTRO', 41.64731900, -0.88586200, '0101000020E6100000E59CD843FB58ECBF2B8A5759DBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31230842860.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31230842860.webp', 'https://www.flickr.com/photos/zaragozaantigua/31230842860/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23144, 'Lago de Paraâ”œآ،so 2006', 'Foto: Oliver Duch. Aspecto de la plaza de Basilio Paraâ”œآ،so inundada a causa del reventâ”œâ”‚n de una tuberâ”œآ،a de agua de 90 aâ”œâ–’os, el domingo 18 de junio de 2006. A la derecha, paseo de la Constituciâ”œâ”‚n, por donde el lâ”œآ،quido elemento siguiâ”œâ”‚ su curso natural sobre el Huerva, llegando hasta el paseo de la Mina. Fuente: Heraldo de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', 'CENTRO', 41.64713000, -0.88578500, '0101000020E61000000E32C9C85958ECBF5721E527D5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31946040346.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31946040346.webp', 'https://www.flickr.com/photos/zaragozaantigua/31946040346/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23196, 'Cinema Elâ”œآ،seos 2015', 'El "Cinema Elâ”œآ،seos" formaba parte del gran proyecto que Teodoro Râ”œآ،os Balaguer diseâ”œâ–’â”œâ”‚ en 1939 para el nuevo "Edificio Elâ”œآ،seos", estratâ”œآ®gico entre el arranque de la nueva avenida del General Mola, y el paseo de Calvo Sotelo, con su esquina achaflanada mirando hacia la plaza de Paraâ”œآ،so. Fue inaugurado como sala de proyecciâ”œâ”‚n comercial a finales de 1944, con capacidad para 500 espectadores, que visionaron "Me casâ”œآ® con una bruja", de Renâ”œآ® Clair. Allâ”œآ، tuvo lugar, al aâ”œâ–’o siguiente, la primera sesiâ”œâ”‚n del "Cineclub de Zaragoza", y en 1967 se convirtiâ”œâ”‚ en la primera "Sala de Arte y Ensayo" de la ciudad. Entre 1987 y 1991, ejerciâ”œâ”‚ de sede de la Filmoteca de Zaragoza, cuando â”œآ®sta andaba de romerâ”œآ،a por diversas ubicaciones de la ciudad. En 1993, fue rehabilitado y restaurado respetando el original estilo de sus orâ”œآ،genes, y su aforo quedâ”œâ”‚ en 396 localidades. Era una singular "rara avis" en el panorama de las salas de proyecciâ”œâ”‚n de la ciudad, cuando estallâ”œâ”‚ la plaga de los "complejos multisalas". En 2009 fue declarado "Bien Catalogado del Patrimonio Cultural Aragonâ”œآ®s". A comienzos del mes de agosto de 2014, cuando se acercaba su aniversario 70 como sala de cine, y tras la proyecciâ”œâ”‚n del filme "Marsella", de Belâ”œآ®n Macâ”œآ،as, se anunciâ”œâ”‚ su cierre temporal para "modernizar el sistema de proyecciâ”œâ”‚n", lo que significaba sustituir el tradicional de celuloide, por el sistema digital, y acondicionar en consecuencia la sala. Pasaron los meses, sin que ninguna actividad indicara que se estaba llevando a cabo la anunciada "digitalizaciâ”œâ”‚n". Transcurridos 14 meses, el Ayuntamiento seguâ”œآ،a sin haber recibido ninguna solicitud de licencia de obras para tal fin. La empresa propietaria del local no soltaba prenda, y mantenâ”œآ،a sus declaraciones realizadas en agosto de 2014, en el sentido de "realizar un estudio sobre la mejor manera de proceder a la transformaciâ”œâ”‚n, enmarcada dentro de la apuesta de Zaragoza Urbana por el desarrollo de la actividad cultural de la ciudad". Mientras, los demâ”œأ­s esperâ”œأ­bamos,', 2015, 2015, 2015, 'Siglo XXI', 'CENTRO', 41.64627800, -0.88563200, '0101000020E6100000765089EB1857ECBFE90FCD3CB9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24473996940.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24473996940.webp', 'https://www.flickr.com/photos/zaragozaantigua/24473996940/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23200, 'Plaza Paraâ”œآ،so 2010', 'Vista del tâ”œâ•‘nel-puente sobre el râ”œآ،o Huerva, a su paso subterrâ”œأ­neo por la plaza de Basilio Paraâ”œآ،so. Al fondo, las profundidades del paseo de la Constituciâ”œâ”‚n. Fuente: Ayuntamiento de Zaragoza.', 2010, 2010, 2010, 'Siglo XXI', 'CENTRO', 41.64707400, -0.88569900, '0101000020E61000006A32E36DA557ECBFC40B2252D3D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32410027174.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32410027174.webp', 'https://www.flickr.com/photos/zaragozaantigua/32410027174/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23668, 'Plaza de Aragâ”œâ”‚n 1920', 'Imagen centrada en la fachada del gran edificio de la Capitanâ”œآ،a General, construido sobre tres de los cuatro solares de la manzana suroccidental de la antigua glorieta de Pignatelli. A su derecha, el edificio construido sobre el cuarto solar, con diseâ”œâ–’o de Fernando de Yarza. Casualmente, transita en direcciâ”œâ”‚n al sur la elâ”œآ®ctrica y diâ”œأ­fana unidad 27 de la tranviaria lâ”œآ،nea "Torrero", una jardinera motora que poco despuâ”œآ®s serâ”œآ،a reformada, cerrâ”œأ­ndola, porque el clima zaragozano parece aconsejarlo, durante la mayor parte del aâ”œâ–’o. Fuente visual: www.ebay.es/', 1920, 1920, 1920, 'Anos 20', 'CENTRO', 41.64785400, -0.88552600, '0101000020E61000000C3F389F3A56ECBF994A3FE1ECD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31354016305.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31354016305.webp', 'https://www.flickr.com/photos/zaragozaantigua/31354016305/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24238, 'Pl. de Basilio Paraâ”œآ،so 1953', 'Imagen capturada en el entorno de la plaza de Basilio Paraâ”œآ،so durante el paso de la local comparsa de Gigantes y Cabezudos que parece estar bajando desde el paseo del General Mola. En primer tâ”œآ®rmino, el cabezudo Forano latiguea pardales. Al fondo encabezan el paso de los Gigantes, posiblemente, las figuras del Rey, la Reina, el Duque y la Duquesa de Villahermosa. La rotunda presencia de la gran fachada principal del colegio del Salvador de los PP. Jesuitas ofrece un marco incomparable para cerrar el campo visual. Desde el', 1953, 1953, 1953, 'Anos 50', 'CENTRO', 41.64718600, -0.88574000, '0101000020E61000000E4A9869FB57ECBFEB36A8FDD6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39772909184.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39772909184.webp', 'https://www.flickr.com/photos/zaragozaantigua/39772909184/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24258, 'Huerva cubierto 1927', 'Imagen del cubrimiento del râ”œآ،o Huerva en su urbano tramo primero (Curva de "La Veneciana"-Puente de Santa Engracia). A la derecha, el edificio del Hospital Clâ”œآ،nico junto a la Facultad de Medicina y Ciencias. Las obras, en este tramo, estâ”œأ­n prâ”œأ­cticamente finalizadas, y es perceptible el destacado desnivel entre un lado y otro del nuevo vial. Fuente visual: "Aragâ”œâ”‚n : revista grâ”œأ­fica de cultura aragonesa" (Aâ”œâ–’o III, Nâ”¬â•‘ 16, enero 1927).', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.64691500, -0.88584000, '0101000020E6100000F0A2AF20CD58ECBF5B25581CCED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15661755442.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15661755442.webp', 'https://www.flickr.com/photos/zaragozaantigua/15661755442/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24259, 'Râ”œآ،o Huerva 1900', 'Imagen desde el Puente de Santa Engracia del cauce del râ”œآ،o Huerva. A la derecha, la Facultad de Medicina y Ciencias. A la izquierda, el Velâ”œâ”‚dromo de los Campos Elâ”œآ،seos. Fuente visual: www.bildarchivaustria.at/', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.64691500, -0.88584000, '0101000020E6100000F0A2AF20CD58ECBF5B25581CCED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16041516225.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16041516225.webp', 'https://www.flickr.com/photos/zaragozaantigua/16041516225/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24883, 'Pl. de Basilio Paraâ”œآ،so 1940', 'AHPZ-Archivo Coyne, Manuel Coyne, 1940. Plaza de Basilio Paraâ”œآ،so, con la estatua de Câ”œآ®sar Augusto. Al fondo, la Facultad de Medicina y Ciencias.', 1940, 1940, 1940, 'Anos 40', 'CENTRO', 41.64766200, -0.88563300, '0101000020E61000008D4468041B57ECBF546EA296E6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14883103041.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14883103041.webp', 'https://www.flickr.com/photos/zaragozaantigua/14883103041/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25638, 'La Romareda c.1972', 'Imagen capturada desde la altura de la Residencia Sanitaria "Josâ”œآ® Antonio" y centrada en el original aspecto del estadio municipal de La Romareda un domingo de liga, con el entorno invadido por abundante parque automovilâ”œآ،stico. Pocos aâ”œâ–’os despuâ”œآ®s conocerâ”œآ،a su primera gran ampliaciâ”œâ”‚n. A la derecha, vista del Pabellâ”œâ”‚n Francâ”œآ®s de la inmediata Feria de Muestras. Al fondo, desarrollo urbanâ”œآ،stico del Polâ”œآ،gono de la Gran Vâ”œآ،a, tras el que todavâ”œآ،a verdean campos de herbâ”œأ­ceas. Entre los dos bloques en construcciâ”œâ”‚n, en el centro de la imagen, se ubicarâ”œآ،a algo mâ”œأ­s tarde el Pabellâ”œâ”‚n Municipal de Deportes.', 1972, 1972, 1972, 'Anos 70', 'UNIVERSIDAD', 41.63629300, -0.90167200, '0101000020E61000005401F73C7FDAECBF3DD68C0C72D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49502395181.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49502395181.webp', 'https://www.flickr.com/photos/zaragozaantigua/49502395181/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24894, 'Plaza de Paraâ”œآ،so 1966', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. 23/11/1966. Una autâ”œآ®ntica "performance" a la zaragozana, con elementos de arquitectura, escultura, publicidad, y urbanismo. La imagen estâ”œأ­ tomada en el arranque del Paseo de Marina Moreno (sigue hacia la izquierda). Al fondo, la esquina del colegio de los jesuitas, aâ”œâ•‘n ahâ”œآ،. Delante, un cartelâ”œâ”‚n publicitario del Ayuntamiento de Zaragoza, patrocinado (pagado) por la empresa "Pegaso", de fomento de la "Cortesâ”œآ،a" en el trâ”œأ­fico mediante una campaâ”œâ–’a de sensibilizaciâ”œâ”‚n. Esta campaâ”œâ–’a incluyâ”œâ”‚ un premio de Prensa y Radio para los periodistas mâ”œأ­s sensibilizadores. La ediciâ”œâ”‚n de ese aâ”œâ–’o fue ganada por Alberto Albericio Conchâ”œأ­n (Radio Juventud de Zaragoza). Y de guinda, la escultura "La siesta" de Enrique Galcerâ”œأ­, donada al Ayuntamiento tras haber recibido de la Diputaciâ”œâ”‚n de Zaragoza la medalla de plata de la Bienal de Pintura y Escultura de Zaragoza (1963). Estâ”œأ­ echadica, sin saberlo, claro, justo en un espacio muy constitucional, pero varias dâ”œآ®cadas despuâ”œآ®s.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.64719700, -0.88503200, '0101000020E61000002A3BFDA02E52ECBFDF88EE59D7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15203260646.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15203260646.webp', 'https://www.flickr.com/photos/zaragozaantigua/15203260646/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24914, 'Facultad de Medicina 1933', 'Facultad de Medicina y Ciencia. Hacia la derecha, e inmediata, la plaza de Aragâ”œâ”‚n. Detrâ”œأ­s, el paseo de Pamplona. Fuente visual: Foto Conrado Barlâ”œآ®s, donada por Daniel Barlâ”œآ®s y digitalizada por Josâ”œآ® Luis Cintora para www.rafaelcastillejo.com', 1933, 1933, 1933, 'Anos 30', 'CENTRO', 41.64758900, -0.88581600, '0101000020E6100000CFC0C8CB9A58ECBFEB1F4432E4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22875466699.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22875466699.webp', 'https://www.flickr.com/photos/zaragozaantigua/22875466699/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24964, 'Velâ”œâ”‚dromo Campos Elâ”œآ،seos 1896', '1896. Inaugurado en 1895, reconvertido parcialmente en garaje de motos y bicicletas en 1908 y derribado en 1920. Situado en la actual esquina del paseo de Sagasta con la plaza Paraâ”œآ،so, donde el cine Elâ”œآ،seos conserva el recuerdo de su nombre.', 1896, 1896, 1896, 'Siglo XIX', 'CENTRO', 41.64666500, -0.88573700, '0101000020E6100000CA6DFB1EF557ECBFE23B31EBC5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14918261752.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14918261752.webp', 'https://www.flickr.com/photos/zaragozaantigua/14918261752/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25015, 'Pâ”¬â•‘ del General Mola 1937', 'Vista aâ”œآ®rea del primer tramo del paseo del General Mola, redenominaciâ”œâ”‚n de la avenida de la Repâ”œâ•‘blica tras el fallecimiento de este general golpista. Incluye el 25% de la superficie del proyectado (lo ejecutado es otra historia) ensanche de Miraflores. Fuente visual: www.facebook.com/photo.php?fbid=10204363057770144&set...', 1937, 1937, 1937, 'Anos 30', 'CENTRO', 41.64622300, -0.88547900, '0101000020E6100000DF6E490ED855ECBF25766D6FB7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14847204898.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14847204898.webp', 'https://www.flickr.com/photos/zaragozaantigua/14847204898/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25029, 'P.â”¬â•‘ de Sagasta c.1912', 'Imagen capturada desde el interior de los jardines del colegio del Salvador de los PP. Jesuitas, en su estratâ”œآ®gica ubicaciâ”œâ”‚n entre el râ”œآ،o Huerva y el arranque del ensanche del paseo de Sagasta. Con ediciâ”œâ”‚n de â”œأ¼ngel Toldrâ”œأ­ Viazo, en Barcelona, esta fotografâ”œآ،a formâ”œâ”‚ parte de una serie de postales alusiva a este colegio, denominada precisamente "Jardines del Colegio". En primer plano, y desde cierta altura, los referidos jardines que ornamentaban el acceso desde el paseo de Sagasta, que queda tras el muro perimetral en ladrillo. Justo enfrente, la notable puerta monumental que permitâ”œآ،a el ingreso al Velâ”œâ”‚dromo de los Campos Elâ”œآ،seos. De izquierda a derecha, la fronda arbâ”œâ”‚rea seâ”œâ–’ala el cauce al aire del râ”œآ،o Huerva, salvado por el puente de Santa Engracia. Al fondo destaca el destacado complejo de la Facultad de Medicina y Ciencias, y las Clâ”œآ،nicas Universitarias. Fuente visual: www.delcampe.es/', 1912, 1912, 1912, 'Anos 10', 'CENTRO', 41.64667800, -0.88532000, '0101000020E6100000BFD4CF9B8A54ECBF77853E58C6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27405182960.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27405182960.webp', 'https://www.flickr.com/photos/zaragozaantigua/27405182960/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25033, 'P.â”¬â•‘ de Sagasta c.1902', 'Imagen capturada en altura, posiblemente desde el edificio de la Facultad de Medicina y Ciencias, de la gran mole en "U" del colegio del Salvador. Su fachada principal, solanera, recayente a los jardines de acceso desde el paseo de Sagasta. En primer plano, el puente de Santa Engracia, y el acceso peatonal a la puerta de Santa Engracia e ingreso a la plaza de Aragâ”œâ”‚n, a la izquierda. Al fondo, la arboleda fluvial del Huerva serpentea junto a la antigua huerta de Santa Engracia, con vista de algunas de las instalaciones harineras ubicadas en torno a su cauce, hasta el puente de San Josâ”œآ®. A la derecha, despejada vista de los campos de las Adulas, entre el paseo de las Damas, y el camino de las Torres. Fuente: Fototipia Lucas Escolâ”œأ­, en www.ebay.es/', 1902, 1902, 1902, 'Anos 1900', 'CENTRO', 41.64667800, -0.88532000, '0101000020E6100000BFD4CF9B8A54ECBF77853E58C6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31449357142.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31449357142.webp', 'https://www.flickr.com/photos/zaragozaantigua/31449357142/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25035, 'P.â”¬â•‘ del General Mola 1978', 'Paso de la comparsa de Gigantes y Cabezudos de Zaragoza por el paseo de Sagasta, en octubre de 1978. Al fondo, el Cinema Elâ”œآ،seos (1944-2014) proyecta el estreno en Espaâ”œâ–’a del documental "Morir en Madrid" (Frâ”œآ®dâ”œآ®ric Rossif, 1963), sobre la Guerra Civil. El Estado habâ”œآ،a dado todas las facilidades al filme, creyendo que se trataba de un panegâ”œآ،rico franquista. Al verse traicionados, encargaron dos pelâ”œآ،culas de râ”œآ®plica, a Eduardo Manzanos y Mariano Ozores. Fuente visual: Heraldo de Aragâ”œâ”‚n.', 1978, 1978, 1978, 'Anos 70', 'CENTRO', 41.64647300, -0.88565600, '0101000020E6100000983270404B57ECBF9E5F94A0BFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31943514371.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31943514371.webp', 'https://www.flickr.com/photos/zaragozaantigua/31943514371/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25037, 'P.â”¬â•‘ del General Mola 1977', 'Imagen con el solar del desaparecido colegio del Salvador en el arranque del paseo del General Mola, en este caso como provisional y alegre recinto ferial para un circo. Al fondo, el edificio "Elâ”œآ،seos" con su publicitaria peineta, chaflanero con el paseo de Calvo Sotelo. En el centro, el edificio de la antigua facultad de Medicina y Ciencias. A la derecha, edificios del paseo de Pamplona. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1977, 1977, 1977, 'Anos 70', 'CENTRO', 41.64660900, -0.88474400, '0101000020E610000094A12AA6D24FECBF4E266E15C4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32288614533.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32288614533.webp', 'https://www.flickr.com/photos/zaragozaantigua/32288614533/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26078, 'Vista desde Santa Engracia c.1902', 'Vista capturada desde la altura de las torres de la iglesia de Santa Engracia, con orientaciâ”œâ”‚n hacia el norte.', 1902, 1902, 1902, 'Anos 1900', 'CENTRO', 41.64910600, -0.88288600, '0101000020E6100000871403249A40ECBF96D1C8E715D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53816308332.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53816308332.webp', 'https://www.flickr.com/photos/zaragozaantigua/53816308332/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25042, 'Puente de Santa Engracia c.1895', 'Inâ”œآ®dita imagen que muestra desde la margen izquierda del râ”œآ،o Huerva, y de forma parcial, el puente de Santa Engracia construido en piedra sillar en 1855 y alineado con el paseo de la Lealtad. Al fondo y a la izquierda destaca la gran mole edilicia del colegio del Salvador que seâ”œâ–’ala el arranque del densamente arbolado paseo de Sagasta. Aâ”œâ–’os despuâ”œآ®s, durante las obras de cubrimiento del Huerva, este paso hacia el paseo de las Damas, y el de Sagasta, fue considerablemente ensanchado y reorientado mâ”œأ­s hacia la plaza de Aragâ”œâ”‚n, "comiâ”œآ®ndose" la inmediata construcciâ”œâ”‚n que aquâ”œآ، aparece tras el puente, y llegando hasta el perâ”œآ،metro de los jardines de entrada al colegio, de forma que el puente de Santa Engracia quedâ”œâ”‚ ya oculto a la vista para siempre. En la fotografâ”œآ،a, la circulaciâ”œâ”‚n por el puente parece ser bien escasa, de forma que el seâ”œâ–’or tancredo apoyado sobre la barandilla no puede sino fijarse en el pausado trâ”œأ­nsito de un ocasional velocâ”œآ،pedo, tras el que un niâ”œâ–’o vendedor de periâ”œâ”‚dicos aguarda paciente el paso de clientes.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.64686100, -0.88561100, '0101000020E6100000994A3FE1EC56ECBF68075C57CCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48030546323.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48030546323.webp', 'https://www.flickr.com/photos/zaragozaantigua/48030546323/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25043, 'Paseo de Sagasta c.1895', 'Infrecuente imagen capturada en la umbrâ”œآ،a del primer tramo del paseo de Sagasta como bulevar frondosamente arbolado, a la altura de la glorieta que, hacia la izquierda, marcaba el arranque del paseo de las Damas; a la derecha, albinos muros del ingreso al nuevo velâ”œâ”‚dromo de los Campos Elâ”œآ،seos, que sustituyâ”œâ”‚ al anterior y homâ”œâ”‚nimo Circo, tambiâ”œآ®n utilizado como ocasional plaza de toros. Sobre el terroso pavimento del bulevar, y a los laterales, tendido tranviario de la lâ”œآ،nea de Torrero, que en tiempos de vigencia de la tracciâ”œâ”‚n de sangre apenas suponâ”œآ،a las vâ”œآ،as sobre las que ascendâ”œآ،an los coches tirados por caballerâ”œآ،as hasta la playa de Torrero, para descender luego hasta la plaza de la Constituciâ”œâ”‚n.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.64614700, -0.88562200, '0101000020E610000093C7D3F20357ECBF4AB4E4F1B4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48051884826.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48051884826.webp', 'https://www.flickr.com/photos/zaragozaantigua/48051884826/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25045, 'P.â”¬â•‘ de Sagasta c.1901', 'Imagen capturada en el principio del terroso paseo de Sagasta y orientada hacia el puente de Santa Engracia sobre el râ”œآ،o Huerva. A la izquierda y fuera de plano, el velâ”œâ”‚dromo de los Campos Elâ”œآ،seos, y al otro lado del râ”œآ،o destaca el edificio de las facultades de Medicina y Ciencias. Al fondo, la Glorieta de Pignatelli. A la derecha y fuera de plano, jardines del ingreso al colegio del Salvador. En primer tâ”œآ®rmino, unas caballerâ”œآ،as tiran de un cargado carro hacia Torrero.', 1901, 1901, 1901, 'Anos 1900', 'CENTRO', 41.64639900, -0.88540700, '0101000020E61000007AC8940F4155ECBF6495D233BDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49885576583.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49885576583.webp', 'https://www.flickr.com/photos/zaragozaantigua/49885576583/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25048, 'P.â”¬â•‘ de Sagasta 1893', 'Imagen capturada pasado el puente de Santa Engracia, con una interesante perspectiva desde el punto de vista de los peatones, del ascendente y terroso camino de Torrero hacia el fondo. A la derecha, murete que delimitaba el Circo de los Campos Elâ”œآ،seos, ante el que desciende un vehâ”œآ،culo traccionado por caballerâ”œآ،a, como hacâ”œآ،an los tranvâ”œآ،as de la lâ”œآ،nea de Torrero que por allâ”œآ، circulaban. Al fondo, isleta triangular que hacâ”œآ،a las veces de despartidero entre el camino de Torrero y el paseo de las Damas, y tras cuya foresta se perfila levemente el colegio del Sagrado Corazâ”œâ”‚n.', 1893, 1893, 1893, 'Siglo XIX', 'CENTRO', 41.64666800, -0.88554700, '0101000020E6100000E94482A96656ECBF53AF5B04C6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50159816452.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50159816452.webp', 'https://www.flickr.com/photos/zaragozaantigua/50159816452/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25056, 'Estatua Câ”œآ®sar Augusto 1940', 'En junio de 1940 tuvo lugar en Zaragoza una "Semana Augâ”œâ•‘stea", con presencia de jerarquâ”œآ،as varias de los regâ”œآ،menes fascistas de Italia y Espaâ”œâ–’a. Hubo misa en la capilla del Pilar; visita a las ruinas de Velilla, Azaila, y Numancia; conferencias en el Paraninfo de la Facultad de Medicina. Clausurâ”œâ”‚ el Rector de la Universidad de Zaragoza, que terminâ”œâ”‚ con vivas a Italia y a Espaâ”œâ–’a, al Duce y a Franco. Dentro de los actos organizados, el 2 de junio fue inaugurada la estatua de Câ”œآ®sar Augusto regalada por el Duce (el fascista Benito Mussolini) a la ciudad de Zaragoza. A tal fin acudieron a Zaragoza el Ministro de Educaciâ”œâ”‚n Nacional, el aciago Josâ”œآ® Ibâ”œأ­â”œâ–’ez Martâ”œآ،n, y el Presidente de la Junta Polâ”œآ،tica, Ramâ”œâ”‚n Serrano Sâ”œâ•‘â”œâ–’ez (meses antes de ser designado como Ministro de Asuntos Exteriores). La estatua, en bronce, copia el original de Prima Porta. Su ubicaciâ”œâ”‚n provisional fue la Plaza de Basilio Paraâ”œآ،so, aunque estuvo allâ”œآ، hasta octubre de 1950, en que fue reinstalado en las Murallas Romanas, en la Plaza de Câ”œآ®sar Augusto. En la imagen, a la derecha, el alcalde de Zaragoza, Juan Josâ”œآ® Rivas Bosch, escuchando a Serrano Sâ”œâ•‘â”œâ–’er en la fervorosa y nacionalista inauguraciâ”œâ”‚n de la estatua, hablando de lo que unâ”œآ،a a italianos y a espaâ”œâ–’oles como herederos directos de Augusto. Romanistas de todo el mundo siguen tratando de descifrar lo que eso significa. Fuente visual: Instantâ”œأ­neas zaragozanas. Caja de Ahorros y Monte de Piedad de Zaragoza, Aragâ”œâ”‚n y Rioja, 1982.', 1940, 1940, 1940, 'Anos 40', 'CENTRO', 41.64750200, -0.88568100, '0101000020E6100000D10836AE7F57ECBF1C0C7558E1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14766290069.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14766290069.webp', 'https://www.flickr.com/photos/zaragozaantigua/14766290069/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25195, 'Puente de Santa Engracia 1840', 'Plano con plantas y alzado del proyecto para el puente de Santa Engracia sobre el râ”œآ،o Huerva. Josâ”œآ® de Yarza y Joaquâ”œآ،n Gironza, Zaragoza, 4 de enero de 1840. Este puente, proyectado para sustituir el puente de madera arrastrado por las aguas del Huerva en 1838, fue finalmente construido en 1855 en piedra sillar. Desapareciâ”œâ”‚ con el cubrimiento del râ”œآ،o en los aâ”œâ–’os veinte del siglo XX.', 1840, 1840, 1840, 'Siglo XIX', 'CENTRO', 41.64713800, -0.88567300, '0101000020E61000001B683EE76E57ECBFDAFF006BD5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23898032160.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23898032160.webp', 'https://www.flickr.com/photos/zaragozaantigua/23898032160/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25200, 'P.â”¬â•‘ de la Independencia 1955', 'AHPZ-Archivo Coyne, Manuel Coyne. Paseo de la Independencia y Plaza de Aragâ”œâ”‚n.', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.64807900, -0.88496800, '0101000020E61000007A354069A851ECBFB91CAF40F4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14694377839.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14694377839.webp', 'https://www.flickr.com/photos/zaragozaantigua/14694377839/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25205, 'Plaza de Pignatelli 1889', '1889. El Archivo Roger Viollet contiene una instantâ”œأ­nea del "Estudio Fotogrâ”œأ­fico J. Lâ”œآ®vy et Cie" titulada "Place de Pignatelli" (Plaza de Pignatelli), otro destacado ejemplo de lo inapropiado de decir que algo en Zaragoza es asâ”œآ،, o estâ”œأ­, "desde siempre". Para el caso que nos ocupa, desde el aâ”œâ–’o de 1859 estuvo en el centro de esa glorieta (y en el centro de la imagen), luego plaza, dâ”œأ­ndole su nombre, la broncâ”œآ،nea estatua del prâ”œâ”‚cer don Ramâ”œâ”‚n Pignatelli y Moncayo, obra de Antonio Palao. Allâ”œآ، estuvo hasta que en 1904 fue trasladada 1326 metros mâ”œأ­s al sur, en los terrenos de la aterrazada y antigua Torre de Pablo Buil, que devino en el primer parque de la ciudad, y adquiriâ”œâ”‚ ilustrada denominaciâ”œâ”‚n: Parque Pignatelli. El hueco dejado por la oronda estatua fue pronto rellenado con una sedente imagen del justicia ajusticiado, y a la plaza se la empezâ”œâ”‚ a denominar "de Aragâ”œâ”‚n". Mientras estuvo en esta tan câ”œآ®ntrica localizaciâ”œâ”‚n, la estatua de Don Ramâ”œâ”‚n permanecâ”œآ،a rodeada de una verja y unos frondosos jardines, y era habitual lugar de encuentro de paseantes y peatones del entonces Paseo de Santa Engracia (hoy, Independencia). De esta imagen apenas encontramos supervivencias que no sean, al fondo, a la derecha de la estatua, el ondulante chapitel de la torre de la Seo, y el remate de una de las torres de Santa Engracia (junto a la gran farola de la derecha). A la izquierda, se alza novâ”œآ،simo (de 1888) el edificio de viviendas de la Plaza Aragâ”œâ”‚n 12. A continuaciâ”œâ”‚n, el edificio de viviendas del Paseo Independencia 34-36, antes de ser reformado, que contenâ”œآ،a desde este mismo aâ”œâ–’o 1889, en sus bajos, el cafâ”œآ® "Ambos Mundos"... El paisanaje conforma un cuadro antropolâ”œâ”‚gico de la realidad social de la Zaragoza de finales del XIX, y el entorno urbano ilustra otra ciudad, tambiâ”œآ®n llamada Zaragoza, pero que no es la actual: los chalecitos vallados de la Plaza Aragâ”œâ”‚n, el Teatro Pignatelli, el Convento de Jerusalâ”œآ®n... Fuente: "Zaragoza en la mirada ajena. Instantâ”œأ­neas del archivo Roger-Violle', 1889, 1889, 1889, 'Siglo XIX', 'CENTRO', 41.64769500, -0.88560600, '0101000020E61000002786E464E256ECBF306475ABE7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14878858183.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14878858183.webp', 'https://www.flickr.com/photos/zaragozaantigua/14878858183/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25207, 'Panorâ”œأ­mica 1954', 'Unas impresionantes imâ”œأ­genes nos dan juego para mostrar una panorâ”œأ­mica insâ”œâ”‚lita. Fueron capturadas desde lo alto del estratâ”œآ®gico nâ”¬â•‘ 2-4 del Paseo de Mola (antes del 18 de julio de 1936, Avenida de la Repâ”œâ•‘blica), obra ideada por Teodoro Râ”œآ،os Balaguer apenas una dâ”œآ®cada antes (1945). Desde esta privilegiada altura, y gracias a la excepcional calidad de imagen, la visual alcanza, al fondo a la izquierda, hasta los escarpes de Juslibol y el Castellar. Al fondo, a la derecha, llegamos hasta la Sierra de Alcubierre. De izquierda a derecha podemos visualizar: las torrecillas del Hogar Pignatelli y alguno de sus talleres de trabajo; las traseras del Convento-Noviciado de la Congregaciâ”œâ”‚n de las Hermanas de la Caridad de Santa Ana, en la calle Madre Rafols; algunas instalaciones y la barroca câ”œâ•‘pula del Hospital Provincial de Nâ”¬آ¬ Sâ”¬آ¬ de Gracia; las huertas donde aâ”œâ–’os despuâ”œآ®s se levantarâ”œأ­ el nuevo Monasterio de la Encarnaciâ”œâ”‚n de las Madres Carmelitas; la Puerta del Carmen; el Paseo de Pamplona aâ”œâ•‘n con su andador central peatonal; el edificio chaflâ”œأ­n con la calle Doctor Cerrada, antes de la reforma que le dio su actual y acristalado remate; al fondo, se eleva la chimenea de la Azucarera Agrâ”œآ،cola "El Pilar", en la calle Santa Lucâ”œآ،a; la torre de la iglesia de San Pablo; la câ”œâ•‘pula de Santiago el Mayor, antes de su reforma de finales de dâ”œآ®cada. Descanso. La plaza de Aragâ”œâ”‚n y el Paseo de la Independencia, "provincianos" (en lenguaje desarrollista) con su paseo central y zonas verdes, antes de su "reforma" automovilâ”œآ،stica de comienzos de los 60; la plaza de Aragâ”œâ”‚n aâ”œâ•‘n poblada con sus hotelitos de finales del XIX-primeros aâ”œâ–’os del XX; una composiciâ”œâ”‚n motor-remolque de la serie 100 de la lâ”œآ،nea 5 "Venecia-Delicias" enfila hacia Mola; al fondo, en el Coso Alto, los torreones pareados de la antigua Casa de los Luna, luego Audiencia; el moderno edificio de seguros "La Adriâ”œأ­tica", la câ”œâ•‘pula de la iglesia de la Manterâ”œآ،a en la plaza de San Roque, y la vigorosa y vecina câ”œâ•‘pula del Banco de Aragâ”œâ”‚n;', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.64750200, -0.88568100, '0101000020E6100000D10836AE7F57ECBF1C0C7558E1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16100773069.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16100773069.webp', 'https://www.flickr.com/photos/zaragozaantigua/16100773069/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25218, 'Plaza de Aragâ”œâ”‚n 1892', 'Imagen parcial de la antigua glorieta de Pignatelli, capturada a ras de suelo en el despejado espacio que se extendâ”œآ،a desde la arboleda en torno al monumento a Pignatelli, y hasta la puerta de Santa Engracia, en primer plano. Al fondo, a la derecha, la novâ”œآ،sima Facultad de Medicina y Ciencias, prâ”œأ­cticamente acabada aunque no inaugurada. Al fondo, a la izquierda, el puente de Santa Engracia, y el cauce del Huerva al aire. Hemos volteado horizontalmente la original imagen para disfrutar mejor del juego de luces y sombras. Fuente visual: Estudio Coyne, AHPZ.', 1892, 1892, 1892, 'Siglo XIX', 'CENTRO', 41.64785400, -0.88552600, '0101000020E61000000C3F389F3A56ECBF994A3FE1ECD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31271815980.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31271815980.webp', 'https://www.flickr.com/photos/zaragozaantigua/31271815980/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25219, 'Plaza de Aragâ”œâ”‚n 1892', 'Canicular imagen parcial de la antigua glorieta de Pignatelli, capturada a ras de suelo poco antes de su ingreso por la puerta de Santa Engracia, en primer plano. Al fondo, a la izquierda, la arboleda en torno al monumento a Pignatelli, de la que emergen tâ”œآ،midamente los remates del Teatro Pignatelli, y posiblemente la torre oriental de Santa Engracia. A la derecha, el novâ”œآ،simo hotelito diseâ”œâ–’ado por el veterano arquitecto zaragozano Mariano Lâ”œâ”‚pez Altaoja en el solar del extremo sureste de la plaza correspondiente al nâ”œâ•‘mero 8, por encargo de Ramâ”œâ”‚n Gironza. Sobre el firme, el tendido tranviario de subida de la lâ”œآ،nea de Torrero, tirado por caballerâ”œآ،as, que coexistiâ”œâ”‚ con la puerta de Santa Engracia, hasta que fue derribada. Fuente visual: Estudio Coyne, AHPZ.', 1892, 1892, 1892, 'Siglo XIX', 'CENTRO', 41.64785400, -0.88552600, '0101000020E61000000C3F389F3A56ECBF994A3FE1ECD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31272872100.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31272872100.webp', 'https://www.flickr.com/photos/zaragozaantigua/31272872100/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25223, 'Glorieta de Pignatelli 1889', 'Imagen capturada sobre trâ”œآ،pode, y desde algo de altura, un soleado dâ”œآ،a de finales de invierno en la glorieta de Pignatelli, a espaldas de la Puerta de Santa Engracia, y tambiâ”œآ®n del Sol, como indican los paisanos y paisanas que desde la poblada glorieta miran hacia el objetivo fotogrâ”œأ­fico protegiâ”œآ®ndose los ojos de los rayos directos, en una abigarrada composiciâ”œâ”‚n de personajes. Hacia el fondo, y de derecha a izquierda, el destacado volumen del Teatro Pignatelli, el Monumento a Pignatelli antes de ser exiliado polâ”œآ،ticamente hacia el sur, la calle de la Independencia y algunas de las primeras viviendas unifamiliares construidas sobre los solares parcelados donde tuvo lugar la Exposiciâ”œâ”‚n Aragonesa de 1868, como la pionera del nâ”¬â•‘ 13 de la glorieta, esquinera con la calle de Josâ”œآ® Luis Albareda. Esta antropolâ”œâ”‚gica imagen se comercializâ”œâ”‚ en la Repâ”œâ•‘blica de Francia, y editada en formato mâ”œأ­s pequeâ”œâ–’o, en el Imperio alemâ”œأ­n.', 1889, 1889, 1889, 'Siglo XIX', 'CENTRO', 41.64795900, -0.88512800, '0101000020E6100000B1C398F4F752ECBF0E130D52F0D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48169492932.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48169492932.webp', 'https://www.flickr.com/photos/zaragozaantigua/48169492932/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25224, 'Pl. de Aragâ”œâ”‚n c.1950', 'Imagen capturada desde cierta altura en el reciente Edificio Elâ”œآ،seos, y centrada en la plaza de Aragâ”œâ”‚n y el paseo de la Independencia. Esta vista presenta varias singularidades, inâ”œآ®ditas hasta ahora en el el Gran Archivo Zaragoza Antigua, como la vista de la isleta de la plaza de Basilio Paraâ”œآ،so, ppoco despuâ”œآ®s reformada, que a la izquierda y en primer tâ”œآ®rmino muestra el pedestal vacâ”œآ،o sobre el que desde 1940 y hasta 1950 se alzâ”œâ”‚ la estatua que representaba a Cayo Octavio Augusto, regalada por el gobierno del Reino de Italia presidido por Benito Mussolini para conmemorar la fundaciâ”œâ”‚n de la Colonia Cesaraugusta por las legiones romanas III Macedâ”œâ”‚nica, VI Victrix y X Gemina hacia el aâ”œâ–’o 15 antes de nuestra Era. Esta estatua se convirtiâ”œâ”‚ en un bien semoviente desde entonces y durante bastantes dâ”œآ®cadas, siendo ubicada en varias localizaciones de la ciudad. En la plaza de Aragâ”œâ”‚n se destacan algunos de los hotelitos que en la dâ”œآ®cada de los aâ”œâ–’os cuarenta fueron reformados de forma intensa, como el del nâ”¬â•‘ 12, a la izquierda, reciâ”œآ®n recrecido en altura con proyecto de Miguel â”œأ¼ngel Navarro y Josâ”œآ® Luis Anguela. Por encima de â”œآ®l, ademâ”œأ­s, se aprecia al fondo el alzamiento del edificio de Seguros La Adriâ”œأ­tica, y el de la sede central del Banco de Aragâ”œâ”‚n, ambos novâ”œآ،simos inmuebles que flanquean la nueva plaza de San Roque, reformada radicalmente tras el derribo del Arco de San Roque.', 1950, 1950, 1950, 'Anos 50', 'CENTRO', 41.64759800, -0.88539700, '0101000020E6100000963FDF162C55ECBF3E7AC37DE4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48364964326.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48364964326.webp', 'https://www.flickr.com/photos/zaragozaantigua/48364964326/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25231, 'Plaza de Aragâ”œâ”‚n c.1955', 'Vista en altura de la plaza de Aragâ”œâ”‚n.', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.64788800, -0.88535700, '0101000020E6100000081C0934D854ECBF45BC75FEEDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54382740255.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54382740255.webp', 'https://www.flickr.com/photos/zaragozaantigua/54382740255/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25233, 'Puente de Santa Engracia 1861', 'Imagen capturada desde la ribera izquierda del râ”œآ،o Huerva, casi a nivel del cauce, y centrada en el nuevo puente de piedra sillar de Santa Engracia, construido en 1855 para dar acceso al camino y paseo de Torrero. A la izquierda y fuera de plano, sobre la trinchera del râ”œآ،o, el Campo de Lezcano donde en unos aâ”œâ–’os se construirâ”œآ،a la nueva Facultad de Medicina y Ciencias.A la derecha, la Torre de Montadas, donde aâ”œâ–’os mâ”œأ­s tarde se levantarâ”œآ،a en gran colegio del Salvador.', 1861, 1861, 1861, 'Siglo XIX', 'CENTRO', 41.64701100, -0.88575800, '0101000020E6100000A87345292158ECBF7D93A641D1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14710709750.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14710709750.webp', 'https://www.flickr.com/photos/zaragozaantigua/14710709750/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25234, 'Pl. de Basilio Paraâ”œآ،so 1954', '1954. Vista aâ”œآ®rea del entorno de la plaza de Basilio Paraâ”œآ،so. En el centro, el colegio de los Jesuitas. La efâ”œآ،mera iglesia anexa estâ”œأ­ siendo construida en el paseo de las Damas, mientras que en Marina Moreno se levanta la residencia de estudiantes, que aâ”œâ–’os mâ”œأ­s tarde se convertirâ”œآ،an en residencias civiles.', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.64677100, -0.88490100, '0101000020E61000008753E6E61B51ECBF28806264C9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14963318242.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14963318242.webp', 'https://www.flickr.com/photos/zaragozaantigua/14963318242/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25239, 'Plaza Paraâ”œآ،so 2011', 'Foto: Maite Santonja. La fuente inaugurada en 1991 en el centro de la plaza de Basilio Paraâ”œآ،so de Zaragoza fue desmantelada el 25 de julio de 2011 con motivo de las obras del nuevo tranvâ”œآ،a, momento que recoge la imagen. Ya habâ”œآ،a habido ahâ”œآ، una fuente luminosa circular entre 1961 y 1975. En la toma, al fondo el paseo de Pamplona. Fuente: Heraldo de Aragâ”œâ”‚n.', 2011, 2011, 2011, 'Siglo XXI', 'CENTRO', 41.64714800, -0.88547300, '0101000020E610000056B60F79CB55ECBFFED5E3BED5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19393697748.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19393697748.webp', 'https://www.flickr.com/photos/zaragozaantigua/19393697748/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25240, 'Pl. de Paraâ”œآ،so 1955', 'Vista en altura, desde una de las ventanas del "hotelito" mâ”œأ­s al sureste de la plaza de Aragâ”œâ”‚n, de la ajardinada plaza de Paraâ”œآ،so, y el principio del paseo de Calvo Sotelo. Una unidad de la lâ”œآ،nea 11, en direcciâ”œâ”‚n al "Parque". El guardia urbano encasetado, pendiente de un improbable desbarajuste automovilâ”œآ،stico.', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.64713800, -0.88567300, '0101000020E61000001B683EE76E57ECBFDAFF006BD5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21792464843.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21792464843.webp', 'https://www.flickr.com/photos/zaragozaantigua/21792464843/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25242, 'Pl. de Paraâ”œآ،so 1955', 'Aâ”œآ®rea visual (cortesâ”œآ،a de la Fuerza Aâ”œآ®rea de los Estados Unidos de Norteamâ”œآ®rica) del entorno de la plaza de Paraâ”œآ،so, como nodal enlace al oeste con la plaza de Aragâ”œâ”‚n, al norte con el paseo de Marina Moreno, al este con General Mola y paseo de las Damas, al sureste con Calvo Sotelo, y al suoeste con el paseo de Pamplona. En primer plano, el gran complejo jesuâ”œآ،tico (Colegio y Residencia Universitaria), aâ”œâ•‘n sin la nueva iglesia de quita y pon.', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.64732300, -0.88583900, '0101000020E6100000DAAED007CB58ECBF6C79E57ADBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22252138561.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22252138561.webp', 'https://www.flickr.com/photos/zaragozaantigua/22252138561/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25243, 'Plaza de Paraâ”œآ،so 1955', 'Despejada vista en altura, desde el inmediato edificio "Elâ”œآ،seos", de la plaza, y de un panorama luminoso y provinciano. En primerâ”œآ،simo plano, uno de los recientes trolebuses "Pegaso-Escoriaza" de Material Mâ”œâ”‚vil y Construcciones, realizando el retorno de la lâ”œآ،nea "Terminillo". En la rotonda ajardinada, el funcionario municipal de trâ”œأ­fico que controla la circulaciâ”œâ”‚n sigue al raso. Pronto le pondrâ”œأ­n una sombrilla, por el sol, y mâ”œأ­s tarde un pâ”œâ•‘lpito. Cosas del progreso. Fuente visual: www.delcampe.net/', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.64713800, -0.88567300, '0101000020E61000001B683EE76E57ECBFDAFF006BD5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22576031184.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22576031184.webp', 'https://www.flickr.com/photos/zaragozaantigua/22576031184/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
