INSERT INTO public.photos VALUES (25245, 'Pl. de Paraâ”œآ،so 1955', 'Imagen de la plaza de Paraâ”œآ،so, despejada tras la recolocaciâ”œâ”‚n del estâ”œأ­tico Cesar Augusto en las murallas de piedra de la ciudad. Tras la verde y florida rotonda, la Facultad de Medicina y Ciencias, y un trolebâ”œâ•‘s (posiblemente, un Pegaso-Escoriaza) de la lâ”œآ،nea del "Terminillo", de regreso de ese destino. A la izquierda, arranque del paseo de Calvo Sotelo. Fuente visual: Garcâ”œآ،a Garrabella, en www.todocoleccion.net/', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.64720400, -0.88575200, '0101000020E61000001FBB0B941458ECBF92EBA694D7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25669414836.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25669414836.webp', 'https://www.flickr.com/photos/zaragozaantigua/25669414836/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25246, 'Puerta de Santa Engracia 1899', '"Puerta de San Engration. Plaza d''Aragon", Renâ”œآ® Ancely, 1899. Tras la puerta de Santa Engracia, de la que destacan las casetas de cobro de consumos, a la izquierda, el novâ”œآ،simo e historicista edificio de la Capitanâ”œآ،a General de Aragâ”œâ”‚n, y el arranque de los vecinos hotelitos. A la derecha, ingreso a la plaza de Aragâ”œâ”‚n, donde todavâ”œآ،a estaba presidiâ”œآ®ndola el bulto redondo de Ramâ”œâ”‚n Pignatelli. Hacâ”œآ،a tiempo que por aquâ”œآ، transitaban las unidades del tranvâ”œآ،a hacia Torrero.', 1899, 1899, 1899, 'Siglo XIX', 'CENTRO', 41.64758900, -0.88581600, '0101000020E6100000CFC0C8CB9A58ECBFEB1F4432E4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27100992000.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27100992000.webp', 'https://www.flickr.com/photos/zaragozaantigua/27100992000/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25247, 'Puente de Santa Engracia 1899', '"Universitâ”œآ® Facultâ”œآ® de mâ”œآ®decine et des sciences", Renâ”œآ® Ancely, 1899. Un vehâ”œآ،culo a propulsiâ”œâ”‚n de sangre transita tranquilo por el puente de Santa Engracia sobre el cauce al aire del râ”œآ،o Huerva, posiblemente en direcciâ”œâ”‚n al paseo de Sagasta. De telâ”œâ”‚n de fondo, el reciente edificio de las Facultades de Medicina y Ciencias. Sobre el terroso firme, el tendido de la tranviaria lâ”œآ،nea de Torrero, que desde la plaza de la Constituciâ”œâ”‚n llegaba hasta poco antes de la "playa" junto al Canal Imperial. Justo a la izquierda, ya fuera de plano, el Velâ”œâ”‚dromo de los Campos Elâ”œآ،seos. Fuente visual: www.georgesancely.com/', 1899, 1899, 1899, 'Siglo XIX', 'CENTRO', 41.64711600, -0.88576200, '0101000020E61000000344C18C2958ECBFF25B74B2D4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27342974396.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27342974396.webp', 'https://www.flickr.com/photos/zaragozaantigua/27342974396/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25248, 'Facultad de Medicina 1893', 'Imagen desde cierta altura (posiblemente, desde el nâ”¬â•‘ 8 de la Glorieta de PIgnatelli) con panorama de la novâ”œآ،sima Facultad de Medicina y Ciencias, aâ”œâ•‘n en obras, y un primer plano de la tercera (y â”œâ•‘ltima) puerta de Santa Engracia como controlado acceso a la referida glorieta y la calle de la Independencia. Por esta puerta ya transitaba el tranvâ”œآ،a a sangre hacia la playa de Torrero. A la izquierda, arranque del puente de Santa Engracia sobre el Huerva, y al fondo el cauce al aire de este râ”œآ،o, con alguna de las fâ”œأ­bricas del Camino de los Cubos. Hacia la derecha, el paseo de la Lealtad. Esta imagen fue publicada en octubre de 1893. Fuente: "El Diario de Zaragoza"', 1893, 1893, 1893, 'Siglo XIX', 'CENTRO', 41.64758900, -0.88581600, '0101000020E6100000CFC0C8CB9A58ECBFEB1F4432E4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27597312566.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27597312566.webp', 'https://www.flickr.com/photos/zaragozaantigua/27597312566/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25249, 'Plaza Paraâ”œآ،so 2011', 'Foto: Josâ”œآ® Miguel Marco. Vista de la plaza de Basilio Paraâ”œآ،so el 27 del octubre de 2011 desde el edificio central de Ibercaja, durante las obras de remodelaciâ”œâ”‚n con motivo de la prolongaciâ”œâ”‚n de la lâ”œآ،nea 1 del tranvâ”œآ،a. Fuente: Heraldo de Aragâ”œâ”‚n.', 2011, 2011, 2011, 'Siglo XXI', 'CENTRO', 41.64718600, -0.88574000, '0101000020E61000000E4A9869FB57ECBFEB36A8FDD6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27861286129.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27861286129.webp', 'https://www.flickr.com/photos/zaragozaantigua/27861286129/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
