INSERT INTO public.photos VALUES (25250, 'Râ”œآ،o Huerva 1861', 'Aspecto del actual paseo de la Constituciâ”œâ”‚n, visto desde el puente de Santa Engracia sobre el râ”œآ،o Huerva. Al fondo a la derecha, iglesia de San Miguel. Fuente: Mariano Jâ”œâ•‘dez y Ortiz. â”œأ¼lbum de Andrâ”œآ®s Martâ”œآ،n e Ipâ”œأ­s. Colecciâ”œâ”‚n Mariano Martâ”œآ،n Casalderrey. Libro Primeros tiempos de la fotografâ”œآ،a en Zaragoza', 1861, 1861, 1861, 'Siglo XIX', 'CENTRO', 41.64728400, -0.88522600, '0101000020E61000006534F279C553ECBFAE9CBD33DAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27967123764.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27967123764.webp', 'https://www.flickr.com/photos/zaragozaantigua/27967123764/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25252, 'Plaza de Paraâ”œآ،so 1955', 'Vista en altura capturada desde el edificio Elâ”œآ،seos" de la inmediata plaza de Paraâ”œآ،so, la plaza de Aragâ”œâ”‚n y el antiguo paseo de la Independencia, y el arranque a la derecha de la avenida de Marina Moreno. Transitan trolebuses de la lâ”œآ،nea "Terminillo", y tranvâ”œآ،a de la lâ”œآ،nea de Venecia-Delicias. Fuente visual: www.delcampe.net/', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.64713000, -0.88578500, '0101000020E61000000E32C9C85958ECBF5721E527D5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31291812343.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31291812343.webp', 'https://www.flickr.com/photos/zaragozaantigua/31291812343/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
