INSERT INTO public.photos VALUES (25254, 'Patio de la Infanta 2007', 'Foto: Juan Carlos Arcos. Presentaciâ”œâ”‚n del libro "Conversaciones con Josâ”œآ® Joaquâ”œآ،n Sancho Dronda" en el Patio de la Infanta, inserto en el edificio central de Ibercaja. En primer plano, Manuel Pizarro, presidente de la Bolsa de Madrid en 1991, presidente de Ibercaja entre 1995 y 2004, presidente de Endesa entre 2002 y 2007, diputado en el Congreso por el Partido Popular entre 2008 y 2010 y adjunto a la presidencia de El Corte Inglâ”œآ®s en 2014. Le sigue Josâ”œآ® Joaquâ”œآ،n Sancho Dronda, secretario general del Banco de Aragâ”œâ”‚n de 1953 a 1965, director general de la Caja de Ahorros de Zaragoza entre 1965 y 1987, presidente de Elâ”œآ®ctricas Reunidas de Zaragoza, presidente de CASER, presidente de los patronatos del Colegio Mayor Miraflores de Zaragoza y del santuario de Torreciudad, ambos pertenecientes al Opus Dei, impulsor de Formigal y de la instalaciâ”œâ”‚n de General Motors en Figueruelas. Tras â”œآ®l, Amado Franco, presidente de Elâ”œآ®ctricas Reunidas de Zaragoza en 1997 y presidente de Ibercaja desde 2004. Mâ”œأ­s allâ”œأ­, Javier Andreu, el autor del libro y profesor de Historia Antigua en la Universidad de Navarra, perteneciente al Opus Dei. Fuente visual: Heraldo de Aragâ”œâ”‚n.', 2007, 2007, 2007, 'Siglo XXI', 'CENTRO', 41.64660900, -0.88474400, '0101000020E610000094A12AA6D24FECBF4E266E15C4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32213138652.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32213138652.webp', 'https://www.flickr.com/photos/zaragozaantigua/32213138652/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25258, 'Pl. de Paraâ”œآ،so 1954', 'Luminosa imagen capturada desde la altura del chaflanero Edificio Elâ”œآ،seos con bien despejada vista, en primer tâ”œآ®rmino, de la plaza de Paraâ”œآ،so y el arranque del paseo de Pamplona. Hacia el fondo, la plaza de Aragâ”œâ”‚n y el paseo de la Independencia densamente arbolados, mientras una unidad tranviaria de la serie 200, posiblemente en servicio en la lâ”œآ،nea 11 "Parque", se dirige hacia allâ”œآ،. La ovalada isleta central de la plaza de Paraâ”œآ،so se nos muestra con su austero y enjuto aspecto desde que se le despojâ”œâ”‚ de la imperial estatua de Câ”œآ®sar Augusto, y hasta que fue remozada para albergar una luminosa y luego problemâ”œأ­tica fuente. Al fondo, la vieja ciudad con sus jalones principales desde la torre de San Pablo, la câ”œâ•‘pula de Santiago y el Frontâ”œâ”‚n Aragonâ”œآ®s, a la izquierda, hasta la iglesia de Santa Engracia, a la derecha. Fuente visual: Ediciones Sicilia, en www.delcampe.net', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.64717000, -0.88574000, '0101000020E61000000E4A9869FB57ECBFE6797077D6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45448123532.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45448123532.webp', 'https://www.flickr.com/photos/zaragozaantigua/45448123532/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25259, 'Pl. de Basilio Paraâ”œآ،so 1954', 'Imagen capturada desde la altura del Edificio Eliseos, sobre el inmueble del nâ”¬â•‘ 3 del paseo de Calvo Sotelo, con una interesante vista panorâ”œأ­mica del entorno de la plaza de Paraâ”œآ،so, su engarce con la arbolada plaza de Aragâ”œâ”‚n y el paseo de la Independencia, y con el original y reciente tramo inicial del bulevar de la avenida de Marina Moreno, a la derecha extrema. A la izquierda, e inmediata, la Facultad de Medicina y Ciencia de la Universidad. Por la plaza transita una composiciâ”œâ”‚n tranviaria de la lâ”œآ،nea 5 "Venecia-Delicias" en descenso hacia la plaza de Espaâ”œâ–’a, y una unidad de la lâ”œآ،nea 11 "Parque" hacia el parque de Primo de Rivera. Al fondo, variado horizonte del que despuntan algunas torres y câ”œâ•‘pulas de la vieja ciudad, y hasta de las chimeneas de la Azucarera de Aragâ”œâ”‚n o del Arrabal, al otro lado del râ”œآ،o Ebro.', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.64717000, -0.88574000, '0101000020E61000000E4A9869FB57ECBFE6797077D6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46368626735.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46368626735.webp', 'https://www.flickr.com/photos/zaragozaantigua/46368626735/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25260, 'Puerta de Santa Engracia c.1895', 'Inâ”œآ®dita imagen capturada desde la altura del esquinero inmueble del nâ”¬â•‘ 8 de la glorieta de Pignatelli, luego plaza de Aragâ”œâ”‚n, con una vista parcial de la tercera y â”œâ•‘ltima versiâ”œâ”‚n contemporâ”œأ­nea de la Puerta de Santa Engracia, casi eclipsada en este caso por el majestuoso fondo edilicio de la novâ”œآ،sima Facultad de Medicina y Ciencias de la Universidad.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.64762200, -0.88556800, '0101000020E6100000C74ACCB39256ECBFC6151747E5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48049544058.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48049544058.webp', 'https://www.flickr.com/photos/zaragozaantigua/48049544058/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25261, 'Plaza de Basilio Paraâ”œآ،so c.1958', 'Imagen capturada posiblemente desde la altura de la fachada principal del colegio del Salvador recayente al paseo del General Mola, con una interesante vista orientada hacia la plaza de Basilio Paraâ”œآ،so y el paseo de Pamplona. A la izquierda destaca la mole del Edificio Elâ”œآ،seos, rematado por la luminosa peineta publicitaria corporativa. Tras la Facultad de Medicina y Ciencias y el ingreso a la calle del Doctor Cerrada, el reciente inmueble del nâ”¬â•‘ 1 del paseo de Pamplona. Hacia el fondo, el bulevar de este paseo alcanza hasta la rotonda de la Puerta del Carmen, tras la que se extiende el enorme espacio de la huerta del convento de la Encarnaciâ”œâ”‚n y la huerta del Hospital Provincial, la Casa y Noviciado de las Hermanas de la Caridad de Santa Ana, y el Hospicio Provincial. De la plaza del Portillo emerge, a la derecha, la câ”œâ•‘pula que remata la sucursal de la agencia nâ”¬â•‘ 1 de una importante entidad de ahorro local. En primer tâ”œآ®rmino y encaminada hacia la terminal de la plaza del Emperador Carlos V, una unidad de la serie 200 en servicio en la tranviaria lâ”œآ،nea 11. Parque.', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.64639900, -0.88540700, '0101000020E61000007AC8940F4155ECBF6495D233BDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49575046281.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49575046281.webp', 'https://www.flickr.com/photos/zaragozaantigua/49575046281/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25345, 'Plaza de Aragâ”œâ”‚n 1983', 'Imagen capturada desde cierta altura, con un buen panorama de la plaza de Paraâ”œآ،so, la de Aragâ”œâ”‚n, y el paseo de la Independencia. La estatua de Câ”œآ®sar Augusto ha sido regresada, aproximadamente, a sus imperiales orâ”œآ،genes, ahora en una exuberante rotonda automovilâ”œآ،stica. La plaza de Aragâ”œâ”‚n progresa adecuadamente en el sobresaliente recrecimiento de sus edificios. Al fondo, la autopista de la Independencia, y la antigua fachada provinciana del Coso a la plaza de Espaâ”œâ–’a, que todavâ”œآ،a permite ver el emergente bloque del principio de la calle Sixto Celorrio, al otro lado del Ebro. Fuente visual: www.ebay.es/', 1983, 1983, 1983, 'Anos 80', 'CENTRO', 41.64754400, -0.88577600, '0101000020E6100000419DF2E84658ECBF4B5CC7B8E2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31278229801.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31278229801.webp', 'https://www.flickr.com/photos/zaragozaantigua/31278229801/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25408, 'P.â”¬â•‘ de Sagasta c.1925', 'Una vista del comienzo del paseo de Sagasta desde la altura del hotelito del nâ”œâ•‘mero 8 de la plaza de Aragâ”œâ”‚n. En primer tâ”œآ®rmino, pretil del ensanchado Puente de Santa Engracia bajo el que fluye el râ”œآ،o Huerva. A la izquierda, acceso a los jardines del Colegio del Salvador, y al fondo la plazoleta del Obelisco en homenaje al Reducto del Pilar y el colegio del Sagrado Corazâ”œâ”‚n. A la derecha, puerta del Velâ”œâ”‚dromo de los Campos Elâ”œآ،seos y las fincas del primer tramo del paseo hasta la calle de Lagasca. Un tranvâ”œآ،a de la lâ”œآ،nea de Torrero regresa hacia la plaza de la Constituciâ”œâ”‚n. Imagen convertida en tarjeta postal dentro de una serie editada por al papelerâ”œآ،a La Reina de las Tintas.', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.64674900, -0.88516300, '0101000020E6100000CD22145B4153ECBF40DCD5ABC8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14922155496.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14922155496.webp', 'https://www.flickr.com/photos/zaragozaantigua/14922155496/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25415, 'Râ”œآ،o Huerva 1927', 'Vista de 1927 del entonces vial sin nombre, o Sector 2 del cubrimiento del Huerva (Puente de Santa Engracia-Paseo de la Mina), despuâ”œآ®s Marina Moreno. A la izquierda, el edificio del colegio de los PP. Jesuitas. A la derecha, las traseras de los hotelitos de la plaza de Aragâ”œâ”‚n. Fuente visual: www.facebook.com/photo.php?fbid=588844694554232&set=o...', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.64729400, -0.88478400, '0101000020E610000022C500892650ECBFD272A087DAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15294108160.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15294108160.webp', 'https://www.flickr.com/photos/zaragozaantigua/15294108160/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25497, 'Puerta y paseo de Santa Engracia 1902', 'Fototipia Escolâ”œأ­. 1902. Al fondo a la derecha, la iglesia de Santa Engracia en todo su volumen.', 1902, 1902, 1902, 'Anos 1900', 'CENTRO', 41.64752100, -0.88560400, '0101000020E6100000F99D2633DE56ECBF923CD7F7E1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14895327105.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14895327105.webp', 'https://www.flickr.com/photos/zaragozaantigua/14895327105/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25504, 'Puerta de Santa Engracia c.1900', 'Hauser y Menet. Puerta de Santa Engracia. Ca.1900. Imagen de la Tercera, o "Nueva", Puerta de Santa Engracia. Construida en este nuevo emplazamiento, inmediato a la glorieta de Pignatelli, en 1866, con proyecto de Mariano Lâ”œâ”‚pez. Tenâ”œآ،a cinco accesos, peatonales y para tranvâ”œآ،as. Muy contestada desde el principio, terminâ”œâ”‚ siendo piqueteada en 1904. Inmediatamente, la plaza recibiâ”œâ”‚ la denominaciâ”œâ”‚n de "Aragâ”œâ”‚n", y se sustituyâ”œâ”‚ la estatua de Pignatelli por la del Justicia. En la imagen, la Puerta de Santa Engracia capturada desde la Glorieta de Pignatelli. De fondo de escenario, la Facultad de Medicina de la Universidad.', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.64750200, -0.88568100, '0101000020E6100000D10836AE7F57ECBF1C0C7558E1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15729708458.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15729708458.webp', 'https://www.flickr.com/photos/zaragozaantigua/15729708458/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25515, 'Puerta de Santa Engracia c.1900', 'Vista de la Puerta de Santa Engracia (1866-1904), con el edificio de Capitanâ”œآ،a de la Glorieta de Pignatelli al fondo. Fuente: AMZ.', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.64785400, -0.88552600, '0101000020E61000000C3F389F3A56ECBF994A3FE1ECD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25542484636.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25542484636.webp', 'https://www.flickr.com/photos/zaragozaantigua/25542484636/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25525, 'Puerta de santa Engracia c.1899', 'Invernal y parcial imagen de la puerta de Santa Engracia capturada desde su exterior con el fondo de la plaza de Aragâ”œâ”‚n, donde a la izquierda destaca la reciente e historicista fachada del edificio de la Capitanâ”œآ،a General y la continuaciâ”œâ”‚n hacia el norte con los hotelitos del lado occidental de la plaza. Unos vecinos aprovechan la solanera para hacer el tancredo junto a una de las casetas de consumos ubicada junto a la puerta. En primer tâ”œآ®rmino, vial por el que circulaban los tranvâ”œآ،as a tracciâ”œâ”‚n de sangre de la lâ”œآ،nea de Torrero de regreso a la plaza de la Constituciâ”œâ”‚n. Hemos volteado horizontalmente la imagen original para que tenga sentido.', 1899, 1899, 1899, 'Siglo XIX', 'CENTRO', 41.64755000, -0.88548300, '0101000020E61000003A3FC571E055ECBF2D431CEBE2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52033563459.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52033563459.webp', 'https://www.flickr.com/photos/zaragozaantigua/52033563459/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25919, 'Pl. de Basilio Paraâ”œآ،so 1954', 'Imagen capturada desde cierta altura en el colegio del Salvador, con interesante vista del entorno de la plaza de Basilio Paraâ”œآ،so en un momento de notable confluencia tranviaria y trolebusera que no parece colapsar mucho la circulaciâ”œâ”‚n rodada: una unidad de la serie 50, con remolque, de la lâ”œآ،nea 5 se encamina hacia Venecia; una unidad de la serie 100, con remolque, de la misma lâ”œآ،nea desciende hacia Delicias; un trolebâ”œâ•‘s BUT de 1 piso regresa del Terminillo. Pese a todo, el guardia urbano de la ajardinada rotonda permanece atento al trâ”œأ­nsito Fuente visual: postal de Garcâ”œآ،a Garrabella, en www.todocoleccion.net/', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.64714800, -0.88547300, '0101000020E610000056B60F79CB55ECBFFED5E3BED5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31683233400.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31683233400.webp', 'https://www.flickr.com/photos/zaragozaantigua/31683233400/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25926, 'Pl. de Paraâ”œآ،so 1954', 'Imagen capturada desde cierta altura en el colegio del Salvador, con vista del entorno de la plaza de Paraâ”œآ،so con su preciosa y florida rotonda central, como lugar de entronque del paseo de Pamplona, paseo de Calvo Sotelo, paseo del General Mola, y paseo de Marina Moreno. Transitan dos unidades de la serie 200, o "rizados", en servicio en la tranviaria lâ”œآ،nea 11 "Parque", una en direcciâ”œâ”‚n hacia la plaza Emperador Carlos, y la otra, en primer plano, hacia la terminal de la plaza de Espaâ”œâ–’a. Fuente visual: www.ebay.es/', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.64730700, -0.88579600, '0101000020E610000008AF5DDA7058ECBF66BCADF4DAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34089327660.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34089327660.webp', 'https://www.flickr.com/photos/zaragozaantigua/34089327660/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25966, 'Plaza de Paraâ”œآ،so 1974', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. 08/09/1974. Imagen en altura, desde el Edificio Elâ”œآ،seos, de la Plaza de Basilio Paraâ”œآ،so, la Plaza de Aragâ”œâ”‚n y el arranque del Paseo de Marina Moreno. Ya estamos en setiembre, pero el verano de este aâ”œâ–’o se prolonga unas semanas mâ”œأ­s. Se ha secado hasta la fuente de la Plaza. A la derecha mâ”œأ­s extrema, las tapias que delimitan el solar del volatilizado Colegio de los PP. Jesuâ”œآ،tas, en el â”œآ،nterin hasta que de ahâ”œآ، salga la nueva sede central de una conocida entidad de ahorro. Al otro lado de Marina Moreno, otras vallas ocultan el solar de un recientemente derribado hotelito de la Plaza de Aragâ”œâ”‚n, el que hacâ”œآ،a esquina con la Plaza Paraâ”œآ،so, a la espera de que de ahâ”œآ، florezcan hasta 10 alturas en bloque.', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.64668400, -0.88579900, '0101000020E61000004C8BFA247758ECBF596C938AC6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14761852699.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14761852699.webp', 'https://www.flickr.com/photos/zaragozaantigua/14761852699/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25971, 'Av. de Marina Moreno 1963', 'Vista desde cierta altura del arranque de la avenida de Marina Moreno desde la plaza de Basilio Paraâ”œآ،so. A la derecha, la mole del colegio de los PP. Jesuitas. A la izquierda, las traseras de los hotelitos de la plaza de Aragâ”œâ”‚n, Santa Engracia y la torre de la Caja de Previsiâ”œâ”‚n Social. Al fondo, la torre de la iglesia de San Miguel. Fuente visual: Archivo Fotogrâ”œأ­fico Coyne, AHPZ.', 1963, 1963, 1963, 'Anos 60', 'CENTRO', 41.64668400, -0.88579900, '0101000020E61000004C8BFA247758ECBF596C938AC6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15005610111.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15005610111.webp', 'https://www.flickr.com/photos/zaragozaantigua/15005610111/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26066, 'Plaza de Basilio Paraâ”œآ،so 1991', 'Imagen capturada desde la notable altura del acristalado y airoso remate del inmueble del nâ”¬â•‘ 1 del paseo de Pamplona, con una vista del entorno de la plaza de Basilio Paraâ”œآ،so, en cuyo centro destaca la glorieta central despojada de la mayor parte de su denso jardâ”œآ،n de â”œأ­rboles y arbustos, en el proceso de sustituirlo por una fuente cibernâ”œآ®tica. A la izquierda, enlace con la plaza de Aragâ”œâ”‚n, donde destaca por su antigua escala la antigua casa de Marcelino Celestino, el â”œâ•‘ltimo de los "hotelitos" que aâ”œâ–’os despuâ”œآ®s serâ”œآ،a derribado y sustituido por una mole homologada con sus vecinas. De fondo, la gran sede central de una reconocida entidad de ahorro, lindando con el arranque tanto del paseo de las Damas, hacia el fondo, como con la glorieta de Sasera y su referencial gran superficie comercial en altura. A la derecha, el Edificio Elâ”œآ،seos chaflanea el arranque del paseo de Sagasta y de la Gran Vâ”œآ،a. En primer tâ”œآ®rmino, escaleras de ingreso al Edificio Paraninfo y el trâ”œأ­fico rodado canalizado por el paseo de Pamplona. En esta imagen queda claro el oxâ”œآ،moron de considerar que la de Basilio Paraâ”œآ،so es una plaza. Nunca lo ha sido.', 1991, 1991, 1991, 'Anos 90', 'CENTRO', 41.64731800, -0.88572900, '0101000020E610000014CD0358E457ECBF5A0EF450DBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50442708971.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50442708971.webp', 'https://www.flickr.com/photos/zaragozaantigua/50442708971/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26067, 'Plaza de Basilio Paraâ”œآ،so 1992', 'Imagen capturada desde la altura del inmueble del nâ”¬â•‘ 1 del paseo de Pamplona, con una vista del entorno de la plaza de Basilio Paraâ”œآ،so centrada en el aspecto de la glorieta central tras la instalaciâ”œâ”‚n de una fuente cibernâ”œآ®tica que, por una parte facilitaba la visibilidad del intenso trâ”œأ­fico rodado que la circunvalaba diariamente, y por otra "la ionizaciâ”œâ”‚n producida en el aire por el agua es mucho mâ”œأ­s beneficiosa para la salud pâ”œâ•‘blica que la que pueda obtenerse de una masa vegetal", como se argumentâ”œâ”‚ de forma cientâ”œآ،fica para justificar la eliminaciâ”œâ”‚n de la preexistente zona de arbustos y â”œأ­rboles. Desde ese momento, esta plaza fue uno de los lugares mâ”œأ­s sanos de la ciudad. Tras la rotonda automovilâ”œآ،stica y en el arranque del paseo de la Constituciâ”œâ”‚n, el metâ”œأ­lico Monumento a la Constituciâ”œâ”‚n de 1978 proyectado por Florencio de Pedro Herrera inaugurado en diciembre de 1989 y que, de puro simbolismo, resulta tal vez demasiado difâ”œآ،cil de comprender, algo que deberâ”œآ،a estar en la antâ”œآ،poda de un texto constitucional.', 1992, 1992, 1992, 'Anos 90', 'CENTRO', 41.64733400, -0.88566500, '0101000020E610000065C746205E57ECBF60CB2BD7DBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50444382226.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50444382226.webp', 'https://www.flickr.com/photos/zaragozaantigua/50444382226/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21155, 'La Veneciana 1897', 'Dibujo, publicado en Heraldo de Aragâ”œâ”‚n, del proyecto de fachada principal de la fâ”œأ­brica de espejos La Veneciana, de Basilio Paraâ”œآ،so, sita en el camino de los Cubos, junto a la fundiciâ”œâ”‚n de Pellicer y Juan. Las traseras daban al Huerva, conformando la denominada "curva de La Veneciana" de ese râ”œآ،o. Este edificio de Fâ”œآ®lix Navarro estuvo en pie hasta 1937. Fuente: Mâ”¬آ¬ Pilar Biel Ibâ”œأ­â”œâ–’ez, Zaragoza y la industrializaciâ”œâ”‚n: la arquitectura industrial 1875-1936, IFC, 2004.', 1897, 1897, 1897, 'Siglo XIX', 'CENTRO', 41.64762800, -0.88839200, '0101000020E6100000A3E5400FB56DECBFA8FC6B79E5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19182456024.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19182456024.webp', 'https://www.flickr.com/photos/zaragozaantigua/19182456024/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21181, 'Camino de los Cubos 1893', 'Imagen del novâ”œآ،simo edificio de la Facultad de Medicina y Ciencias capturado desde el camino de Herederos o de los Cubos, por el que fluye al aire la acequia de la Romareda Baja, junto a la puerta de acceso al Hospital Clâ”œآ،nico (en el centro de la imagen) y al original Departamento Anatâ”œâ”‚mico (a la derecha, fuera de plano). Al fondo, a la izquierda, y tras el paseo de la Lealtad, el tambiâ”œآ®n reciente edificio de la Capitanâ”œآ،a General de la plaza de Aragâ”œâ”‚n. Fuente visual: fotografâ”œآ،a de Lucas Escolâ”œأ­ Arimany recogida en Hilariâ”œâ”‚n y Enrique Villuendas (secciâ”œâ”‚n Fotomicrogrâ”œأ­fica de la Facultad de Medicina), "â”œأ¼lbum fotogrâ”œأ­fico realizado con motivo de la inauguraciâ”œâ”‚n del edificio de la Facultad de Medicina y Ciencias". Colegio Oficial de Arquitectos de Aragâ”œâ”‚n. Reproducida en la exposiciâ”œâ”‚n "Historia, conocimiento y patrimonio, 475 aniversario del privilegio fundacional de la Universidad de Zaragoza, Vicerrectorado de Cultura y Proyecciâ”œâ”‚n Social-Universidad de Zaragoza.', 1893, 1893, 1893, 'Siglo XIX', 'CENTRO', 41.64759200, -0.88826000, '0101000020E6100000EA094B3CA06CECBF5C936E4BE4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33966331253.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33966331253.webp', 'https://www.flickr.com/photos/zaragozaantigua/33966331253/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21182, 'Camino de los Cubos 1893', 'Imagen del novâ”œآ،simo palacio de las Facultades de Medicina y Ciencias, centrada en el tercero de los edificios de que constaba, el departamento de Disecciâ”œâ”‚n o Anfiteatro anatâ”œâ”‚mico. La captura se ha realizado desde la altura del inmediato Hospital clâ”œآ،nico. Al fondo, las arboladas mâ”œأ­rgenes del râ”œآ،o Huerva, con vista parcial de la fâ”œأ­brica de sombreros de Desiderio Casanava, en el camino de los Cubos. Inmediata a la derecha, en el mismo camino, carpinterâ”œآ،a y fâ”œأ­brica de hielo. Tras ella, aâ”œâ–’os despuâ”œآ®s se instalarâ”œآ،a la Fundiciâ”œâ”‚n de Pellicer y Juan, y la fâ”œأ­brica de cristales de la Veneciana. Fuente visual: fotografâ”œآ،a de Lucas Escolâ”œأ­ Arimany recogida en Hilariâ”œâ”‚n y Enrique Villuendas (secciâ”œâ”‚n Fotomicrogrâ”œأ­fica de la Facultad de Medicina), "â”œأ¼lbum fotogrâ”œأ­fico realizado con motivo de la inauguraciâ”œâ”‚n del edificio de la Facultad de Medicina y Ciencias". Colegio Oficial de Arquitectos de Aragâ”œâ”‚n. Reproducida en la exposiciâ”œâ”‚n "Historia, conocimiento y patrimonio, 475 aniversario del privilegio fundacional de la Universidad de Zaragoza, Vicerrectorado de Cultura y Proyecciâ”œâ”‚n Social-Universidad de Zaragoza.', 1893, 1893, 1893, 'Siglo XIX', 'CENTRO', 41.64690300, -0.88813100, '0101000020E6100000740AF2B3916BECBF9757AEB7CDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34007036663.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34007036663.webp', 'https://www.flickr.com/photos/zaragozaantigua/34007036663/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21366, 'Velâ”œâ”‚dromo Campos Elâ”œآ،seos 1915', 'Interior del velâ”œâ”‚dromo de los Campos Elâ”œآ،seos, en la confluencia del paseo de Sagasta y el cauce al aire del râ”œآ،o Huerva. Al fondo, edificio del arranque de los nâ”œâ•‘meros pares del paseo de Sagasta. Fuente visual: El fotâ”œâ”‚grafo Luis Gandâ”œâ•‘ Mercadal. Una crâ”œâ”‚nica visual 1910-1830.', 1915, 1915, 1915, 'Anos 10', 'CENTRO', 41.64638100, -0.88605700, '0101000020E6100000378AAC35945AECBFBDE0D39CBCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14979092707.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14979092707.webp', 'https://www.flickr.com/photos/zaragozaantigua/14979092707/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21393, 'Velâ”œâ”‚dromo Campos Elâ”œآ،seos 1915', '"Los deportes en Zaragoza. Calderâ”œâ”‚n, salto de altura". Aspecto del Velâ”œâ”‚dromo de los Campos Elâ”œآ،seos de Zaragoza, con el râ”œآ،o Huerva a la izquierda y la actual plaza de Paraâ”œآ،so al fondo. La entrada se realizaba por el chaflâ”œأ­n entre la Gran Vâ”œآ»a y el paseo Sagasta actuales. Fue inaugurado en 1895 y derribado en 1920. Fuente: Fotografâ”œآ،a de Aurelio Grasa publicada en Heraldo de Aragâ”œâ”‚n el 7 de julio de 1915, junto a una composiciâ”œâ”‚n de otras tres fotografâ”œآ،as. Fue publicada en la pâ”œأ­gina 61 del catâ”œأ­logo "Aurelio Grasa reportero grâ”œأ­fico 1910-1917", RSFZ, Galerâ”œآ،a Costa, 3. Zaragoza 2003. www.aureliograsa.es Tomada de www.facebook.com/photo.php?fbid=896176007071692&set=g...', 1915, 1915, 1915, 'Anos 10', 'CENTRO', 41.64638100, -0.88605700, '0101000020E6100000378AAC35945AECBFBDE0D39CBCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21224325020.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21224325020.webp', 'https://www.flickr.com/photos/zaragozaantigua/21224325020/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21493, 'Paseo de Pamplona aâ”œâ–’os 20', 'AHPZ. Gabriel Faci. Aâ”œâ–’os 20. "Calles nevadas." Interesante perspectiva, tras una nevada, del Paseo de Pamplona, en su confluencia con la Plaza de Paraâ”œآ،so. El Paseo presenta su andador central, con bancos y â”œأ­rboles, y el Monumento a la Expo 1908, allâ”œآ، instalado desde 1910. Los edificios de vivienda de la izquierda seâ”œâ–’alan dâ”œâ”‚nde desemboca el camino de Herederos (aâ”œâ–’os mâ”œأ­s tarde Doctor Cerrada), por el que fluâ”œآ،a la acequia de la Romareda. A la derecha, el edificio de Capitanâ”œآ،a, y las calles de Valencia (luego, de Ponzano) y de Teruel (luego, de Bilbao), con vista, en primer lugar, de la fâ”œأ­brica de conservas alimenticias "Bescâ”œâ”‚s Hermanos", y detrâ”œأ­s, el colegio de las Esclavas del Sagrado Corazâ”œâ”‚n de Jesâ”œâ•‘s.', 1920, 1920, 1929, 'Anos 20', 'CENTRO', 41.64783100, -0.88631900, '0101000020E61000007D59DAA9B95CECBFE02A4F20ECD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15252466290.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15252466290.webp', 'https://www.flickr.com/photos/zaragozaantigua/15252466290/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21614, 'Cubrimiento Huerva 1925', 'Imagen del cubrimiento del râ”œآ،o Huerva en su urbano tramo entre la curva de "La Veneciana", cuyas instalaciones destacan al fondo, y el puente de Santa Engracia, desde donde se ha realizado esta captura. A la izquierda, el circuito del antiguo velâ”œâ”‚dromo, y el arranque del camino del Sâ”œأ­bado. A la derecha, el Hospital Clâ”œآ،nico y la Facultad de Medicina y Ciencias. Al fondo, la fâ”œأ­brica de sombreros de Gregorio Hernâ”œأ­ndez, junto a la zanja del ferrocarril de la lâ”œآ،nea MZA. Destaca la notable diferencia de cota entre una y otra orilla del râ”œآ،o, que el cubrimiento nivelarâ”œأ­ adecuadamente. Fuente visual: â”œأ¼ngel Aâ”œآ،sa y Hermanos.', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.64664600, -0.88682200, '0101000020E61000002CF2EB87D860ECBF6B0BCF4BC5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31656822710.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31656822710.webp', 'https://www.flickr.com/photos/zaragozaantigua/31656822710/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21616, 'Cubrimiento Huerva 1926', 'Imagen realizada durante las obras de cubrimiento del râ”œآ،o Huerva en su primer tramo urbano, entre la "curva de la Veneciana" y el puente de Santa Engracia. La captura se ha realizado junto a la facultad de Medicina y Ciencias, con los edificios de las clâ”œآ،nicas universitarias al fondo, muy cerca ya del puente. Este tramo fue denominado "Gran Vâ”œآ،a", pero tras el golpe del 18 de julio de 1936 serâ”œأ­ cambiado por los afines al nuevo Râ”œآ®gimen como "avenida de Calvo Sotelo", hasta la recuperaciâ”œâ”‚n de la democracia local en 1979. Fuente visual: â”œأ¼ngel Aâ”œآ،sa y Hermano.', 1926, 1926, 1926, 'Anos 20', 'CENTRO', 41.64680300, -0.88659900, '0101000020E61000005D52B5DD045FECBF33FAD170CAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31946689646.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31946689646.webp', 'https://www.flickr.com/photos/zaragozaantigua/31946689646/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21731, 'Pl. de Basilio Paraâ”œآ،so 1936', '12 de octubre de 1936. Celebraciâ”œâ”‚n del Dâ”œآ،a de la Raza y de la fiesta de la Virgen del Pilar. Las calles de la ciudad fueron escenario de interesantes manifestaciones varias, incluyendo el de la precipitaciâ”œâ”‚n en forma de lluvia. Catâ”œâ”‚licos y patriâ”œâ”‚ticos falangistas, carlistas y renovadores espaâ”œâ–’oles, portando banderas propias, alemanas, italianas y portuguesas, desfilaron y procesionaron acompaâ”œâ–’ados de mâ”œâ•‘sicas militares desde distintos puntos hasta el escenario central establecido câ”œâ”‚mo no en la plaza del Pilar. Esta imagen forma parte de una serie de tres, en la que se documenta grâ”œأ­ficamente esta concentraciâ”œâ”‚n y posterior desfile de miembros de la Falange, partiendo desde la puerta de la facultad de Medicina y Ciencias, que centra esta escena representativa de la Zaragoza de la â”œآ®poca.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.64748500, -0.88634200, '0101000020E61000008847E2E5E95CECBF46D3D9C9E0D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21321647900.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21321647900.webp', 'https://www.flickr.com/photos/zaragozaantigua/21321647900/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21736, 'Pl. de Basilio Paraâ”œآ،so 1936', '12 de octubre de 1936. Celebraciâ”œâ”‚n del Dâ”œآ،a de la Raza y de la fiesta de la Virgen del Pilar. Las calles de la ciudad fueron escenario de manifestaciones varias, incluyendo el de la precipitaciâ”œâ”‚n en forma de lluvia. Catâ”œâ”‚licos y patriâ”œâ”‚ticos falangistas, carlistas y renovadores espaâ”œâ–’oles, con banderas (propias, alemanas, italianas y portuguesas) y mâ”œâ•‘sicas, desfilaron y procesionaron desde distintos puntos hasta el escenario central de la plaza del Pilar. Imagen de una serie de tres, en la que se documenta la concentraciâ”œâ”‚n y posterior desfile de miembros de la Falange, partiendo de la puerta de la facultad de Medicina y Ciencias, desde donde estâ”œأ­ tomada la foto. A la izquierda, edificio de Capitanâ”œآ،a. Al fondo, iglesia de Santa Engracia. Fuente visual: Archivo Digital Nacional, Polonia. www.nac.gov.pl/', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.64748500, -0.88634200, '0101000020E61000008847E2E5E95CECBF46D3D9C9E0D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21483618296.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21483618296.webp', 'https://www.flickr.com/photos/zaragozaantigua/21483618296/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21737, 'Pl. de Basilio Paraâ”œآ،so 1936', 'Bajo pertinaz lluvia, celebraciâ”œâ”‚n del Dâ”œآ،a de la Raza y de la fiesta de la Virgen del Pilar. Militantes de Falange Espaâ”œâ–’ola, Renovaciâ”œâ”‚n Espaâ”œâ–’ola y carlistas con banderas propias, ademâ”œأ­s de la alemana, italiana y portuguesa y con marciales mâ”œâ•‘sicas, desfilaron desde distintos puntos hasta el escenario central de la plaza del Pilar. En la imagen, abanderadas de la Secciâ”œâ”‚n Femenina de Falange con el fondo de la facultad de Medicina y Ciencias. Fuente visual: Archivo Digital Nacional, Polonia. www.nac.gov.pl/', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.64748500, -0.88634200, '0101000020E61000008847E2E5E95CECBF46D3D9C9E0D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21498762552.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21498762552.webp', 'https://www.flickr.com/photos/zaragozaantigua/21498762552/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21963, 'Pl. de Basilio Paraâ”œآ،so 1949', 'Recreaciâ”œâ”‚n de la plaza de Basilio Paraâ”œآ،so de Zaragoza en 1949, con la Facultad de Medicina y Ciencias al fondo. Dibujo de Vâ”œآ،ctor M. Lahuerta con guion de Emilio Alfaro para esta primera viâ”œâ–’eta de la historieta "Doctor Garcâ”œآ،a", 1981. Fuente: "El â”œâ•‘ltimo nombre. Miguel Labordeta", IFC, 2015.', 1949, 1949, 1949, 'Anos 40', 'CENTRO', 41.64750900, -0.88605200, '0101000020E6100000C5C551B9895AECBFCE6E2D93E1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21163914405.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21163914405.webp', 'https://www.flickr.com/photos/zaragozaantigua/21163914405/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21992, 'Pl. de Basilio Paraâ”œآ،so 1944', 'Imagen capturada durante la lectura del doctor Julio Ariâ”œâ–’o Cenzano de su discurso de ingreso en la Real Academia de Medicina de Zaragoza, en la Facultad de Medicina y Ciencias sita en la plaza de Paraâ”œآ،so. Este doctor zaragozano se especializâ”œâ”‚ en otorrinolaringologâ”œآ،a, y creâ”œâ”‚ el servicio de esta especialidad mâ”œآ®dica en el hospital provincial de Nâ”¬آ¬ Sâ”¬آ¬ de Gracia. Fuente visual: Foto Lozano, en www.todocoleccion.net/', 1944, 1944, 1944, 'Anos 40', 'CENTRO', 41.64727500, -0.88691100, '0101000020E610000014CE6E2D9361ECBF5B423EE8D9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30898410605.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30898410605.webp', 'https://www.flickr.com/photos/zaragozaantigua/30898410605/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22079, 'P.â”¬â•‘ de Pamplona 1958', 'Câ”œآ®sar Gracia Jarque. 1958. "Paseo de Pamplona." Imagen capturada desde el Edificio de Elâ”œآ،seos, chaflanero entre Calvo Sotelo, la Plaza de Paraâ”œآ،so, y el arranque del paseo del general Mola. El paseo de Pamplona, aâ”œâ•‘n con andador central arbolado. Al fondo, sin barreras arquitectâ”œâ”‚nicas, la visual alcanza hasta el Convento de las Hermanas de la Caridad de Santa Ana, en la calle Madre Rafols.', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.64793500, -0.88637300, '0101000020E610000049D6E1E82A5DECBF8577B988EFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15754353817.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15754353817.webp', 'https://www.flickr.com/photos/zaragozaantigua/15754353817/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22117, 'P.â”¬â•‘ de Calvo Sotelo 1953', 'Imagen del andamiaje de obra tras el que se estaba construyendo el bloque del nâ”¬â•‘ 18 (actual 34) del paseo de Calvo Sotelo, chaflanero con la calle Dato (izquierda), y con proyecto de Josâ”œآ® Descartâ”œآ،n Burillo. Este paseo conservarâ”œأ­ esta denominaciâ”œâ”‚n oficial hasta 1979. Fuente visual: Archivo Juan Mora Insa (DARA-AHPZ).', 1953, 1953, 1953, 'Anos 50', 'CENTRO', 41.64613300, -0.88874300, '0101000020E6100000D190F1289570ECBFE5EE737CB4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22500438876.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22500438876.webp', 'https://www.flickr.com/photos/zaragozaantigua/22500438876/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22139, 'P.â”¬â•‘ de Calvo Sotelo 1953', 'Tranvâ”œآ،a nâ”¬â•‘ 160 se servicio en la lâ”œآ،nea de Casablanca transitando por el paseo de Calvo Sotelo, el 11 de mayo de 1953. Al fondo, plaza de Paraâ”œآ،so. Fuente visual: "Los tranvâ”œآ،as de Zaragoza", J. Peâ”œâ–’a - J. M. Valero, DPZ, 1985.', 1953, 1953, 1953, 'Anos 50', 'CENTRO', 41.64680300, -0.88659900, '0101000020E61000005D52B5DD045FECBF33FAD170CAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24851870335.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24851870335.webp', 'https://www.flickr.com/photos/zaragozaantigua/24851870335/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22166, 'Facultad de Medicina 1954', 'Posado, ante la puerta del edificio de las Facultades de Medicina y Ciencias, de los participantes en el XV Hispana Kongreso de Esperanto, que se celebrâ”œâ”‚ en Zaragoza, del 24 al 27 de julio de 1954. Fuente: www.bildarchivaustria.at/', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.64753300, -0.88648100, '0101000020E6100000E1CFF0660D5EECBF570A815CE2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30871420681.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30871420681.webp', 'https://www.flickr.com/photos/zaragozaantigua/30871420681/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22317, 'Vista aâ”œآ®rea c.1965', 'Comercial JOSAN. Ca. 1965 Vista aâ”œآ®rea de Zaragoza a media altura, con una muy buena visual del entorno de la plaza de Paraâ”œآ،so, paseo de Pamplona, plaza de Aragâ”œâ”‚n, y paseo de la Independencia. Fuente: www.facebook.com/photo.php?fbid=738831036211922&set=g...', 1965, 1965, 1965, 'Anos 60', 'CENTRO', 41.64795900, -0.88687700, '0101000020E61000000F63D2DF4B61ECBF0E130D52F0D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15806320360.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15806320360.webp', 'https://www.flickr.com/photos/zaragozaantigua/15806320360/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22322, 'Plaza de Paraâ”œآ،so 1969', 'Un momento de pâ”œأ­nico controlado: mientras reparan algâ”œâ•‘n desperfecto cerca de la vâ”œآ،a tranviaria, el trâ”œأ­fico rodado en la plaza de Paraâ”œآ،so se pone en Defcon 3, porque aunque la plaza de Espaâ”œâ–’a siga emperrada en ser el "centro", el verdadero poder (cuando menos, en tâ”œآ®rminos de regulaciâ”œâ”‚n circulatoria) reside en este gran â”œâ”‚valo donde confluyen hasta cinco arterias vitales de la ciudad. Mientras los tranvâ”œآ،as aguardan (el 11 al Parque, el 5, a Torrero), la circulaciâ”œâ”‚n rodada se regula mediante trapo, mientras llega el seâ”œâ–’or del silbato. Es casi seguro que ya hay reporteros anunciando grandes cataclismos câ”œâ”‚smicos por el "suceso", y repitiendo cuales cotorras que son la consigna de "caâ”œâ–’a al tranvâ”œآ،a". Fuente: "Zaragoza viva" (1969)', 1969, 1969, 1969, 'Anos 60', 'CENTRO', 41.64765600, -0.88593100, '0101000020E61000000667F0F78B59ECBF72874D64E6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15876637252.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15876637252.webp', 'https://www.flickr.com/photos/zaragozaantigua/15876637252/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22422, 'Pl. de Paraâ”œآ،so c.1968', 'Vista aâ”œآ®rea de la plaza de Basilio Paraâ”œآ،so. Sobre â”œآ®sta, el paseo de Pamplona. Fuente: Foto para postal de Comercial Josan. Cesiâ”œâ”‚n de la familia de Josâ”œآ® Marâ”œآ،a Sanz Gonzâ”œأ­lez a Rafael Castillejo. Dataciâ”œâ”‚n y procesado:', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.64767600, -0.88616000, '0101000020E61000005DBF60376C5BECBFB933130CE7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27142994250.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27142994250.webp', 'https://www.flickr.com/photos/zaragozaantigua/27142994250/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22644, 'Facultad de Medicina 1971', 'Foto: Gerardo Sancho. Fila para la vacunaciâ”œâ”‚n contra el câ”œâ”‚lera, en las escaleras de la Facultad de Medicina y Ciencias de Zaragoza, el 20 de julio de 1971. La epidemia se extendiâ”œâ”‚ por Zaragoza, Barcelona, Valencia y Murcia. Fuente: AMZ.', 1971, 1971, 1971, 'Anos 70', 'CENTRO', 41.64738900, -0.88649200, '0101000020E6100000DB4C8578245EECBF23658BA4DDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20571413533.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20571413533.webp', 'https://www.flickr.com/photos/zaragozaantigua/20571413533/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22828, 'Plaza de Basilio Paraâ”œآ،so 1970', 'Tremendo pozo excavado en el entorno de la plaza de Basilio Paraâ”œآ،so por la empresa Elâ”œآ®ctricas Reunidas de Zaragoza SA al objeto de construir la subterrâ”œأ­nea SET (Subestaciâ”œâ”‚n Elâ”œآ®ctrica Transformadora) "Paraâ”œآ،so" con la que mejor atender sus necesidades de negocio en el centro de la ciudad. En primer tâ”œآ®rmino la maquinaria trabaja extrayendo tierra mientras al fondo la circulaciâ”œâ”‚n rodada transita por el paseo de Pamplona.', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.64719700, -0.88605100, '0101000020E6100000AFD172A0875AECBFDF88EE59D7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52853380244.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52853380244.webp', 'https://www.flickr.com/photos/zaragozaantigua/52853380244/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22993, '&quot;Leâ”œâ”‚n&quot; de Rallo, 1990', 'Imagen durante el proceso de modelado de los monumentales "Leones del Puente de Piedra": realizada la figura en arcilla, va a comenzar el "vaciado" en escayola. Luego serâ”œأ­ fundido en bronce, en Valls (Tarragona). Este proyecto estaba asociado con la reforma del puente de Piedra acometida entre 1989 y 1991 por Josâ”œآ® Manuel Pâ”œآ®rez Latorre. Junto a Francisco Rallo Lahoz (con las manos en la escayola), autor de esta camada de broncâ”œآ،neos felinos, su hijo Paco Rallo Gâ”œâ”‚mez, y Fernando Cortâ”œآ®s. El provisional taller es una de las antiguas aulas de la Facultad de Medicina y Ciencias, antes de su rehabilitaciâ”œâ”‚n. Los originales leones del puente de Piedra, dos parejas de gatillos tallados en piedra barroca a mediados del XVII, ejercieron de originales "guardianes del puente" hasta que una intervenciâ”œâ”‚n realizada al hilo de la Expo Hispano-Francesa de 1908 se los llevâ”œâ”‚ allâ”œأ­ por donde anda la Torre Nueva, y la puerta del Duque, entre otras. Fuente visual: Foto Gonzalo Bullâ”œâ”‚n, en "Revista Rolde".', 1990, 1990, 1990, 'Anos 90', 'CENTRO', 41.64719400, -0.88688000, '0101000020E6100000533F6F2A5261ECBF6E15C440D7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21679214183.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21679214183.webp', 'https://www.flickr.com/photos/zaragozaantigua/21679214183/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23036, 'Gran Vâ”œآ،a 1992', 'Manifestaciâ”œâ”‚n contra el racismo y la xenofobia celebrada el 29 de noviembre de 1992, a su paso por el arranque de la Gran Vâ”œآ،a desde la cercana glorieta de Sasera, donde iniciâ”œâ”‚ su recorrido. Fue convocada por la Coordinadora Antirracista, que aglutinaba a prâ”œأ­cticamente todas las asociaciones zaragozanas y grupos polâ”œآ،ticos de izquierda, y fue secundada por unas 10.000 personas. El detonante de la respuesta social en toda Espaâ”œâ–’a fue el asesinato racista en el distrito de Aravaca de Madrid de la dominicana Lucrecia Pâ”œآ®rez, por parte del guardia civil Luis Merino, cometido el 13 de noviembre. Dâ”œآ،as antes de la marcha, en la plaza de los Sitios, unos jâ”œâ”‚venes neonazis habâ”œآ،an agredido a un grupo de mendigos.', 1992, 1992, 1992, 'Anos 90', 'CENTRO', 41.64698000, -0.88626600, '0101000020E6100000C8D0B1834A5CECBF42959A3DD0D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50367962093.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50367962093.webp', 'https://www.flickr.com/photos/zaragozaantigua/50367962093/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23191, 'Gran Vâ”œآ،a 2010', 'Obras de reforzamiento del cubrimiento del râ”œآ،o Huerva, a su paso por la Gran Vâ”œآ،a de Zaragoza. A la derecha, el puente de Santa Engracia. Al fondo, la plaza de Paraâ”œآ،so. Fuente: www.elperiodicodearagon.com/', 2010, 2010, 2010, 'Siglo XXI', 'CENTRO', 41.64688400, -0.88622400, '0101000020E61000000DC51D6FF25BECBF20274C18CDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19668020719.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19668020719.webp', 'https://www.flickr.com/photos/zaragozaantigua/19668020719/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23192, 'Gran Vâ”œآ،a 2010', 'Imagen virtual de â”œأ¼ngel Hernâ”œأ­ndez, 2010. Recreaciâ”œâ”‚n artâ”œآ،stica del râ”œآ،o Huerva a su paso por la Gran Vâ”œآ،a de Zaragoza, visto desde la plaza de Paraâ”œآ،so. La propuesta no prosperâ”œâ”‚. Fuente: www.heraldo.es', 2010, 2010, 2010, 'Siglo XXI', 'CENTRO', 41.64688400, -0.88622400, '0101000020E61000000DC51D6FF25BECBF20274C18CDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19730233199.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19730233199.webp', 'https://www.flickr.com/photos/zaragozaantigua/19730233199/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23643, 'Gran Vâ”œآ،a 1966', 'Archivo Municipal. Gerardo Sancho Ramo. Abril 1966. Imagen de las faenas de plantado arbustâ”œآ،fero en el paseo central de la Gran Vâ”œآ،a, muy cerca de la plaza de Paraâ”œآ،so. Enfrente, el solar del actual nâ”¬â•‘ 24. A la derecha, la entonces Jefatura de servicios y del sector Aâ”œآ®reo del Ejâ”œآ®rcito del Aire.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.64647600, -0.88735500, '0101000020E610000085251E503665ECBF0FD3BEB9BFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15718346822.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15718346822.webp', 'https://www.flickr.com/photos/zaragozaantigua/15718346822/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24032, 'Clâ”œآ،nicas Universitarias 1919', 'Imagen de la inauguraciâ”œâ”‚n del monumento al decano de la Facultad de Medicina, Hipâ”œâ”‚lito Fairâ”œآ®n y Andrâ”œآ®s, ubicado en la plaza entre la puerta principal de las Clâ”œآ،nicas Universitarias, y la original Facultad de Medicina, entre el camino de los Cubos y el cauce al aire del râ”œآ،o Huerva. Este ilustre doctor falleciâ”œâ”‚ un aâ”œâ–’o antes, el busto era obra del escultor Josâ”œآ® Bueno, y al acto acudiâ”œâ”‚ una selecta representaciâ”œâ”‚n de la comunidad universitaria, (con el rector y el decano al frente), de la ciudad (con el alcalde Pedro Calvo Olivares), y de otras entidades. Este monumento fue desmontado aâ”œâ–’os despuâ”œآ®s, aunque al menos se conserva el busto, como parte integrante del patrimonio artâ”œآ،stico de la Universidad de Zaragoza. Fuente visual: Foto Sancho Mercadâ”œآ®, "La Hormiga de Oro".', 1919, 1919, 1919, 'Anos 10', 'CENTRO', 41.64711100, -0.88747700, '0101000020E61000005B785E2A3666ECBFE1F08288D4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26349267862.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26349267862.webp', 'https://www.flickr.com/photos/zaragozaantigua/26349267862/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24098, 'Facultad de Medicina y Ciencias 1917', 'Imagen capturada tras el incendio que el 20 de julio de 1917 se iniciâ”œâ”‚ de madrugada en el laboratorio de quâ”œآ،mica inorgâ”œأ­nica y que asolâ”œâ”‚ la Facultad de Medicina y Ciencias, centrada en el estado en que quedâ”œâ”‚ el Museo de Botâ”œأ­nica. El retâ”œآ®n de bomberos, ademâ”œأ­s de guardiaciviles, y militares de los cuerpos de ingenieros pontoneros y de infanterâ”œآ،a movilizados para la ocasiâ”œâ”‚n por las deficiencias del servicio municipal de bomberos, atajaron el fuego asesorados por el arquitecto Yarza. Se dio la circunstancia de que las bocas de riego de la Facultad no coincidâ”œآ،an con el diâ”œأ­metro de las mangueras de los bomberos, por lo que hubo que bombear el agua desde la inmediata acequia de la Romareda que fluâ”œآ،a al aire por el camino de los Cubos. En la escena y con una manguera se escenifica para la prensa grâ”œأ­fica el control de un incendio ya extinguido con anterioridad, mientras una pareja de guardiaciviles permanece a la sombra. Una secciâ”œâ”‚n de ingenieros pontoneros y un retâ”œآ®n de bomberos permanecieron durante la noche como medida de precauciâ”œâ”‚n.', 1917, 1917, 1917, 'Anos 10', 'CENTRO', 41.64729400, -0.88697400, '0101000020E6100000ADDF4C4C1762ECBFD272A087DAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50132907851.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50132907851.webp', 'https://www.flickr.com/photos/zaragozaantigua/50132907851/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24119, 'Facultad de Medicina 1916', 'Tras la caâ”œآ،da de la colonia alemana del Camerâ”œâ•‘n en manos aliadas en enero de 1916, un millar de militares y civiles alemanes se refugiaron en la Guinea espaâ”œâ–’ola, acompaâ”œâ–’ados de unos 45.000 indâ”œآ،genas cameruneses, aunque mâ”œأ­s de la mitad de estos â”œâ•‘ltimos fueron inmediatamente devueltos a Camerâ”œâ•‘n. Bajo presiâ”œâ”‚n de los aliados se condujo a los alemanes a la Penâ”œآ،nsula para ser internados bajo la promesa de no salir de sus destinos de residencia hasta el fin de la guerra. De los 856 llegados a Espaâ”œâ–’a 347 se instalaron en Zaragoza, revolucionando la sociedad local de la â”œآ®poca. Aunque la mayor parte de ellos regresaron a Alemania tras la derrota de 1918, un contingente no determinado optâ”œâ”‚ por quedarse. Poco despuâ”œآ®s de su llegada a Zaragoza, la Universidad decidiâ”œâ”‚ establecer cursos de castellano para alemanes, a impartir en el edificio de la Facultad de Medicina y Ciencias, de cuatro a cinco de la tarde, dividiendo a los inscritos segâ”œâ•‘n tuvieran o no estudios de latâ”œآ،n. En la imagen, posado colectivo en las escaleras de acceso a la facultad de algunos de los alemanes inscritos a estos cursos.', 1916, 1916, 1916, 'Anos 10', 'CENTRO', 41.64751000, -0.88645900, '0101000020E6100000EDD5C743DF5DECBF9EEA909BE1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53459621636.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53459621636.webp', 'https://www.flickr.com/photos/zaragozaantigua/53459621636/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24264, 'Camino de los Cubos 1890', 'Panorâ”œأ­mica capturada desde la altura de la nueva Facultad de Medicina y Ciencias, orientada hacia los terrenos entre el râ”œآ،o Huerva y el camino de los Cubos junto a la acequia Baja de la Romareda. Al fondo, tras la torre de Fita, la fâ”œأ­brica de sombreros de Desiderio Casanava, que ya en el siglo XX pasarâ”œأ­ a ser propiedad de Gregorio Hernâ”œأ­ndez. A la derecha, camino de los Capuchinos. Fuente visual: "Vista de la Vega de Zaragoza", fototipia de Joarizti y Mariezcurrena, en أ”أ‡آ£Zaragoza Artâ”œآ،stica, Monumental e Histâ”œâ”‚ricaأ”أ‡أک, Anselmo y Pedro Gascâ”œâ”‚n de Gotor (1890-91).', 1890, 1890, 1890, 'Siglo XIX', 'CENTRO', 41.64670500, -0.88867100, '0101000020E61000006CEA3C2AFE6FECBF7094BC3AC7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33221020491.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33221020491.webp', 'https://www.flickr.com/photos/zaragozaantigua/33221020491/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24265, 'Gran Vâ”œآ،a 1931', 'Invernal imagen de la prâ”œآ،stina Gran Vâ”œآ،a, apenas comenzada a urbanizar tras las obras de cubrimiento del râ”œآ،o Huerva, en una luminosa captura de Lucien Roisin de su andador central y su fachada norte, con la facultad de Medicina y Ciencias en primer tâ”œآ®rmino, y despuâ”œآ®s, los pabellones de las Clâ”œآ،nicas universitarias, el pionero bloque de viviendas del actual nâ”¬â•‘ 22, y la fâ”œأ­brica de la Veneciana, terminando, al fondo, con algunos de los pâ”œآ¼oneros bloques del ensanche de Miralbueno, al otro lado de la trinchera del ferrocarril a Barcelona. Fuente visual: "Zaragoza 1908-2008. Arquitectura y Urbanismo".', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.64664600, -0.88682200, '0101000020E61000002CF2EB87D860ECBF6B0BCF4BC5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33341897190.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33341897190.webp', 'https://www.flickr.com/photos/zaragozaantigua/33341897190/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24709, 'Grupo Vizconde Escoriaza 1991', 'Imagen capturada en el interior del grupo de viviendas o barriada "Vizconde de Escoriaza" proyectada por el arquitecto Miguel Beltrâ”œأ­n. La escena se centra en los edificios exentos de la capilla dedicada a la Virgen de Santa Rosa de Lima, y la anexa escuela segregada para niâ”œâ–’os y para niâ”œâ–’as, que se ubicaron en el centro de la barriada. A pesar de que este espacio interior, al que se accede por la calle de Fray Luis Urbano, estaba proyectado como zona verde y de recreo, esto no se realizâ”œâ”‚ nunca, quedando como la explanada de tierra que figura en la fotografâ”œآ،a. En 1995, la Fundaciâ”œâ”‚n Tranvâ”œآ،a, en colaboraciâ”œâ”‚n con la Asociaciâ”œâ”‚n de Vecinos, rehabilitarâ”œآ،a este equipamiento religioso y escolar en desuso, que ademâ”œأ­s se habâ”œآ،a convertido en un foco conflictivo del barrio de Las Fuentes, como Centro de Recursos Bâ”œأ­sicos que actualmente ejerce de Centro de Recursos Comunitarios.', 1991, 1991, 1991, 'Anos 90', 'LAS FUENTES', 41.64831200, -0.85833900, '0101000020E6100000F833BC598377EBBF5BCD3AE3FBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50449886923.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50449886923.webp', 'https://www.flickr.com/photos/zaragozaantigua/50449886923/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24268, 'Velâ”œâ”‚dromo de los Campos Elâ”œآ،seos 1895', 'Dibujo realizado poco despuâ”œآ®s de la inauguraciâ”œâ”‚n del flamante velâ”œâ”‚dromo de los Campos Elâ”œآ،seos, construido en terrenos de la antigua adula del Miâ”œآ®rcoles, entre el cauce al aire del râ”œآ،o Huerva y el arranque del ensanche vertebrado por el paseo de Sagasta. Durante las â”œâ•‘ltimas dâ”œآ®cadas del siglo XIX esta ribereâ”œâ–’a ubicaciâ”œâ”‚n conociâ”œâ”‚ diversos usos recreativos y de ocio, fue sede del provisional Teatro de los Campos Elâ”œآ،seos (1875-1880), solar de algâ”œâ•‘n itinerante circo, y hasta ocasional plaza de toros. En 1895 fue construido un recinto para usuarios de velocâ”œآ،pedos, en uso hasta la construcciâ”œâ”‚n del un velâ”œâ”‚dromo mâ”œأ­s moderno localizado terrazas arriba, en Torrero, a finales de los aâ”œâ–’os veinte del pasado siglo. A la izquierda, el novâ”œآ،simo edificio de las Facultades de Medicina y Ciencias y de la Escuela de Artes y Oficios. Al fondo, el imponente Colegio del Salvador y el arbolado arranque de los paseos de las Damas y de Sagasta. Fuente visual: AMZ; en Amparo Martâ”œآ،nez Herranz, La arquitectura teatral en Zaragoza, IFC, 2003.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.64638100, -0.88605700, '0101000020E6100000378AAC35945AECBFBDE0D39CBCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/44448834351.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/44448834351.webp', 'https://www.flickr.com/photos/zaragozaantigua/44448834351/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24269, 'Facultad de Medicina 1931', 'Imagen capturada en la altura del Observatorio Oficial del Servicio Meteorolâ”œâ”‚gico Nacional, instalado en la Facultad de Medicina y Ciencias de la Universidad, durante la realizaciâ”œâ”‚n de un matinal sondeo aerolâ”œâ”‚gico que incluye la utilizaciâ”œâ”‚n de un globo. Este observatorio habâ”œآ،a sustituido al establecido originalmente en el colegio de las Escuelas Pâ”œآ،as.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.64721400, -0.88725300, '0101000020E610000075E448676064ECBFB5C189E8D7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52520532294.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52520532294.webp', 'https://www.flickr.com/photos/zaragozaantigua/52520532294/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24872, 'Puerta de Santa Engracia 1887', '"Zaragoza. Colocaciâ”œâ”‚n de la primera piedra del edificio para las Facultades de Medicina y Ciencias, el 21 de marzo â”œâ•‘ltimo. (Dibujo de â”œأ¼lvarez Dumont, segâ”œâ•‘n fotografâ”œآ،a)". A.M.Z. Sign. 0845. La Universidad de Zaragoza encargâ”œâ”‚ el edificio de las facultades de Medicina y Ciencias al arquitecto Ricardo Magdalena, en el antiguo campo de Lezcano ubicado extramuros de la puerta de Santa Engracia, entre el Huerva, el camino de los Cubos, y el paseo de la Lealtad. El dibujo reproduce una foto del 21 de marzo de 1887.', 1887, 1887, 1887, 'Siglo XIX', 'CENTRO', 41.64706100, -0.88677800, '0101000020E610000043FE99417C60ECBF2FC214E5D2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14672303378.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14672303378.webp', 'https://www.flickr.com/photos/zaragozaantigua/14672303378/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24880, 'Facultad de Medicina y Ciencias 1930', 'Imagen capturada desde la altura del inmueble del nâ”¬â•‘ 8 de la plaza de Aragâ”œâ”‚n y orientada hacia la gran fachada del ingreso principal a la Facultad de Medicina y Ciencias de la Universidad de Zaragoza. En primer tâ”œآ®rmino, jardines de la triangular isleta que marcaba el arranque del paseo de Pamplona, hacia la derecha, y el paseo de Sagasta, hacia la izquierda.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.64742200, -0.88642700, '0101000020E61000001553E9279C5DECBFFF5A5EB9DED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14865515734.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14865515734.webp', 'https://www.flickr.com/photos/zaragozaantigua/14865515734/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
